  const downloadBarcode = async (format) => {
    if (!barcodeImage) return;

    try {
      if (format === 'png') {
        const response = await fetch(barcodeImage);
        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.download = `barcode-${formData.id || 'generated'}.png`;
        link.href = url;
        link.click();
        window.URL.revokeObjectURL(url);
      } else if (format === 'pdf') {
        const response = await fetch(barcodeImage);
        const blob = await response.blob();

        // Convert blob to data URL for PDF
        const reader = new FileReader();
        reader.onload = () => {
          const dataUrl = reader.result;

          const img = new Image();
          img.onload = () => {
            const pdf = new jsPDF();
            const imgWidth = 100;
            const imgHeight = (img.height * imgWidth) / img.width;

            // Add some text to the PDF
            pdf.setFontSize(16);
            pdf.text('Generated Barcode', 10, 10);
            pdf.setFontSize(12);
            pdf.text(`Product ID: ${formData.id || 'N/A'}`, 10, 20);
            pdf.text(`Product Name: ${formData.name || 'N/A'}`, 10, 30);
            pdf.text(`Category: ${formData.category || 'N/A'}`, 10, 40);
            pdf.text(`Price: $${formData.price || 'N/A'}`, 10, 50);
            pdf.text(`Location: ${formData.locationX || 'N/A'}, ${formData.locationY || 'N/A'}, ${formData.locationZ || 'N/A'}`, 10, 60);

            // Add the barcode image
            pdf.addImage(dataUrl, 'PNG', 10, 80, imgWidth, imgHeight);

            pdf.save(`barcode-${formData.id || 'generated'}.pdf`);
          };
          img.src = dataUrl;
        };
        reader.readAsDataURL(blob);
      }
    } catch (error) {
      console.error('Error downloading barcode:', error);
      showToast('Error downloading barcode');
    }
  };

  const clearForm = () => {
    setFormData({
      id: '',
      name: '',
      category: '',
      price: '',
      locationX: '',
      locationY: '',
      locationZ: '',
      description: '',
      barcodeType: 'qr'
    });
    setGeneratedBarcode(false);
    setBarcodeImage(null);
    setBarcodeId('');
    setBarcodeData('');
  };

  return (
    <div className="barcode-generator">
      <div className="header">
        <h1><FaQrcode /> Barcode Generator</h1>
        <p>Generate and manage barcodes for your products</p>

        {/* Backend Status Indicator */}
        <div className="backend-status">
          <div className={`status-indicator ${backendStatus}`}>
            {backendStatus === 'checking' && <FaSync className="spinning" />}
            {backendStatus === 'running' && <FaDatabase style={{ color: '#34A853' }} />}
            {backendStatus === 'starting' && <FaSync className="spinning" />}
            {backendStatus === 'error' && <FaDatabase style={{ color: '#EA4335' }} />}

            <span className="status-text">
              {backendStatus === 'checking' && 'Checking backend...'}
              {backendStatus === 'running' && 'Backend running'}
              {backendStatus === 'starting' && 'Starting backend...'}
              {backendStatus === 'error' && 'Backend error'}
            </span>
          </div>

          {backendStatus === 'error' && (
            <button
              onClick={startBackend}
              className="btn btn-primary btn-sm"
              style={{ marginTop: '8px' }}
            >
              <FaSync /> Retry Start Backend
            </button>
          )}
        </div>
      </div>

      <div className="main-content">
        <div className="form-section">
          <h2>Product Information</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="id">Product ID</label>
              <input
                type="text"
                id="id"
                name="id"
                value={formData.id}
                onChange={handleInputChange}
                placeholder="Enter product ID"
              />
            </div>

            <div className="form-group">
              <label htmlFor="name">Product Name</label>
              <input
                type="text"
                id="name"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder="Enter product name"
              />
            </div>

            <div className="form-group">
              <label htmlFor="category">Category</label>
              <select
                id="category"
                name="category"
                value={formData.category}
                onChange={handleInputChange}
              >
                <option value="">Select category</option>
                {categories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label htmlFor="price">Price</label>
              <input
                type="number"
                id="price"
                name="price"
                value={formData.price}
                onChange={handleInputChange}
                placeholder="Enter price"
                step="0.01"
              />
            </div>

            <div className="form-group">
              <label htmlFor="locationX">Location X</label>
              <input
                type="number"
                id="locationX"
                name="locationX"
                value={formData.locationX}
                onChange={handleInputChange}
                placeholder="Enter X coordinate"
                step="0.1"
              />
            </div>

            <div className="form-group">
              <label htmlFor="locationY">Location Y</label>
              <input
                type="number"
                id="locationY"
                name="locationY"
                value={formData.locationY}
                onChange={handleInputChange}
                placeholder="Enter Y coordinate"
                step="0.1"
              />
            </div>

            <div className="form-group">
              <label htmlFor="locationZ">Location Z</label>
              <input
                type="number"
                id="locationZ"
                name="locationZ"
                value={formData.locationZ}
                onChange={handleInputChange}
                placeholder="Enter Z coordinate"
                step="0.1"
              />
            </div>

            <div className="form-group">
              <label htmlFor="barcodeType">Barcode Type</label>
              <div className="barcode-type-selector">
                {barcodeTypes.map(type => {
                  const Icon = type.icon;
                  return (
                    <button
                      key={type.value}
                      type="button"
                      className={`type-option ${formData.barcodeType === type.value ? 'selected' : ''}`}
                      onClick={() => setFormData(prev => ({ ...prev, barcodeType: type.value }))}
                    >
                      <Icon className="type-icon" />
                      <span className="type-label">{type.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="form-group full-width">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleInputChange}
              placeholder="Enter product description"
              rows="3"
            />
          </div>

          <div className="button-group">
            <button
              onClick={generateBarcode}
              disabled={isGenerating || !barcodeData}
              className="btn btn-primary generate-btn"
            >
              {isGenerating ? (
                <FaSync className="spinning" />
              ) : (
                (() => {
                  const IconComponent = barcodeTypes.find(type => type.value === formData.barcodeType)?.icon || FaQrcode;
                  return <IconComponent />;
                })()
              )}
              {isGenerating ? 'Generating...' : barcodeTypes.find(type => type.value === formData.barcodeType)?.shortLabel || 'Generate'}
            </button>

            <button
              onClick={saveToDatabase}
              disabled={!generatedBarcode || isSaving}
              className="btn btn-success"
            >
              {isSaving ? <FaSync className="spinning" /> : <FaSave />}
              {isSaving ? 'Saving...' : 'Save to Database'}
            </button>

            <button
              onClick={updateRecord}
              disabled={!formData.id || isUpdating}
              className="btn btn-warning"
            >
              {isUpdating ? <FaSync className="spinning" /> : <FaSync />}
              {isUpdating ? 'Updating...' : 'Update Record'}
            </button>

            <button onClick={clearForm} className="btn btn-secondary">
              Clear Form
            </button>
          </div>

          {saveMessage && (
            <div className="message success">
              {saveMessage}
            </div>
          )}
        </div>

        <div className="barcode-section">
          <h2>Generated Barcode</h2>

          {generatedBarcode && barcodeImage ? (
            <div className="barcode-display">
              <div className="barcode-info">
                <p><strong>Barcode ID:</strong> {barcodeId}</p>
                <p><strong>Type:</strong> {formData.barcodeType.toUpperCase()}</p>
                <p><strong>Data:</strong> {barcodeData}</p>
              </div>

              <div className="barcode-image">
                <img src={barcodeImage} alt="Generated barcode" />
              </div>

              <div className="download-options">
                <button
                  onClick={() => downloadBarcode('png')}
                  className="btn btn-download"
                >
                  <FaDownload /> Download PNG
                </button>
                <button
                  onClick={() => downloadBarcode('pdf')}
                  className="btn btn-download"
                >
                  <FaDownload /> Download PDF
                </button>
              </div>
            </div>
          ) : (
            <div className="no-barcode">
              <FaQrcode className="placeholder-icon" />
              <p>No barcode generated yet</p>
              <p>Fill in the form and click "Generate Barcode" to get started</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BarcodeGenerator;

import React, { useState, useEffect } from 'react';
import { getServerURL } from '../config/api';
import {
  FaBarcode,
  FaTimesCircle,
  FaSync,
  FaSearch,
  FaFilter,
  FaDownload,
  FaEdit,
  FaInfoCircle,
  FaCheckCircle,
  FaExclamationTriangle,
  FaCog,
  FaSignal,
  FaBatteryFull,
  FaBatteryThreeQuarters,
  FaBatteryHalf,
  FaBatteryQuarter,
  FaBatteryEmpty,
  FaClock,
  FaMapMarkerAlt,
  FaMicrochip
} from 'react-icons/fa';
import { useWebSocket } from '../contexts/WebSocketContext';
import './DeviceConnected.css';

const DeviceConnected = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [filterStatus, setFilterStatus] = useState('all');
  const [sortBy, setSortBy] = useState('name');
  const [showFilters, setShowFilters] = useState(false);
  const [selectedDevice, setSelectedDevice] = useState(null);
  const [showDetails, setShowDetails] = useState(false);
  const [showConfigure, setShowConfigure] = useState(false);
  const { isConnected, esp32Devices, latestScan, socket } = useWebSocket();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (esp32Devices.length > 0) {
      setLoading(false);
    } else {
      const timer = setTimeout(() => setLoading(false), 1500);
      return () => clearTimeout(timer);
    }
  }, [esp32Devices]);

  // Listen for device pairing/unpairing events for instant updates
  React.useEffect(() => {
    if (!socket) return;

    const handleDevicePaired = () => {
      console.log('Device paired - devices will auto-update via WebSocket context');
    };

    const handleDeviceUnpaired = () => {
      console.log('Device unpaired - devices will auto-update via WebSocket context');
    };

    socket.on('device_paired', handleDevicePaired);
    socket.on('device_unpaired', handleDeviceUnpaired);

    return () => {
      socket.off('device_paired', handleDevicePaired);
      socket.off('device_unpaired', handleDeviceUnpaired);
    };
  }, [socket]);

  // Use WebSocket devices directly (no local polling needed)
  const displayDevices = esp32Devices;


  const getBatteryIcon = (level) => {
    if (level >= 80) return <FaBatteryFull />;
    if (level >= 60) return <FaBatteryThreeQuarters />;
    if (level >= 40) return <FaBatteryHalf />;
    if (level >= 20) return <FaBatteryQuarter />;
    return <FaBatteryEmpty />;
  };

  const getBatteryColor = (level) => {
    if (level >= 60) return '#4CAF50';
    if (level >= 30) return '#FF9800';
    return '#F44336';
  };

  const getSignalIcon = (strength) => {
    if (strength >= 80) return <FaSignal />;
    if (strength >= 60) return <FaSignal />;
    if (strength >= 40) return <FaSignal />;
    return <FaSignal />;
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'connected': return '#4CAF50';
      case 'disconnected': return '#F44336';
      default: return '#9AA0A6';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'connected': return <FaCheckCircle />;
      case 'disconnected': return <FaTimesCircle />;
      default: return <FaExclamationTriangle />;
    }
  };

  const filteredDevices = displayDevices.filter(device => {
    const matchesSearch = device.deviceName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      device.deviceId.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = filterStatus === 'all' || device.status === filterStatus;
    return matchesSearch && matchesStatus;
  });

  const sortedDevices = [...filteredDevices].sort((a, b) => {
    switch (sortBy) {
      case 'name':
        return a.deviceName.localeCompare(b.deviceName);
      case 'status':
        return a.status.localeCompare(b.status);
      case 'lastSeen':
        return new Date(b.lastSeen) - new Date(a.lastSeen);
      case 'scanCount':
        return (b.totalScans || 0) - (a.totalScans || 0);
      default:
        return 0;
    }
  });

  const refreshDevices = async () => {
    setIsRefreshing(true);
    try {
      const serverURL = getServerURL();
      const token = localStorage.getItem('robridge_token');

      await fetch(`${serverURL}/api/esp32/devices`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      // Force visual delay for feedback
      setTimeout(() => setIsRefreshing(false), 800);
    } catch (error) {
      console.error('Error refreshing devices:', error);
      setIsRefreshing(false);
    }
  };

  const exportDeviceData = () => {
    const csvContent = [
      ['Device Name', 'Device ID', 'Status', 'IP Address', 'Last Seen', 'Total Scans'],
      ...displayDevices.map(device => [
        device.deviceName,
        device.deviceId,
        device.status,
        device.ipAddress,
        device.lastSeen,
        device.totalScans || 0
      ])
    ].map(row => row.join(',')).join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const date = new Date().toISOString().split('T')[0];
    const a = document.createElement('a');
    a.href = url;
    a.download = `connected_devices_${date}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  const handleDetails = (device) => {
    setSelectedDevice(device);
    setShowDetails(true);
  };

  const handleConfigure = (device) => {
    setSelectedDevice(device);
    setShowConfigure(true);
  };

  const closeModal = () => {
    setShowDetails(false);
    setShowConfigure(false);
    setSelectedDevice(null);
  };

  return (
    <div className="device-connected">
      <div className="page-header">
        <h1>Device Connected</h1>
        <p>Monitor and manage connected Barcode Scanners</p>
      </div>

      {/* Connection Status */}
      <div className="connection-status">
        <div className={`status-indicator ${isConnected ? 'connected' : 'disconnected'}`}>
          <FaSignal />
          WebSocket: {isConnected ? 'Connected' : 'Disconnected'}
        </div>
        <div className="device-count">
          <FaMicrochip />
          Device Connected: {displayDevices.length}
        </div>
      </div>

      {/* Controls */}
      <div className="device-controls">
        <div className="search-section">
          <div className="search-box">
            <FaSearch className="search-icon" />
            <input
              type="text"
              placeholder="Search devices..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button
            className="filter-btn"
            onClick={() => setShowFilters(!showFilters)}
          >
            <FaFilter />
            Filters
          </button>
        </div>

        <div className="action-buttons">

          <button className="btn btn-primary" onClick={exportDeviceData}>
            <FaDownload />
            Export
          </button>
        </div>
      </div>

      {/* Filters */}
      {showFilters && (
        <div className="filters-panel">
          <div className="filter-group">
            <label>Status:</label>
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
            >
              <option value="all">All</option>
              <option value="connected">Connected</option>
              <option value="disconnected">Disconnected</option>
            </select>
          </div>
          <div className="filter-group">
            <label>Sort by:</label>
            <select
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
            >
              <option value="name">Name</option>
              <option value="status">Status</option>
              <option value="lastSeen">Last Seen</option>
              <option value="scanCount">Scan Count</option>
            </select>
          </div>
        </div>
      )}

      {/* Latest Scan Info */}
      {latestScan && (
        <div className="latest-scan-info">
          <h3>Latest Device Connected Scan</h3>
          <div className="scan-details">
            <p><strong>Device:</strong> {latestScan.deviceName}</p>
            <p><strong>Barcode:</strong> {latestScan.barcodeData}</p>
            <p><strong>Time:</strong> {new Date(latestScan.timestamp).toLocaleString()}</p>

          </div>
        </div>
      )}

      {/* Device Grid */}
      <div className="device-grid">
        {loading ? (
          <div className="loading-spinner-container" style={{
            gridColumn: '1 / -1',
            padding: '60px',
            display: 'flex',
            justifyContent: 'center',
            flexDirection: 'column',
            alignItems: 'center'
          }}>
            <div className="spinner-small" style={{
              width: '40px',
              height: '40px',
              border: '4px solid #E3821E',
              borderTopColor: 'transparent',
              borderRadius: '50%',
              animation: 'spin 1s linear infinite',
              marginBottom: '16px'
            }}></div>
            <h3 style={{ color: '#5F6368', fontSize: '18px' }}>Searching for devices...</h3>
          </div>
        ) : sortedDevices.length > 0 ? (
          sortedDevices.map((device) => (
            <div key={device.deviceId} className="device-card">
              <div className="device-header">
                <div className="device-info">
                  <div className="name-row">
                    <h3>{device.deviceName}</h3>
                  </div>
                  <div className="status-row">
                    <span className={`status-badge ${device.status}`}>
                      {getStatusIcon(device.status)}
                      {device.status}
                    </span>
                  </div>
                </div>
              </div>

              <div className="device-details">
                <div className="detail-row">
                  <FaMapMarkerAlt />
                  <span>IP: {device.ipAddress}</span>
                </div>
                <div className="detail-row">
                  <FaClock />
                  <span>Last Seen: {new Date(device.lastSeen).toLocaleString()}</span>
                </div>
                <div className="detail-row">
                  <FaBarcode />
                  <span>Total Scans: {device.totalScans || 0}</span>
                </div>


              </div>

              <div className="device-actions">
                <button
                  className="btn btn-sm btn-secondary"
                  onClick={() => handleDetails(device)}
                >
                  <FaInfoCircle />
                  Details
                </button>

              </div>
            </div>
          ))
        ) : (
          <div className="no-devices">
            <FaMicrochip size={64} />
            <h3>No Device Connected Devices</h3>
            <p>Waiting for Device Connected devices to connect...</p>
            <p>Make sure your Device Connected is powered on and connected to WiFi.</p>
          </div>
        )}
      </div>

      {/* Details Modal */}
      {showDetails && selectedDevice && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h2>Device Details</h2>
              <button className="close-btn" onClick={closeModal}>
                <FaTimesCircle />
              </button>
            </div>
            <div className="modal-body">
              <div className="device-details-grid">
                <div className="detail-section">
                  <h3>Basic Information</h3>
                  <div className="detail-item">
                    <strong>Device Name:</strong> {selectedDevice.deviceName}
                  </div>
                  <div className="detail-item">
                    <strong>Device ID:</strong> {selectedDevice.deviceId}
                  </div>
                  <div className="detail-item">
                    <strong>Status:</strong>
                    <span className="status-badge" style={{ color: getStatusColor(selectedDevice.status) }}>
                      {getStatusIcon(selectedDevice.status)} {selectedDevice.status}
                    </span>
                  </div>
                  <div className="detail-item">
                    <strong>IP Address:</strong> {selectedDevice.ipAddress}
                  </div>

                </div>

                <div className="detail-section">
                  <h3>Activity</h3>
                  <div className="detail-item">
                    <strong>Total Scans:</strong> {selectedDevice.totalScans || 0}
                  </div>
                  <div className="detail-item">
                    <strong>Last Seen:</strong> {new Date(selectedDevice.lastSeen).toLocaleString()}
                  </div>



                </div>
              </div>
              <div className="modal-footer">
                <button className="btn btn-secondary" onClick={closeModal}>
                  Close
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Configure Modal */}
      {showConfigure && selectedDevice && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h2>Configure Device</h2>
              <button className="close-btn" onClick={closeModal}>
                <FaTimesCircle />
              </button>
            </div>
            <div className="modal-body">
              <div className="config-form">
                <div className="form-group">
                  <label>Device Name</label>
                  <input
                    type="text"
                    defaultValue={selectedDevice.deviceName}
                    className="form-control"
                  />
                </div>

                <div className="form-group">
                  <label>Scan Interval (seconds)</label>
                  <input
                    type="number"
                    defaultValue="30"
                    className="form-control"
                  />
                </div>

                <div className="form-group">
                  <label>Heartbeat Interval (seconds)</label>
                  <input
                    type="number"
                    defaultValue="30"
                    className="form-control"
                  />
                </div>

                <div className="form-group">
                  <label>Auto Reconnect</label>
                  <select className="form-control">
                    <option value="true">Enabled</option>
                    <option value="false">Disabled</option>
                  </select>
                </div>

                <div className="form-group">
                  <label>Debug Mode</label>
                  <select className="form-control">
                    <option value="false">Disabled</option>
                    <option value="true">Enabled</option>
                  </select>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={closeModal}>
                Cancel
              </button>
              <button className="btn btn-primary">
                Save Configuration
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

