import React, { useState } from 'react';
import { FaSync, FaDownload, FaUpload, FaCheckCircle, FaExclamationTriangle, FaPlug } from 'react-icons/fa';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useToast } from '../components/Toast';

export default function IMSErp() {
  const { imsFetch } = useWorkspace();
  const showToast = useToast();
  const [loading, setLoading] = useState(false);
  const [stockData, setStockData] = useState([]);
  const [poJson, setPoJson] = useState('{\n  "doc_no": "PO-2024-001",\n  "items": [\n    { "barcode": "SKU001", "name": "Item A", "qty": 100 }\n  ]\n}');

  const syncStock = async () => {
    setLoading(true);
    try {
      const res = await imsFetch('/api/ims/erp/sync', {
        method: 'POST',
        body: JSON.stringify({ action: 'SYNC_STOCK', payload: {} })
      });
      const d = await res.json();
      if (d.success) {
        setStockData(d.stock);
        showToast(`✅ Exported ${d.stock.length} SKUs for ERP`, 'success');
      } else {
        showToast(d.error || 'Sync failed', 'error');
      }
    } catch (e) {
      showToast('Failed to sync stock', 'error');
    }
    setLoading(false);
  };

  const importPO = async () => {
    let payload;
    try { payload = JSON.parse(poJson); } catch(e) {
      showToast('Invalid JSON in PO payload', 'error'); return;
    }
    setLoading(true);
    try {
      const res = await imsFetch('/api/ims/erp/sync', {
        method: 'POST',
        body: JSON.stringify({ action: 'IMPORT_PO', payload })
      });
      const d = await res.json();
      if (d.success) {
        showToast(`PO ${payload.doc_no} imported as GRN successfully`, 'success');
      } else {
        showToast(d.error || 'Import failed', 'error');
      }
    } catch (e) {
      showToast('Failed to import PO', 'error');
    }
    setLoading(false);
  };

  const downloadStockCSV = () => {
    if (!stockData.length) return;
    const headers = ['barcode', 'name', 'stock', 'cost'];
    const rows = stockData.map(i => headers.map(h => i[h] ?? '').join(','));
    const csv = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = 'stock_export.csv'; a.click();
  };

  return (
    <div style={{ padding: 24, maxWidth: 1100, margin: '0 auto' }}>
      {/* Header */}
      <div className="page-header ims-page-header" style={{ marginBottom: 24 }}>
        <div className="ims-header-left">
          <h1>ERP Integration</h1>
          <p>Sync stock data and import Purchase Orders from SAP, Tally, or any external system</p>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24 }}>
        {/* Export Stock */}
        <div className="card">
          <div className="card-header" style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <FaDownload style={{ color: '#E3821E' }} />
            <h3 style={{ margin: 0 }}>Export Stock to ERP</h3>
          </div>
          <div className="card-body">
            <p style={{ color: '#666', fontSize: 14 }}>
              Pull current inventory levels and push them to your ERP system via API or download as CSV.
            </p>
            <div style={{ display: 'flex', gap: 10, marginBottom: 16 }}>
              <button className="btn btn-primary" onClick={syncStock} disabled={loading}>
                <FaSync /> {loading ? 'Syncing...' : 'Pull Stock Data'}
              </button>
              {stockData.length > 0 && (
                <button className="btn btn-secondary" onClick={downloadStockCSV}>
                  <FaDownload /> Download CSV ({stockData.length} SKUs)
                </button>
              )}
            </div>
            {stockData.length > 0 && (
              <div style={{ maxHeight: 300, overflowY: 'auto', border: '1px solid #eee', borderRadius: 8 }}>
                <table className="table" style={{ fontSize: 13 }}>
                  <thead><tr><th>Barcode</th><th>Name</th><th>Stock</th><th>Cost</th></tr></thead>
                  <tbody>
                    {stockData.map((s, i) => (
                      <tr key={i}>
                        <td><code>{s.barcode}</code></td>
                        <td>{s.name}</td>
                        <td style={{ fontWeight: 600, color: s.stock === 0 ? '#e74c3c' : '#27ae60' }}>{s.stock}</td>
                        <td>{s.cost ? '₹' + s.cost : '—'}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        {/* Import PO */}
        <div className="card">
          <div className="card-header" style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <FaUpload style={{ color: '#E3821E' }} />
            <h3 style={{ margin: 0 }}>Import Purchase Order</h3>
          </div>
          <div className="card-body">
            <p style={{ color: '#666', fontSize: 14 }}>
              Paste a PO payload from SAP/Tally/ERP as JSON. It will be imported as a pending GRN.
            </p>
            <div className="form-group">
              <label className="form-label">PO Payload (JSON)</label>
              <textarea
                className="form-textarea"
                style={{ fontFamily: 'monospace', fontSize: 12, minHeight: 180 }}
                value={poJson}
                onChange={e => setPoJson(e.target.value)}
              />
            </div>
            <button className="btn btn-primary" onClick={importPO} disabled={loading}>
              <FaUpload /> {loading ? 'Importing...' : 'Import as GRN'}
            </button>
          </div>
        </div>
      </div>

      {/* Info */}
      <div className="card" style={{ marginTop: 24 }}>
        <div className="card-header" style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <FaPlug style={{ color: '#E3821E' }} />
          <h3 style={{ margin: 0 }}>API Webhook Reference</h3>
        </div>
        <div className="card-body">
          <p style={{ color: '#555', fontSize: 14, marginBottom: 12 }}>
            Use these endpoints to integrate RoBridge IMS with any external system:
          </p>
          <div style={{ background: '#1e1e2e', borderRadius: 8, padding: 16, fontFamily: 'monospace', fontSize: 13, color: '#cdd6f4' }}>
            <div style={{ color: '#89dceb' }}>POST</div>
            <div>/api/ims/erp/sync</div>
            <div style={{ color: '#a6e3a1', marginTop: 12 }}>// Export all stock to ERP</div>
            <div>{'{ "action": "SYNC_STOCK", "payload": {} }'}</div>
            <div style={{ color: '#a6e3a1', marginTop: 12 }}>// Import Purchase Order as pending GRN</div>
            <div>{'{ "action": "IMPORT_PO", "payload": { "doc_no": "PO-001", "items": [...] } }'}</div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import {
  FaFileInvoice, FaPlus, FaTruck, FaCheckCircle, FaSearch,
  FaDownload, FaTimes, FaSave, FaArrowDown, FaArrowUp,
  FaCalendarAlt, FaBuilding, FaBoxes, FaClipboardCheck,
  FaSpinner, FaSync, FaTrash
} from 'react-icons/fa';
import './IMSGrn.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useConfirm } from '../components/ConfirmModal';

const statusStyle = {
  APPROVED: { color: '#27ae60', bg: '#eafaf1', label: '✓ Approved' },
  PENDING:  { color: '#e67e22', bg: '#fef9e7', label: '⏳ Pending Approval' },
  REJECTED: { color: '#e74c3c', bg: '#fdf0ed', label: '✗ Rejected' },
};

const emptyForm = { type: 'INWARD', supplier: '', poRef: '', vehicleNo: '', notes: '' };
const emptyItem = { barcode: '', name: '', orderedQty: '', receivedQty: '', unit: 'pcs', condition: 'Good', note: '' };

export default function IMSGrn() {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const confirm = useConfirm();
  const [tab, setTab] = useState('INWARD');
  const [grns, setGrns] = useState([]);
  const [selected, setSelected] = useState(null);
  const [selectedItems, setSelectedItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [lineItems, setLineItems] = useState([{ ...emptyItem }]);
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState('');

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(''), 3500); };

  const loadGRNs = useCallback(async () => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    try {
      const r = await imsFetch('/api/ims/grn');
      const d = await r.json();
      if (d.success) setGrns(d.grns);
    } finally { setLoading(false); }
  }, [activeWorkspaceId, imsFetch]);

  useEffect(() => { loadGRNs(); }, [loadGRNs]);

  const selectGRN = async (grn) => {
    setSelected(grn);
    const r = await imsFetch(`/api/ims/grn/${grn.id}/items`);
    const d = await r.json();
    if (d.success) setSelectedItems(d.items);
  };

  const createGRN = async () => {
    if (!form.supplier) return;
    setSaving(true);
    try {
      const payload = { ...form, type: tab, items: lineItems.filter(i => i.barcode && i.name) };
      const r = await imsFetch('/api/ims/grn', { method: 'POST', body: JSON.stringify(payload) });
      const d = await r.json();
      if (d.success) {
        setGrns(prev => [d.grn, ...prev]);
        setShowCreate(false);
        setForm(emptyForm);
        setLineItems([{ ...emptyItem }]);
        showToast('✅ Document created successfully');
      }
    } finally { setSaving(false); }
  };

  const approve = async () => {
    if (!selected) return;
    const ok = await confirm({
      title: `Approve ${selected.doc_no}?`,
      message: 'Approving this document will update stock levels. This action cannot be reversed.',
      type: 'warning',
      confirmLabel: 'Approve & Update Stock'
    });
    if (!ok) return;
    const r = await imsFetch(`/api/ims/grn/${selected.id}/approve`, { method: 'POST', body: '{}' });
    const d = await r.json();
    if (d.success) {
      setGrns(prev => prev.map(g => g.id === selected.id ? { ...g, status: 'APPROVED' } : g));
      setSelected(s => ({ ...s, status: 'APPROVED' }));
      showToast('✅ Approved! Stock has been updated.');
    }
  };

  const reject = async () => {
    if (!selected) return;
    const ok = await confirm({
      title: `Reject ${selected.doc_no}?`,
      message: 'The document will be marked as rejected and no stock changes will be made.',
      type: 'danger',
      confirmLabel: 'Reject'
    });
    if (!ok) return;
    const r = await imsFetch(`/api/ims/grn/${selected.id}/reject`, { method: 'POST', body: '{}' });
    const d = await r.json();
    if (d.success) {
      setGrns(prev => prev.map(g => g.id === selected.id ? { ...g, status: 'REJECTED' } : g));
      setSelected(s => ({ ...s, status: 'REJECTED' }));
      showToast('🗑️ Document rejected');
    }
  };

  const filtered = grns.filter(g => g.type === tab &&
    (g.doc_no.includes(search) || g.supplier.toLowerCase().includes(search.toLowerCase())));

  const kpis = [
    { label: 'Total GRNs',          value: grns.filter(g => g.type === 'INWARD').length,            color: '#3498db', icon: FaArrowDown },
    { label: 'Pending Approval',     value: grns.filter(g => g.status === 'PENDING').length,         color: '#e67e22', icon: FaClipboardCheck },
    { label: 'Dispatch Notes',       value: grns.filter(g => g.type === 'OUTWARD').length,           color: '#27ae60', icon: FaArrowUp },
    { label: 'Approved Today',       value: grns.filter(g => g.status === 'APPROVED' && g.created_at?.startsWith(new Date().toISOString().slice(0,10))).length, color: '#9b59b6', icon: FaBoxes },
  ];

  return (
    <div className="ims-grn-page">
      {toast && <div style={{ position: 'fixed', top: 20, right: 20, background: '#2c3e50', color: '#fff', padding: '12px 20px', borderRadius: 10, zIndex: 9999, fontSize: 14 }}>{toast}</div>}

      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Inward GRN &amp; Outward Dispatch</h1>
          <p>Manage Goods Receipt Notes for inbound stock and Dispatch Notes for outward shipments</p>
        </div>
        <div className="ims-header-right" style={{ gap: 10, display: 'flex' }}>
          <button className="btn btn-secondary" onClick={loadGRNs}><FaSync /> Refresh</button>
          <button className="btn btn-primary" onClick={() => { setForm({ ...emptyForm, type: tab }); setShowCreate(true); }}>
            <FaPlus /> Create {tab === 'INWARD' ? 'GRN' : 'Dispatch Note'}
          </button>
        </div>
      </div>

      <div className="grn-kpi-strip">
        {kpis.map((k, i) => (
          <div key={i} className="grn-kpi-card" style={{ borderLeftColor: k.color }}>
            <k.icon style={{ color: k.color, fontSize: 22 }} />
            <div><div className="grn-kpi-val" style={{ color: k.color }}>{k.value}</div><div className="grn-kpi-lbl">{k.label}</div></div>
          </div>
        ))}
      </div>

      <div className="grn-layout">
        {/* Left List */}
        <div className="grn-list-panel">
          <div className="grn-tabs">
            <button className={`grn-tab ${tab === 'INWARD' ? 'active' : ''}`} onClick={() => setTab('INWARD')}><FaArrowDown /> Inward GRN</button>
            <button className={`grn-tab ${tab === 'OUTWARD' ? 'active' : ''}`} onClick={() => setTab('OUTWARD')}><FaArrowUp /> Outward Dispatch</button>
          </div>
          <div className="search-input" style={{ margin: '12px 0' }}>
            <FaSearch className="search-icon" />
            <input type="text" placeholder="Search..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          {loading ? <div style={{ textAlign: 'center', padding: 30, color: '#aaa' }}><FaSpinner /></div> : (
            <div className="grn-cards">
              {filtered.length === 0 && <div style={{ textAlign: 'center', padding: 30, color: '#aaa' }}>No documents found.</div>}
              {filtered.map(grn => {
                const ss = statusStyle[grn.status] || statusStyle.PENDING;
                return (
                  <div key={grn.id} className={`grn-card ${selected?.id === grn.id ? 'active' : ''}`} onClick={() => selectGRN(grn)}>
                    <div className="grn-card-top">
                      <div className="grn-id">{grn.doc_no}</div>
                      <span className="grn-status" style={{ background: ss.bg, color: ss.color }}>{ss.label}</span>
                    </div>
                    <div className="grn-supplier"><FaBuilding /> {grn.supplier}</div>
                    <div className="grn-meta">
                      {grn.po_ref && <span><FaFileInvoice /> {grn.po_ref}</span>}
                      <span><FaCalendarAlt /> {grn.created_at?.split('T')[0]}</span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Right Detail */}
        <div className="grn-detail-panel">
          {selected ? (
            <>
              <div className="grn-detail-header">
                <div>
                  <h2>{selected.doc_no}</h2>
                  <div style={{ color: '#888', fontSize: 14 }}>{selected.supplier} {selected.po_ref && `· ${selected.po_ref}`}</div>
                </div>
                <span className="grn-status large" style={{ background: statusStyle[selected.status]?.bg, color: statusStyle[selected.status]?.color }}>{statusStyle[selected.status]?.label}</span>
              </div>
              <div style={{ padding: '0 0 16px', borderBottom: '1px solid #eee', marginBottom: 16, display: 'flex', gap: 24, flexWrap: 'wrap' }}>
                <div><div style={{ fontSize: 12, color: '#888' }}>Date</div><div style={{ fontWeight: 600 }}>{selected.created_at?.split('T')[0]}</div></div>
                {selected.po_ref && <div><div style={{ fontSize: 12, color: '#888' }}>Reference</div><div style={{ fontWeight: 600 }}>{selected.po_ref}</div></div>}
                {selected.vehicle_no && <div><div style={{ fontSize: 12, color: '#888' }}>Vehicle No</div><div style={{ fontWeight: 600 }}>{selected.vehicle_no}</div></div>}
                <div><div style={{ fontSize: 12, color: '#888' }}>Type</div><div style={{ fontWeight: 600 }}>{selected.type}</div></div>
              </div>

              <h3 style={{ fontSize: 15, marginBottom: 12 }}>Item-wise Details</h3>
              <div className="table-container" style={{ boxShadow: 'none', border: '1px solid #eee' }}>
                <table className="table">
                  <thead><tr><th>Barcode</th><th>Item</th><th>Ordered</th><th>Received</th><th>Condition</th><th>Notes</th></tr></thead>
                  <tbody>
                    {selectedItems.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', color: '#aaa', padding: 20 }}>No items recorded</td></tr>}
                    {selectedItems.map((item, i) => (
                      <tr key={i}>
                        <td><code>{item.barcode}</code></td>
                        <td><strong>{item.name}</strong></td>
                        <td>{item.ordered_qty} {item.unit}</td>
                        <td style={{ color: Number(item.received_qty) >= Number(item.ordered_qty) ? '#27ae60' : '#e74c3c', fontWeight: 600 }}>{item.received_qty} {item.unit}</td>
                        <td><span style={{ background: '#eafaf1', color: '#27ae60', padding: '3px 8px', borderRadius: 10, fontSize: 12 }}>{item.condition}</span></td>
                        <td style={{ color: '#888', fontSize: 13 }}>{item.note || '—'}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {selected.status === 'PENDING' && (
                <div className="grn-approval-strip">
                  <button className="btn btn-primary" style={{ background: '#27ae60' }} onClick={approve}><FaCheckCircle /> Approve &amp; Update Stock</button>
                  <button className="btn btn-secondary" style={{ borderColor: '#e74c3c', color: '#e74c3c' }} onClick={reject}><FaTimes /> Reject</button>
                </div>
              )}
            </>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: '#aaa', gap: 12 }}>
              <FaFileInvoice style={{ fontSize: 48 }} />
              <h3>Select a GRN or Dispatch Note</h3>
              <p style={{ fontSize: 14 }}>Click on a record to view item-level details and take action.</p>
            </div>
          )}
        </div>
      </div>

      {/* Create Modal */}
      {showCreate && (
        <div className="ims-modal-overlay" onClick={() => setShowCreate(false)}>
          <div className="ims-modal" style={{ maxWidth: 700 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div><h2>Create {tab === 'INWARD' ? 'Goods Receipt Note' : 'Dispatch Note'}</h2><p>Fill in the delivery details and items</p></div>
              <button className="modal-close" onClick={() => setShowCreate(false)}><FaTimes /></button>
            </div>
            <div className="modal-body">
              <div className="modal-row">
                <div className="form-group" style={{ flex: 2 }}>
                  <label className="form-label">{tab === 'INWARD' ? 'Supplier Name' : 'Recipient Name'} *</label>
                  <input className="form-input" placeholder="Company / Person" value={form.supplier} onChange={e => setForm(f => ({ ...f, supplier: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">PO / SO Reference</label>
                  <input className="form-input" placeholder="PO-XXXX" value={form.poRef} onChange={e => setForm(f => ({ ...f, poRef: e.target.value }))} />
                </div>
              </div>
              <div className="modal-row">
                <div className="form-group">
                  <label className="form-label">Vehicle / Courier No</label>
                  <input className="form-input" placeholder="TN-01-AB-1234" value={form.vehicleNo} onChange={e => setForm(f => ({ ...f, vehicleNo: e.target.value }))} />
                </div>
                <div className="form-group" style={{ flex: 2 }}>
                  <label className="form-label">Notes</label>
                  <input className="form-input" placeholder="Any special instructions..." value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} />
                </div>
              </div>

              <div style={{ marginTop: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
                  <strong>Line Items</strong>
                  <button className="btn btn-secondary" style={{ padding: '4px 10px', fontSize: 12 }} onClick={() => setLineItems(p => [...p, { ...emptyItem }])}><FaPlus /> Add Row</button>
                </div>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                  <thead><tr style={{ background: '#f8f9fa' }}>
                    <th style={{ padding: '6px 8px', textAlign: 'left' }}>Barcode</th>
                    <th style={{ padding: '6px 8px', textAlign: 'left' }}>Name</th>
                    <th style={{ padding: '6px 8px', width: 70 }}>Ordered</th>
                    <th style={{ padding: '6px 8px', width: 70 }}>Received</th>
                    <th style={{ padding: '6px 8px', width: 60 }}>Unit</th>
                    <th style={{ padding: '6px 8px', width: 30 }}></th>
                  </tr></thead>
                  <tbody>
                    {lineItems.map((it, i) => (
                      <tr key={i}>
                        <td><input className="form-input" style={{ padding: '4px 8px', fontSize: 12 }} value={it.barcode} onChange={e => setLineItems(p => p.map((x, j) => j === i ? { ...x, barcode: e.target.value } : x))} /></td>
                        <td><input className="form-input" style={{ padding: '4px 8px', fontSize: 12 }} value={it.name} onChange={e => setLineItems(p => p.map((x, j) => j === i ? { ...x, name: e.target.value } : x))} /></td>
                        <td><input className="form-input" type="number" style={{ padding: '4px 8px', fontSize: 12 }} value={it.orderedQty} onChange={e => setLineItems(p => p.map((x, j) => j === i ? { ...x, orderedQty: e.target.value } : x))} /></td>
                        <td><input className="form-input" type="number" style={{ padding: '4px 8px', fontSize: 12 }} value={it.receivedQty} onChange={e => setLineItems(p => p.map((x, j) => j === i ? { ...x, receivedQty: e.target.value } : x))} /></td>
                        <td><input className="form-input" style={{ padding: '4px 8px', fontSize: 12 }} value={it.unit} onChange={e => setLineItems(p => p.map((x, j) => j === i ? { ...x, unit: e.target.value } : x))} /></td>
                        <td><button style={{ background: 'none', border: 'none', color: '#e74c3c', cursor: 'pointer' }} onClick={() => setLineItems(p => p.filter((_, j) => j !== i))}><FaTrash /></button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowCreate(false)}>Cancel</button>
              <button className="btn btn-primary" onClick={createGRN} disabled={saving || !form.supplier}>
                {saving ? <FaSpinner /> : <FaSave />} Create Document
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import {
  FaWarehouse, FaPlus, FaSearch, FaExchangeAlt, FaTimes,
  FaSave, FaEdit, FaTrash, FaBoxes, FaMapMarkerAlt, FaSync, FaSpinner
} from 'react-icons/fa';
import './IMSLocations.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useConfirm } from '../components/ConfirmModal';

const ZONE_TYPES = ['WAREHOUSE', 'RND', 'MANUFACTURING', 'ASSEMBLY', 'QC', 'SHIPPING'];
const ZONE_COLORS = { WAREHOUSE: '#3498db', RND: '#9b59b6', MANUFACTURING: '#e67e22', ASSEMBLY: '#e74c3c', QC: '#27ae60', SHIPPING: '#1abc9c' };

export default function IMSLocations() {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const confirm = useConfirm();
  const [locations, setLocations] = useState([]);
  const [selected, setSelected] = useState(null);
  const [zoneStock, setZoneStock] = useState([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [showCreate, setShowCreate] = useState(false);
  const [showTransfer, setShowTransfer] = useState(false);
  const [form, setForm] = useState({ name: '', type: 'WAREHOUSE', description: '' });
  const [transfer, setTransfer] = useState({ barcode: '', itemName: '', fromLocationId: '', toLocationId: '', qty: '' });
  const [toast, setToast] = useState('');

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(''), 3000); };

  const loadLocations = useCallback(async () => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    try {
      const r = await imsFetch('/api/ims/locations');
      const d = await r.json();
      if (d.success) setLocations(d.locations);
    } finally { setLoading(false); }
  }, [activeWorkspaceId, imsFetch]);

  useEffect(() => { loadLocations(); }, [loadLocations]);

  const selectZone = async (loc) => {
    setSelected(loc);
    const r = await imsFetch(`/api/ims/locations/${loc.id}/stock`);
    const d = await r.json();
    if (d.success) setZoneStock(d.stock);
  };

  const createLocation = async () => {
    if (!form.name) return;
    const r = await imsFetch('/api/ims/locations', { method: 'POST', body: JSON.stringify(form) });
    const d = await r.json();
    if (d.success) {
      setLocations(prev => [...prev, { ...d.location, sku_count: 0, total_qty: 0 }]);
      setShowCreate(false);
      setForm({ name: '', type: 'WAREHOUSE', description: '' });
      showToast('✅ Zone created');
    }
  };

  const deleteLocation = async (loc) => {
    const ok = await confirm({
      title: `Delete zone "${loc.name}"?`,
      message: 'This will permanently remove the zone and all its stock assignments.',
      type: 'danger',
      confirmLabel: 'Delete Zone'
    });
    if (!ok) return;
    await imsFetch(`/api/ims/locations/${loc.id}`, { method: 'DELETE' });
    setLocations(prev => prev.filter(l => l.id !== loc.id));
    if (selected?.id === loc.id) { setSelected(null); setZoneStock([]); }
    showToast('🗑️ Zone deleted');
  };

  const doTransfer = async () => {
    if (!transfer.barcode || !transfer.toLocationId || !transfer.qty) return;
    const r = await imsFetch('/api/ims/locations/transfer', { method: 'POST', body: JSON.stringify(transfer) });
    const d = await r.json();
    if (d.success) {
      showToast('✅ Stock transferred successfully');
      setShowTransfer(false);
      setTransfer({ barcode: '', itemName: '', fromLocationId: '', toLocationId: '', qty: '' });
      loadLocations();
      if (selected) selectZone(selected);
    }
  };

  const filtered = locations.filter(l => l.name.toLowerCase().includes(search.toLowerCase()) || l.type.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="ims-locations-page">
      {toast && <div style={{ position: 'fixed', top: 20, right: 20, background: '#2c3e50', color: '#fff', padding: '12px 20px', borderRadius: 10, zIndex: 9999, fontSize: 14 }}>{toast}</div>}

      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Location &amp; Zone Tracking</h1>
          <p>Manage physical storage zones and track which items are in each area</p>
        </div>
        <div className="ims-header-right" style={{ gap: 10, display: 'flex' }}>
          <button className="btn btn-secondary" onClick={loadLocations}><FaSync /> Refresh</button>
          <button className="btn btn-secondary" style={{ borderColor: '#9b59b6', color: '#9b59b6' }} onClick={() => setShowTransfer(true)}><FaExchangeAlt /> Transfer Stock</button>
          <button className="btn btn-primary" onClick={() => setShowCreate(true)}><FaPlus /> Add Zone</button>
        </div>
      </div>

      {/* KPI Strip */}
      <div style={{ display: 'flex', gap: 16, marginBottom: 20 }}>
        {[
          { label: 'Total Zones', value: locations.length, color: '#3498db' },
          { label: 'Total SKUs', value: locations.reduce((a, l) => a + (l.sku_count || 0), 0), color: '#27ae60' },
          { label: 'Total Units', value: locations.reduce((a, l) => a + (l.total_qty || 0), 0), color: '#e67e22' },
        ].map((k, i) => (
          <div key={i} style={{ background: '#fff', borderRadius: 10, padding: '14px 20px', borderLeft: `4px solid ${k.color}`, display: 'flex', gap: 12, alignItems: 'center', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', flex: 1 }}>
            <div style={{ fontSize: 22, color: k.color, fontWeight: 700 }}>{k.value}</div>
            <div style={{ fontSize: 13, color: '#888' }}>{k.label}</div>
          </div>
        ))}
      </div>

      <div className="grn-layout">
        {/* Left List */}
        <div className="grn-list-panel">
          <div className="search-input" style={{ marginBottom: 12 }}>
            <FaSearch className="search-icon" />
            <input type="text" placeholder="Search zones..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          {loading ? <div style={{ textAlign: 'center', padding: 30, color: '#aaa' }}><FaSpinner /></div> : (
            <div className="grn-cards">
              {filtered.length === 0 && <div style={{ textAlign: 'center', padding: 30, color: '#aaa' }}><FaWarehouse style={{ fontSize: 32 }} /><br />No zones yet. Add your first zone.</div>}
              {filtered.map(loc => {
                const color = ZONE_COLORS[loc.type] || '#3498db';
                return (
                  <div key={loc.id} className={`grn-card ${selected?.id === loc.id ? 'active' : ''}`} onClick={() => selectZone(loc)} style={{ borderLeftColor: color }}>
                    <div className="grn-card-top">
                      <div className="grn-id" style={{ color }}><FaMapMarkerAlt /> {loc.name}</div>
                      <span style={{ background: color + '22', color, padding: '3px 10px', borderRadius: 10, fontSize: 12, fontWeight: 600 }}>{loc.type}</span>
                    </div>
                    {loc.description && <div style={{ fontSize: 13, color: '#888', marginTop: 4 }}>{loc.description}</div>}
                    <div className="grn-meta" style={{ marginTop: 8 }}>
                      <span><FaBoxes /> {loc.sku_count || 0} SKUs</span>
                      <span>{loc.total_qty || 0} units total</span>
                    </div>
                    <button style={{ position: 'absolute', top: 10, right: 10, background: 'none', border: 'none', color: '#e74c3c', cursor: 'pointer', opacity: 0.5 }}
                      onClick={e => { e.stopPropagation(); deleteLocation(loc); }} onMouseEnter={e => e.currentTarget.style.opacity = 1} onMouseLeave={e => e.currentTarget.style.opacity = 0.5}>
                      <FaTrash />
                    </button>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Right Detail */}
        <div className="grn-detail-panel">
          {selected ? (
            <>
              <div className="grn-detail-header">
                <div>
                  <h2><FaMapMarkerAlt style={{ color: ZONE_COLORS[selected.type] }} /> {selected.name}</h2>
                  <div style={{ color: '#888', fontSize: 14 }}>{selected.type} Zone {selected.description && `· ${selected.description}`}</div>
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                  <div style={{ textAlign: 'center' }}><div style={{ fontWeight: 700, fontSize: 22, color: '#3498db' }}>{selected.sku_count || 0}</div><div style={{ fontSize: 12, color: '#888' }}>SKUs</div></div>
                  <div style={{ textAlign: 'center', marginLeft: 12 }}><div style={{ fontWeight: 700, fontSize: 22, color: '#27ae60' }}>{selected.total_qty || 0}</div><div style={{ fontSize: 12, color: '#888' }}>Units</div></div>
                </div>
              </div>

              <h3 style={{ fontSize: 15, marginBottom: 12, marginTop: 16 }}>Stock in this Zone</h3>
              <div className="table-container" style={{ boxShadow: 'none', border: '1px solid #eee' }}>
                <table className="table">
                  <thead><tr><th>Barcode</th><th>Item Name</th><th>Category</th><th>Qty in Zone</th><th>Last Updated</th></tr></thead>
                  <tbody>
                    {zoneStock.length === 0 && <tr><td colSpan={5} style={{ textAlign: 'center', color: '#aaa', padding: 20 }}>No stock assigned to this zone yet. Use Transfer Stock to assign items.</td></tr>}
                    {zoneStock.map((s, i) => (
                      <tr key={i}>
                        <td><code>{s.barcode}</code></td>
                        <td><strong>{s.item_name}</strong></td>
                        <td>{s.category || '—'}</td>
                        <td style={{ fontWeight: 700, color: '#27ae60' }}>{s.qty}</td>
                        <td style={{ fontSize: 12, color: '#888' }}>{s.updated_at?.split('T')[0]}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <div style={{ marginTop: 16 }}>
                <button className="btn btn-secondary" style={{ borderColor: '#9b59b6', color: '#9b59b6' }}
                  onClick={() => { setTransfer(t => ({ ...t, toLocationId: String(selected.id) })); setShowTransfer(true); }}>
                  <FaExchangeAlt /> Transfer Stock Here
                </button>
              </div>
            </>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: '#aaa', gap: 12 }}>
              <FaWarehouse style={{ fontSize: 48 }} />
              <h3>Select a Zone</h3>
              <p style={{ fontSize: 14 }}>Click a zone to view its current stock and manage transfers.</p>
            </div>
          )}
        </div>
      </div>

      {/* Add Zone Modal */}
      {showCreate && (
        <div className="ims-modal-overlay" onClick={() => setShowCreate(false)}>
          <div className="ims-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div><h2>Add Storage Zone</h2><p>Define a physical area in your facility</p></div>
              <button className="modal-close" onClick={() => setShowCreate(false)}><FaTimes /></button>
            </div>
            <div className="modal-body">
              <div className="form-group"><label className="form-label">Zone Name *</label>
                <input className="form-input" placeholder="e.g. Warehouse A" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} /></div>
              <div className="modal-row">
                <div className="form-group"><label className="form-label">Zone Type</label>
                  <select className="form-select" value={form.type} onChange={e => setForm(f => ({ ...f, type: e.target.value }))}>
                    {ZONE_TYPES.map(t => <option key={t}>{t}</option>)}
                  </select></div>
                <div className="form-group" style={{ flex: 2 }}><label className="form-label">Description</label>
                  <input className="form-input" placeholder="Optional notes" value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} /></div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowCreate(false)}>Cancel</button>
              <button className="btn btn-primary" onClick={createLocation} disabled={!form.name}><FaSave /> Create Zone</button>
            </div>
          </div>
        </div>
      )}

      {/* Transfer Modal */}
      {showTransfer && (
        <div className="ims-modal-overlay" onClick={() => setShowTransfer(false)}>
          <div className="ims-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div><h2>Transfer Stock Between Zones</h2><p>Move items from one area to another</p></div>
              <button className="modal-close" onClick={() => setShowTransfer(false)}><FaTimes /></button>
            </div>
            <div className="modal-body">
              <div className="modal-row">
                <div className="form-group"><label className="form-label">Barcode *</label>
                  <input className="form-input" placeholder="Item barcode" value={transfer.barcode} onChange={e => setTransfer(t => ({ ...t, barcode: e.target.value }))} /></div>
                <div className="form-group" style={{ flex: 2 }}><label className="form-label">Item Name</label>
                  <input className="form-input" placeholder="Item description" value={transfer.itemName} onChange={e => setTransfer(t => ({ ...t, itemName: e.target.value }))} /></div>
              </div>
              <div className="modal-row">
                <div className="form-group"><label className="form-label">From Zone</label>
                  <select className="form-select" value={transfer.fromLocationId} onChange={e => setTransfer(t => ({ ...t, fromLocationId: e.target.value }))}>
                    <option value="">— Select source —</option>
                    {locations.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select></div>
                <div className="form-group"><label className="form-label">To Zone *</label>
                  <select className="form-select" value={transfer.toLocationId} onChange={e => setTransfer(t => ({ ...t, toLocationId: e.target.value }))}>
                    <option value="">— Select destination —</option>
                    {locations.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select></div>
                <div className="form-group" style={{ width: 100 }}><label className="form-label">Qty *</label>
                  <input className="form-input" type="number" placeholder="1" value={transfer.qty} onChange={e => setTransfer(t => ({ ...t, qty: e.target.value }))} /></div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowTransfer(false)}>Cancel</button>
              <button className="btn btn-primary" onClick={doTransfer} disabled={!transfer.barcode || !transfer.toLocationId || !transfer.qty}><FaExchangeAlt /> Transfer</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import {
  FaCogs, FaSearch, FaSync, FaCheckCircle, FaRedo, FaTimes,
  FaPlus, FaSave, FaSpinner, FaBarcode, FaClipboardList
} from 'react-icons/fa';
import './IMSProduction.css';
import { useWorkspace } from '../contexts/WorkspaceContext';

const OUTCOMES = [
  { value: 'FORWARD', label: '✓ Forward', color: '#27ae60', bg: '#eafaf1' },
  { value: 'REWORK',  label: '↩ Rework',  color: '#e67e22', bg: '#fef9e7' },
  { value: 'REJECT',  label: '✗ Reject',  color: '#e74c3c', bg: '#fdf0ed' },
];

export default function IMSProduction() {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const [stages, setStages] = useState([]);
  const [events, setEvents] = useState([]);
  const [summary, setSummary] = useState([]);
  const [selectedStage, setSelectedStage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [scan, setScan] = useState({ barcode: '', itemName: '', outcome: 'FORWARD', qty: 1, batchNo: '', notes: '', woId: '' });
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState('');

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(''), 3000); };

  const load = useCallback(async () => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    const [sR, eR, sumR] = await Promise.all([
      imsFetch('/api/ims/production/stages').then(r => r.json()),
      imsFetch('/api/ims/production/events').then(r => r.json()),
      imsFetch('/api/ims/production/summary').then(r => r.json()),
    ]);
    if (sR.success) { setStages(sR.stages); if (!selectedStage && sR.stages.length) setSelectedStage(sR.stages[0]); }
    if (eR.success) setEvents(eR.events);
    if (sumR.success) setSummary(sumR.summary);
    setLoading(false);
  }, [activeWorkspaceId, imsFetch]);

  useEffect(() => { load(); }, [load]);

  const recordScan = async () => {
    if (!scan.barcode || !selectedStage) return;
    setSaving(true);
    try {
      const payload = { ...scan, stageId: selectedStage.id, stageName: selectedStage.name, qty: Number(scan.qty) || 1 };
      const r = await imsFetch('/api/ims/production/scan', { method: 'POST', body: JSON.stringify(payload) });
      const d = await r.json();
      if (d.success) {
        showToast(`✅ ${scan.outcome} recorded at ${selectedStage.name}`);
        setScan(s => ({ ...s, barcode: '', batchNo: '', notes: '' }));
        load();
      } else { showToast('❌ ' + d.error); }
    } finally { setSaving(false); }
  };

  // Compute stage-level summary from summary array
  const getStageSummary = (stageName) => {
    const rows = summary.filter(s => s.stage_name === stageName);
    return {
      forward: rows.find(r => r.outcome === 'FORWARD')?.total || 0,
      rework: rows.find(r => r.outcome === 'REWORK')?.total || 0,
      reject: rows.find(r => r.outcome === 'REJECT')?.total || 0,
    };
  };

  const stageEvents = events.filter(e => e.stage_id === selectedStage?.id).slice(0, 50);

  return (
    <div className="ims-production-page">
      {toast && <div style={{ position: 'fixed', top: 20, right: 20, background: '#2c3e50', color: '#fff', padding: '12px 20px', borderRadius: 10, zIndex: 9999, fontSize: 14 }}>{toast}</div>}

      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Production &amp; QC Tracking</h1>
          <p>Scan items at each production stage — classify as Forward, Rework, or Reject</p>
        </div>
        <div className="ims-header-right">
          <button className="btn btn-secondary" onClick={load}><FaSync /> Refresh</button>
        </div>
      </div>

      {/* Stage Pipeline */}
      <div style={{ display: 'flex', gap: 0, marginBottom: 24, overflowX: 'auto' }}>
        {stages.map((st, i) => {
          const s = getStageSummary(st.name);
          const active = selectedStage?.id === st.id;
          return (
            <React.Fragment key={st.id}>
              <div onClick={() => setSelectedStage(st)} style={{
                background: active ? '#E3821E' : '#fff', color: active ? '#fff' : '#333',
                padding: '14px 20px', borderRadius: i === 0 ? '10px 0 0 10px' : i === stages.length - 1 ? '0 10px 10px 0' : 0,
                cursor: 'pointer', border: '1px solid #e0e0e0', borderLeft: i > 0 ? 'none' : '1px solid #e0e0e0',
                minWidth: 140, textAlign: 'center', transition: 'all 0.2s', boxShadow: active ? '0 4px 12px rgba(227,130,30,0.25)' : 'none'
              }}>
                <div style={{ fontWeight: 700, fontSize: 15 }}>{st.name}</div>
                <div style={{ fontSize: 12, marginTop: 4, opacity: active ? 1 : 0.6 }}>
                  <span style={{ color: active ? '#9fffba' : '#27ae60' }}>✓{s.forward}</span>
                  {' · '}
                  <span style={{ color: active ? '#ffe0a0' : '#e67e22' }}>↩{s.rework}</span>
                  {' · '}
                  <span style={{ color: active ? '#ffbaba' : '#e74c3c' }}>✗{s.reject}</span>
                </div>
              </div>
              {i < stages.length - 1 && <div style={{ width: 0, height: 0, borderTop: '31px solid transparent', borderBottom: '31px solid transparent', borderLeft: `18px solid ${active ? '#E3821E' : '#e0e0e0'}`, zIndex: 1 }} />}
            </React.Fragment>
          );
        })}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '380px 1fr', gap: 20 }}>
        {/* Scan Panel */}
        <div style={{ background: '#fff', borderRadius: 12, padding: 20, boxShadow: '0 2px 12px rgba(0,0,0,0.07)', height: 'fit-content' }}>
          <h3 style={{ marginBottom: 16, fontSize: 16 }}><FaBarcode /> Scan at: <span style={{ color: '#E3821E' }}>{selectedStage?.name || 'Select a stage'}</span></h3>

          <div className="form-group" style={{ marginBottom: 12 }}>
            <label className="form-label">Barcode *</label>
            <input className="form-input" placeholder="Scan or type barcode..." value={scan.barcode}
              onChange={e => setScan(s => ({ ...s, barcode: e.target.value }))}
              onKeyDown={e => e.key === 'Enter' && recordScan()} autoFocus />
          </div>
          <div className="form-group" style={{ marginBottom: 12 }}>
            <label className="form-label">Item Name</label>
            <input className="form-input" placeholder="Optional" value={scan.itemName} onChange={e => setScan(s => ({ ...s, itemName: e.target.value }))} />
          </div>

          <div style={{ marginBottom: 12 }}>
            <label className="form-label">Outcome *</label>
            <div style={{ display: 'flex', gap: 8, marginTop: 6 }}>
              {OUTCOMES.map(o => (
                <button key={o.value} onClick={() => setScan(s => ({ ...s, outcome: o.value }))}
                  style={{ flex: 1, padding: '8px 0', border: `2px solid ${scan.outcome === o.value ? o.color : '#e0e0e0'}`, borderRadius: 8, background: scan.outcome === o.value ? o.bg : '#fff', color: o.color, fontWeight: 700, cursor: 'pointer', fontSize: 13, transition: 'all 0.15s' }}>
                  {o.label}
                </button>
              ))}
            </div>
          </div>

          <div className="modal-row" style={{ marginBottom: 12 }}>
            <div className="form-group">
              <label className="form-label">Qty</label>
              <input className="form-input" type="number" value={scan.qty} onChange={e => setScan(s => ({ ...s, qty: e.target.value }))} />
            </div>
            <div className="form-group" style={{ flex: 2 }}>
              <label className="form-label">Batch No</label>
              <input className="form-input" placeholder="Optional" value={scan.batchNo} onChange={e => setScan(s => ({ ...s, batchNo: e.target.value }))} />
            </div>
          </div>

          <div className="form-group" style={{ marginBottom: 16 }}>
            <label className="form-label">Notes</label>
            <input className="form-input" placeholder="Reason for rework/reject..." value={scan.notes} onChange={e => setScan(s => ({ ...s, notes: e.target.value }))} />
          </div>

          <button className="btn btn-primary" style={{ width: '100%' }} onClick={recordScan} disabled={saving || !scan.barcode || !selectedStage}>
            {saving ? <FaSpinner /> : <FaSave />} Record Scan
          </button>
        </div>

        {/* Events at Selected Stage */}
        <div style={{ background: '#fff', borderRadius: 12, padding: 20, boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
            <h3 style={{ fontSize: 16, margin: 0 }}><FaClipboardList /> Events at {selectedStage?.name}</h3>
          </div>

          {/* Summary Row */}
          {selectedStage && (() => {
            const s = getStageSummary(selectedStage.name);
            return (
              <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
                {[{ label: 'Forwarded', val: s.forward, color: '#27ae60' }, { label: 'Rework', val: s.rework, color: '#e67e22' }, { label: 'Rejected', val: s.reject, color: '#e74c3c' }].map((k, i) => (
                  <div key={i} style={{ flex: 1, background: '#f8f9fa', borderRadius: 8, padding: '10px 14px', borderLeft: `4px solid ${k.color}` }}>
                    <div style={{ fontWeight: 700, fontSize: 20, color: k.color }}>{k.val}</div>
                    <div style={{ fontSize: 12, color: '#888' }}>{k.label}</div>
                  </div>
                ))}
              </div>
            );
          })()}

          <div className="table-container" style={{ boxShadow: 'none', border: '1px solid #eee' }}>
            <table className="table">
              <thead><tr><th>Barcode</th><th>Item</th><th>Outcome</th><th>Qty</th><th>Batch</th><th>Operator</th><th>Time</th></tr></thead>
              <tbody>
                {stageEvents.length === 0 && <tr><td colSpan={7} style={{ textAlign: 'center', color: '#aaa', padding: 20 }}>No events at this stage yet.</td></tr>}
                {stageEvents.map((ev, i) => {
                  const o = OUTCOMES.find(x => x.value === ev.outcome) || OUTCOMES[0];
                  return (
                    <tr key={i}>
                      <td><code style={{ fontSize: 12 }}>{ev.barcode}</code></td>
                      <td>{ev.item_name}</td>
                      <td><span style={{ background: o.bg, color: o.color, padding: '3px 8px', borderRadius: 10, fontSize: 12, fontWeight: 600 }}>{o.label}</span></td>
                      <td>{ev.qty}</td>
                      <td style={{ fontSize: 12, color: '#888' }}>{ev.batch_no || '—'}</td>
                      <td style={{ fontSize: 12 }}>{ev.operator_name || '—'}</td>
                      <td style={{ fontSize: 12, color: '#888' }}>{ev.created_at?.replace('T', ' ').slice(0, 16)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import {
  FaChartBar, FaDownload, FaSearch, FaSync, FaFilter,
  FaBoxes, FaExchangeAlt, FaExclamationTriangle, FaHistory, FaSpinner
} from 'react-icons/fa';
import './IMSReports.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import * as XLSX from 'xlsx';

const TABS = [
  { key: 'scan',     label: 'Scan History',    icon: FaHistory },
  { key: 'stock',    label: 'Stock Summary',   icon: FaBoxes },
  { key: 'movement', label: 'Movement Report', icon: FaExchangeAlt },
  { key: 'lowstock', label: 'Low Stock',       icon: FaExclamationTriangle },
  { key: 'wastage',  label: 'Wastage Analysis',icon: FaChartBar },
];

export default function IMSReports() {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const [tab, setTab] = useState('scan');
  const [data, setData] = useState({ scan: [], stock: [], movement: [], lowstock: [], wastage: [], stockTotals: null });
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({ from: '', to: '', workflow: '', barcode: '', days: 30 });

  const load = useCallback(async (t) => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    try {
      const active = t || tab;
      if (active === 'scan') {
        const params = new URLSearchParams();
        if (filters.from) params.set('from', filters.from);
        if (filters.to) params.set('to', filters.to);
        if (filters.workflow) params.set('workflow', filters.workflow);
        if (filters.barcode) params.set('barcode', filters.barcode);
        const r = await imsFetch(`/api/ims/reports/scan-history?${params}`);
        const d = await r.json();
        if (d.success) setData(prev => ({ ...prev, scan: d.events }));
      } else if (active === 'stock') {
        const r = await imsFetch('/api/ims/reports/stock-summary');
        const d = await r.json();
        if (d.success) setData(prev => ({ ...prev, stock: d.items, stockTotals: d.totals }));
      } else if (active === 'movement') {
        const r = await imsFetch(`/api/ims/reports/movement?days=${filters.days}`);
        const d = await r.json();
        if (d.success) setData(prev => ({ ...prev, movement: d.movements }));
      } else if (active === 'lowstock') {
        const r = await imsFetch('/api/ims/reports/low-stock');
        const d = await r.json();
        if (d.success) setData(prev => ({ ...prev, lowstock: d.items }));
      } else if (active === 'wastage') {
        const r = await imsFetch('/api/ims/reports/wastage');
        const d = await r.json();
        if (d.success) setData(prev => ({ ...prev, wastage: d.wastage }));
      }
    } finally { setLoading(false); }
  }, [activeWorkspaceId, tab, filters, imsFetch]);

  useEffect(() => { load(); }, [tab, activeWorkspaceId]);

  const exportXLSX = (rows, filename) => {
    const ws = XLSX.utils.json_to_sheet(rows);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Report');
    XLSX.writeFile(wb, filename + '.xlsx');
  };

  const exportScan = () => exportXLSX(data.scan.map(e => ({
    Date: e.scanned_at?.replace('T', ' ').slice(0, 16),
    Barcode: e.barcode, Item: e.item_name, Action: e.workflow,
    Qty: e.quantity, 'Batch No': e.batch_no, 'Serial No': e.serial_no,
    Operator: e.operator, Notes: e.notes
  })), 'ScanHistory');

  const exportStock = () => exportXLSX(data.stock.map(i => ({
    Barcode: i.barcode, Name: i.name, Category: i.category,
    Stock: i.stock, Unit: i.unit, Supplier: i.supplier,
    'Unit Cost': i.cost, 'Total Value': i.total_value, 'Last Movement': i.last_movement?.split('T')[0]
  })), 'StockSummary');

  return (
    <div className="ims-reports-page">
      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Reports &amp; Analytics</h1>
          <p>Export scan history, stock summaries, movement reports, and low stock alerts</p>
        </div>
        <div className="ims-header-right" style={{ gap: 10, display: 'flex' }}>
          <button className="btn btn-secondary" onClick={() => load()}>
            <FaSync /> Refresh
          </button>
          {tab === 'scan' && <button className="btn btn-secondary" onClick={exportScan}><FaDownload /> Export Excel</button>}
          {tab === 'stock' && <button className="btn btn-secondary" onClick={exportStock}><FaDownload /> Export Excel</button>}
        </div>
      </div>

      {/* Tab Bar */}
      <div style={{ display: 'flex', gap: 4, marginBottom: 20, background: '#f0f2f5', borderRadius: 12, padding: 4 }}>
        {TABS.map(t => (
          <button key={t.key} onClick={() => { setTab(t.key); load(t.key); }}
            style={{ flex: 1, padding: '10px 0', border: 'none', borderRadius: 10, cursor: 'pointer', fontWeight: 600, fontSize: 14,
              background: tab === t.key ? '#fff' : 'transparent', color: tab === t.key ? '#E3821E' : '#666',
              boxShadow: tab === t.key ? '0 2px 8px rgba(0,0,0,0.08)' : 'none', transition: 'all 0.2s', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>
            <t.icon /> {t.label}
          </button>
        ))}
      </div>

      {/* Scan History Filters */}
      {tab === 'scan' && (
        <div style={{ background: '#fff', borderRadius: 12, padding: '14px 16px', marginBottom: 16, display: 'flex', gap: 12, flexWrap: 'wrap', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}>
          <div className="form-group" style={{ flex: 1, minWidth: 140 }}>
            <label className="form-label">From Date</label>
            <input type="date" className="form-input" value={filters.from} onChange={e => setFilters(f => ({ ...f, from: e.target.value }))} />
          </div>
          <div className="form-group" style={{ flex: 1, minWidth: 140 }}>
            <label className="form-label">To Date</label>
            <input type="date" className="form-input" value={filters.to} onChange={e => setFilters(f => ({ ...f, to: e.target.value }))} />
          </div>
          <div className="form-group" style={{ flex: 1 }}>
            <label className="form-label">Action / Workflow</label>
            <input className="form-input" placeholder="RECEIVE, DISPATCH..." value={filters.workflow} onChange={e => setFilters(f => ({ ...f, workflow: e.target.value }))} />
          </div>
          <div className="form-group" style={{ flex: 1 }}>
            <label className="form-label">Barcode Search</label>
            <input className="form-input" placeholder="Search barcode..." value={filters.barcode} onChange={e => setFilters(f => ({ ...f, barcode: e.target.value }))} />
          </div>
          <div style={{ display: 'flex', alignItems: 'flex-end' }}>
            <button className="btn btn-primary" onClick={() => load('scan')}><FaFilter /> Apply</button>
          </div>
        </div>
      )}

      {tab === 'movement' && (
        <div style={{ background: '#fff', borderRadius: 12, padding: '14px 16px', marginBottom: 16, display: 'flex', gap: 12, alignItems: 'flex-end', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}>
          <div className="form-group">
            <label className="form-label">Date Range</label>
            <select className="form-select" value={filters.days} onChange={e => setFilters(f => ({ ...f, days: e.target.value }))}>
              <option value={7}>Last 7 days</option>
              <option value={30}>Last 30 days</option>
              <option value={90}>Last 90 days</option>
              <option value={365}>Last 12 months</option>
            </select>
          </div>
          <button className="btn btn-primary" onClick={() => load('movement')}><FaFilter /> Apply</button>
        </div>
      )}

      {loading ? (
        <div style={{ textAlign: 'center', padding: 60, color: '#aaa' }}><FaSpinner style={{ fontSize: 32 }} /><br />Loading report...</div>
      ) : (
        <div style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 12px rgba(0,0,0,0.07)', overflow: 'hidden' }}>

          {/* Stock Totals Banner */}
          {tab === 'stock' && data.stockTotals && (
            <div style={{ display: 'flex', gap: 24, padding: '16px 20px', borderBottom: '1px solid #eee', background: '#fafbfc' }}>
              {[
                { label: 'Total SKUs', val: data.stockTotals.skus, color: '#3498db' },
                { label: 'Total Units', val: data.stockTotals.total_units, color: '#27ae60' },
                { label: 'Total Value', val: '₹' + Number(data.stockTotals.total_value).toLocaleString(), color: '#e67e22' },
              ].map((k, i) => (
                <div key={i}><div style={{ fontWeight: 700, fontSize: 22, color: k.color }}>{k.val}</div><div style={{ fontSize: 12, color: '#888' }}>{k.label}</div></div>
              ))}
            </div>
          )}

          {/* Scan History Table */}
          {tab === 'scan' && (
            <table className="table">
              <thead><tr><th>Date &amp; Time</th><th>Barcode</th><th>Item</th><th>Action</th><th>Qty</th><th>Batch No</th><th>Operator</th></tr></thead>
              <tbody>
                {data.scan.length === 0 && <tr><td colSpan={7} style={{ textAlign: 'center', color: '#aaa', padding: 30 }}>No scan events found.</td></tr>}
                {data.scan.map((e, i) => (
                  <tr key={i}>
                    <td style={{ fontSize: 12 }}>{e.scanned_at?.replace('T', ' ').slice(0, 16)}</td>
                    <td><code style={{ fontSize: 12 }}>{e.barcode}</code></td>
                    <td>{e.item_name}</td>
                    <td><span style={{ background: e.workflow?.includes('DISPATCH') || e.workflow?.includes('ISSUE') ? '#fdf0ed' : '#eafaf1', color: e.workflow?.includes('DISPATCH') || e.workflow?.includes('ISSUE') ? '#e74c3c' : '#27ae60', padding: '3px 8px', borderRadius: 10, fontSize: 12, fontWeight: 600 }}>{e.workflow}</span></td>
                    <td style={{ fontWeight: 600 }}>{e.quantity}</td>
                    <td style={{ fontSize: 12, color: '#888' }}>{e.batch_no || '—'}</td>
                    <td style={{ fontSize: 12 }}>{e.operator || '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {/* Stock Summary Table */}
          {tab === 'stock' && (
            <table className="table">
              <thead><tr><th>Barcode</th><th>Name</th><th>Category</th><th>Stock</th><th>Unit</th><th>Supplier</th><th>Unit Cost</th><th>Total Value</th></tr></thead>
              <tbody>
                {data.stock.length === 0 && <tr><td colSpan={8} style={{ textAlign: 'center', color: '#aaa', padding: 30 }}>No items in catalog.</td></tr>}
                {data.stock.map((i, idx) => (
                  <tr key={idx}>
                    <td><code style={{ fontSize: 12 }}>{i.barcode}</code></td>
                    <td><strong>{i.name}</strong></td>
                    <td>{i.category}</td>
                    <td style={{ fontWeight: 700, color: i.stock === 0 ? '#e74c3c' : '#27ae60' }}>{i.stock}</td>
                    <td>{i.unit}</td>
                    <td style={{ fontSize: 12, color: '#888' }}>{i.supplier || '—'}</td>
                    <td>{i.cost ? '₹' + i.cost : '—'}</td>
                    <td style={{ fontWeight: 600 }}>{i.cost ? '₹' + Number(i.total_value).toLocaleString() : '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {/* Movement Table */}
          {tab === 'movement' && (
            <table className="table">
              <thead><tr><th>Barcode</th><th>Item Name</th><th>Action</th><th>Total Qty</th><th>Events</th><th>Last Activity</th></tr></thead>
              <tbody>
                {data.movement.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', color: '#aaa', padding: 30 }}>No movement data for this period.</td></tr>}
                {data.movement.map((m, i) => (
                  <tr key={i}>
                    <td><code style={{ fontSize: 12 }}>{m.barcode}</code></td>
                    <td>{m.item_name}</td>
                    <td><span style={{ background: '#eaf4fb', color: '#2980b9', padding: '3px 8px', borderRadius: 10, fontSize: 12 }}>{m.workflow}</span></td>
                    <td style={{ fontWeight: 700 }}>{m.total_qty}</td>
                    <td style={{ color: '#888' }}>{m.event_count}</td>
                    <td style={{ fontSize: 12, color: '#888' }}>{m.last_event?.split('T')[0]}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {/* Wastage Analysis Table */}
          {tab === 'wastage' && (
            <table className="table">
              <thead><tr><th>Barcode</th><th>Item</th><th>Work Order</th><th>Wasted Qty</th><th>Incidents</th></tr></thead>
              <tbody>
                {data.wastage.length === 0 && <tr><td colSpan={5} style={{ textAlign: 'center', color: '#aaa', padding: 30 }}>✅ No wastage or rejections recorded.</td></tr>}
                {data.wastage.map((w, i) => (
                  <tr key={i}>
                    <td><code style={{ fontSize: 12 }}>{w.barcode}</code></td>
                    <td><strong>{w.item_name}</strong></td>
                    <td style={{ color: '#888', fontSize: 12 }}>{w.wo_number || '—'}</td>
                    <td style={{ fontWeight: 700, color: '#e74c3c' }}>{w.wasted_qty}</td>
                    <td style={{ color: '#888' }}>{w.incident_count}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {/* Low Stock Table */}
          {tab === 'lowstock' && (
            <table className="table">
              <thead><tr><th>Barcode</th><th>Name</th><th>Category</th><th>Current Stock</th><th>Threshold</th><th>Shortfall</th><th>Urgency</th></tr></thead>
              <tbody>
                {data.lowstock.length === 0 && <tr><td colSpan={7} style={{ textAlign: 'center', color: '#aaa', padding: 30 }}>✅ No low stock items! All products are above threshold.</td></tr>}
                {data.lowstock.map((i, idx) => {
                  const shortfall = i.threshold - i.stock;
                  const critical = i.stock === 0;
                  return (
                    <tr key={idx}>
                      <td><code style={{ fontSize: 12 }}>{i.barcode}</code></td>
                      <td><strong>{i.name}</strong></td>
                      <td>{i.category}</td>
                      <td style={{ fontWeight: 700, color: critical ? '#e74c3c' : '#e67e22' }}>{i.stock}</td>
                      <td style={{ color: '#888' }}>{i.threshold}</td>
                      <td style={{ color: '#e74c3c', fontWeight: 600 }}>-{shortfall}</td>
                      <td><span style={{ background: critical ? '#fdf0ed' : '#fef9e7', color: critical ? '#e74c3c' : '#e67e22', padding: '3px 8px', borderRadius: 10, fontSize: 12, fontWeight: 600 }}>{critical ? '🔴 OUT OF STOCK' : '🟡 LOW'}</span></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import {
  FaBarcode, FaSearch, FaCheckCircle, FaExclamationCircle,
  FaArrowUp, FaArrowDown, FaPlus, FaTimes, FaClock,
  FaCubes, FaLayerGroup, FaTag, FaBoxOpen, FaSave,
  FaTruckLoading, FaDolly, FaCogs, FaClipboardCheck, FaShippingFast
} from 'react-icons/fa';
import './IMSScanner.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useWebSocket } from '../contexts/WebSocketContext';

const trackingColors = { FEFO: '#e74c3c', FIFO: '#3498db', LIFO: '#27ae60' };

const IMSScanner = () => {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const { scanBuffer, latestScan } = useWebSocket();
  const [scanInput, setScanInput] = useState('');
  const [scanResult, setScanResult] = useState(null);
  const [foundItem, setFoundItem] = useState(null);
  const [scanning, setScanning] = useState(false);
  const [scanStage, setScanStage] = useState('RECEIVE');
  const [dynamicStages, setDynamicStages] = useState([
    { id: 1, name: 'RECEIVE', color: '#27ae60' },
    { id: 2, name: 'DISPATCH', color: '#e74c3c' },
    { id: 3, name: 'PUTAWAY', color: '#f39c12' }
  ]);
  const [batchNo, setBatchNo] = useState('');
  const [serialNo, setSerialNo] = useState('');
  const [scanLog, setScanLog] = useState([]);
  const [showOnboard, setShowOnboard] = useState(false);
  const [onboardForm, setOnboardForm] = useState({ name: '', category: 'General', unit: 'Unit', qty: '', tracking: 'FIFO' });
  const [newItemBarcode, setNewItemBarcode] = useState('');
  const [autoLogEnabled, setAutoLogEnabled] = useState(true);
  const [fefoRec, setFefoRec] = useState([]);
  const [dynamicCategories, setDynamicCategories] = useState(['General', 'Pharmacy', 'PPE', 'Hygiene', 'Electronics', 'Food & Beverage']);
  const inputRef = useRef(null);

  // Fetch recent scan events
  const fetchEvents = async () => {
    if (!activeWorkspaceId) return;
    try {
      const res = await imsFetch('/api/ims/scanner/events?limit=20');
      const data = await res.json();
      if (data.success) {
        setScanLog(data.events.map(e => ({
          barcode: e.barcode, product: e.item_name || 'Unknown', action: e.workflow,
          qty: e.quantity, unit: e.unit || '', time: new Date(e.scanned_at).toLocaleTimeString(),
          trace: [e.batch_no ? `B:${e.batch_no}` : '', e.serial_no ? `S:${e.serial_no}` : ''].filter(Boolean).join(' | ')
        })));
      }
    } catch (err) { console.error('Failed to fetch events'); }
  };

  // Live WebSocket Updates - trigger full scan lookup when ESP32 scan arrives
  useEffect(() => {
    const barcode = scanBuffer?.barcodeData || latestScan?.barcodeData;
    if (barcode) {
      doScan(barcode);
    }
  }, [latestScan?.id, scanBuffer?.lastUpdate]);

  // Load Preferences and Dynamic Stages
  useEffect(() => {
    if (inputRef.current) inputRef.current.focus();
    const loadData = async () => {
      if (activeWorkspaceId) {
        try {
          const res = await imsFetch('/api/ims/settings');
          const setData = await res.json();
          if (setData.success && setData.settings?.scannerPrefs) {
             setAutoLogEnabled(setData.settings.scannerPrefs.autoLog);
          }
          const wfRes = await imsFetch('/api/ims/workflows');
          const wfData = await wfRes.json();
          if (wfData.success && wfData.workflows.length > 0) {
             setDynamicStages(wfData.workflows);
             if (!wfData.workflows.find(s => s.name === scanStage)) {
               setScanStage(wfData.workflows[0].name);
             }
          }
          // Fetch dynamic categories
          const catRes = await imsFetch('/api/ims/categories');
          const catData = await catRes.json();
          if (catData.success && catData.categories.length > 0) {
            setDynamicCategories(catData.categories.map(c => c.name));
          }
          fetchEvents();
        } catch (e) { console.error('IMS fetch error:', e); }
      }
    };
    loadData();
  }, [activeWorkspaceId]);

  const recordScanEvent = async (item, workflow, qty = 1, batch = '', serial = '', nameFallback = '') => {
    try {
      await imsFetch('/api/ims/scanner/scan', {
        method: 'POST',
        body: JSON.stringify({
          barcode: item ? item.barcode : newItemBarcode,
          itemId: item ? item.id : null,
          itemName: item ? item.name : nameFallback,
          workflow,
          quantity: qty,
          unit: item ? item.baseUnit : onboardForm.unit,
          batchNo: batch,
          serialNo: serial
        })
      });
      fetchEvents();
    } catch (e) { console.error('Error recording scan'); }
  };

  const doScan = async (code) => {
    const val = code || scanInput.trim();
    if (!val) return;
    setScanning(true);
    setScanResult(null);
    setFoundItem(null);
    setBatchNo('');
    setSerialNo('');

    try {
      const res = await imsFetch(`/api/ims/scanner/lookup/${encodeURIComponent(val)}`);
      const data = await res.json();
      setScanning(false);

      if (data.success && data.found) {
        setFoundItem(data.item);

        // Fetch FEFO recommendation if item uses FEFO tracking
        if (data.item?.trackingMode === 'FEFO') {
          try {
            const fr = await imsFetch(`/api/ims/fefo-recommendation?barcode=${encodeURIComponent(val)}`);
            const fd = await fr.json();
            if (fd.success) setFefoRec(fd.recommendation || []);
          } catch(e) { setFefoRec([]); }
        } else {
          setFefoRec([]);
        }

        if (autoLogEnabled) {
           setScanResult('known');
           await recordScanEvent(data.item, scanStage, 1);
           setTimeout(() => inputRef.current?.focus(), 100);
        } else {
           setScanResult('pending_confirm');
        }
      } else {
        setScanResult('unknown');
        setNewItemBarcode(val);
        setShowOnboard(true);
      }
    } catch (err) {
      setScanning(false);
      setScanResult('error');
    }
    setScanInput('');
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') doScan();
  };

  const handleQuickScan = (code) => {
    setScanInput(code);
    setTimeout(() => doScan(code), 100);
  };

  const handleOnboardSave = async () => {
    // For unknown items, we don't insert into catalog automatically yet, just record the scan event
    await recordScanEvent(null, scanStage, onboardForm.qty || 1, '', '', onboardForm.name || 'New Item');
    setShowOnboard(false);
    setScanResult('onboarded');
    setOnboardForm({ name: '', category: 'General', unit: 'Unit', qty: '', tracking: 'FIFO' });
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const handleConfirmAction = async () => {
    await recordScanEvent(foundItem, scanStage, 1, batchNo, serialNo);
    setScanResult('confirmed');
    setTimeout(() => {
      setScanResult(null);
      setFoundItem(null);
      inputRef.current?.focus();
    }, 1200);
  };


  return (
    <div className="ims-scanner-page">
      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Smart Scanner</h1>
          <p>Scan barcodes to instantly look up, add or move stock items</p>
        </div>
        <div className="ims-header-right">
          <div className="scan-stage-toggle">
            {dynamicStages.map(s => (
              <button 
                key={s.id}
                className={`stage-btn ${scanStage === s.name ? 'active' : ''}`}
                style={scanStage === s.name ? { backgroundColor: s.color, color: 'white', borderColor: s.color } : {}}
                onClick={() => setScanStage(s.name)}
              >
                <FaCogs /> {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="scanner-layout">
        {/* Left — Scan Zone */}
        <div className="scanner-left">
          <div className={`scan-zone ${scanning ? 'scanning' : ''} ${scanResult === 'known' ? 'found' : ''} ${scanResult === 'unknown' ? 'notfound' : ''}`}>
            <div className="scan-icon-wrap">
              {scanning ? (
                <div className="scan-spinner"></div>
              ) : scanResult === 'known' ? (
                <FaCheckCircle className="scan-status-icon ok" />
              ) : scanResult === 'pending_confirm' ? (
                <FaExclamationCircle className="scan-status-icon warn" style={{ color: '#f39c12' }} />
              ) : scanResult === 'unknown' ? (
                <FaExclamationCircle className="scan-status-icon warn" />
              ) : scanResult === 'onboarded' ? (
                <FaCheckCircle className="scan-status-icon ok" />
              ) : (
                <FaBarcode className="scan-idle-icon" />
              )}
            </div>
            <div className="scan-label">
              {scanning ? 'Scanning...' :
                scanResult === 'known' ? 'Item Auto-Logged ✓' :
                scanResult === 'pending_confirm' ? 'Needs Confirmation' :
                scanResult === 'unknown' ? 'Unknown Barcode' :
                scanResult === 'onboarded' ? 'Item Onboarded! ✓' :
                scanResult === 'confirmed' ? `${scanStage} Confirmed ✓` :
                `Ready to Scan for ${scanStage}`}
            </div>
            <input
              ref={inputRef}
              className="scan-input"
              type="text"
              placeholder="Scan barcode or type here..."
              value={scanInput}
              onChange={e => setScanInput(e.target.value)}
              onKeyDown={handleKeyDown}
              autoFocus
            />
            <button className="btn btn-primary scan-btn" onClick={() => doScan()} disabled={scanning || !scanInput.trim()}>
              <FaSearch /> Scan
            </button>
          </div>

        </div>

        {/* Right — Product Info */}
        <div className="scanner-right">
          {(scanResult === 'known' || scanResult === 'pending_confirm') && foundItem ? (
            <div className="found-item-card">
              <div className="found-header">
                <div className="found-name">{foundItem.name}</div>
                <div className="found-tracking" style={{ background: `${trackingColors[foundItem.trackingMode]}22`, color: trackingColors[foundItem.trackingMode] }}>
                  {foundItem.trackingMode}
                </div>
              </div>
              <div className="found-details-grid">
                <div className="found-detail-item">
                  <FaTag className="fd-icon" /> <span className="fd-label">Barcode</span>
                  <span className="fd-value">{foundItem.barcode}</span>
                </div>
                <div className="found-detail-item">
                  <FaCubes className="fd-icon" /> <span className="fd-label">Category</span>
                  <span className="fd-value">{foundItem.category}</span>
                </div>

                {foundItem.customFields && Object.entries(foundItem.customFields).map(([key, value]) => (
                  <div className="found-detail-item" key={key}>
                    <FaTag className="fd-icon" style={{ color: '#8e44ad' }} /> <span className="fd-label">{key}</span>
                    <span className="fd-value">{value || '-'}</span>
                  </div>
                ))}

                <div className="found-detail-item stock-item">
                  <FaBoxOpen className="fd-icon" /> <span className="fd-label">Current Stock</span>
                  <span className={`fd-value stock-val ${foundItem.stock < 20 ? 'low-stock' : ''}`}>{foundItem.stock} {foundItem.baseUnit}s</span>
                </div>
                <div className="found-detail-item">
                  <FaLayerGroup className="fd-icon" /> <span className="fd-label">Unit</span>
                  <span className="fd-value">{foundItem.baseUnit}</span>
                </div>
                {/* Children panel (parent-child hierarchy) */}
              {foundItem.children && foundItem.children.length > 0 && (
                <div style={{ margin: '0 20px 12px', background: '#fff9f0', border: '1px solid #f39c12', borderRadius: 8, padding: 12 }}>
                  <div style={{ fontWeight: 600, fontSize: 13, color: '#e67e22', marginBottom: 8 }}>📦 Box contains {foundItem.children.length} child item(s):</div>
                  {foundItem.children.map((c, i) => (
                    <div key={i} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, padding: '4px 0', borderBottom: '1px solid #fde8c8' }}>
                      <span><code>{c.barcode}</code> — {c.name}</span>
                      <span style={{ fontWeight: 600, color: c.stock === 0 ? '#e74c3c' : '#27ae60' }}>Stock: {c.stock}</span>
                    </div>
                  ))}
                </div>
              )}

              {/* FEFO Recommendation */}
              {fefoRec.length > 0 && (
                <div style={{ margin: '0 20px 12px', background: '#fff0f0', border: '1px solid #e74c3c', borderRadius: 8, padding: 12 }}>
                  <div style={{ fontWeight: 600, fontSize: 13, color: '#e74c3c', marginBottom: 8 }}>🧊 FEFO — Dispatch this batch first:</div>
                  {fefoRec.map((b, i) => (
                    <div key={i} style={{ fontSize: 13, padding: '3px 0', color: '#555' }}>
                      Batch <strong>{b.batch_no}</strong> → Expires <strong style={{ color: '#e74c3c' }}>{b.expiry_date?.split('T')[0]}</strong> (qty: {b.current_qty})
                    </div>
                  ))}
                </div>
              )}

              {foundItem.parentBarcode && (
                  <div className="found-detail-item uom-item">
                    <FaLayerGroup className="fd-icon" /> <span className="fd-label">Parent Unit</span>
                    <span className="fd-value">1 {foundItem.parentUnit} = {foundItem.multiplier} {foundItem.baseUnit}s</span>
                  </div>
                )}
                {foundItem.expiryDate && (
                  <div className="found-detail-item">
                    <FaClock className="fd-icon" /> <span className="fd-label">Expiry</span>
                    <span className="fd-value">{foundItem.expiryDate}</span>
                  </div>
                )}
                <div className="found-detail-item full-width">
                  <span className="fd-label">📍 Location</span>
                  <span className="fd-value">{foundItem.location}</span>
                </div>
              </div>
              {scanResult === 'known' ? (
                 <div className="found-actions" style={{ justifyContent: 'center', background: '#f0fff5', borderTop: '1px solid #c3e6cb', color: '#155724', padding: '12px', fontWeight: 'bold' }}>
                   <FaCheckCircle style={{ marginRight: '8px' }} /> Successfully Auto-Logged
                 </div>
              ) : (
                 <>
                    <div className="traceability-inputs" style={{ padding: '0 20px 15px', display: 'flex', gap: '10px' }}>
                      <input className="form-input" placeholder="Batch No (Opt)" value={batchNo} onChange={e=>setBatchNo(e.target.value)} style={{ flex: 1 }} />
                      <input className="form-input" placeholder="Serial No (Opt)" value={serialNo} onChange={e=>setSerialNo(e.target.value)} style={{ flex: 1 }} />
                    </div>
                    <div className="found-actions">
                      <button className="btn btn-primary" onClick={handleConfirmAction} style={{ width: '100%' }}>
                        <FaCheckCircle /> Confirm {scanStage} (1 {foundItem.baseUnit})
                      </button>
                    </div>
                 </>
              )}
            </div>
          ) : (
             <div className="empty-state" style={{ background: '#fff', border: '1px solid #dadce0', borderRadius: '12px', height: '100%' }}>
                <FaBarcode className="empty-state-icon" style={{ fontSize: '64px', color: '#e8eaed' }} />
                <h3 style={{ color: '#5f6368' }}>No Product Scanned</h3>
                <p>Scan an item to view its details here</p>
             </div>
          )}
        </div>
      </div>

      {/* Bottom — Scan History Table */}
      <div className="scan-history-section" style={{ marginTop: '24px' }}>
        <div className="card">
          <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
               <FaClock style={{ color: '#e3821e', fontSize: '20px' }} />
               <h2 style={{ margin: 0, fontSize: '18px' }}>Scan History Explorer</h2>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
                <div className="search-input" style={{ width: '250px' }}>
                  <FaSearch className="search-icon" />
                  <input type="text" placeholder="Search logs..." />
                </div>
                 <div className="filter-dropdown">
                   <select>
                     <option>All Actions</option>
                     {dynamicStages.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                   </select>
                 </div>
                <button className="btn btn-secondary">Export CSV</button>
            </div>
          </div>
          <div className="card-body" style={{ padding: 0 }}>
             <div className="table-container" style={{ boxShadow: 'none', borderRadius: 0 }}>
                <table className="table" style={{ width: '100%' }}>
                   <thead>
                      <tr>
                         <th>Time</th>
                         <th>Action</th>
                         <th>Barcode</th>
                         <th>Product</th>
                         <th>Qty</th>
                         <th>Traceability</th>
                         <th>User</th>
                         <th style={{ textAlign: 'right' }}>Actions</th>
                      </tr>
                   </thead>
                   <tbody>
                      {scanLog.map((entry, i) => (
                         <tr key={`log-${i}`}>
                            <td style={{ color: '#5f6368', fontSize: '13px' }}>{entry.time}</td>
                            <td><span className={`log-action-badge action-${entry.action.toLowerCase()}`}>{entry.action}</span></td>
                            <td style={{ fontFamily: 'monospace', fontWeight: 600 }}>{entry.barcode}</td>
                            <td style={{ fontWeight: 600, color: '#2c3e50' }}>{entry.product}</td>
                            <td>{entry.qty} {entry.unit}</td>
                            <td style={{ fontSize: '12px', color: '#7f8c8d' }}>{entry.trace || '-'}</td>
                            <td style={{ fontSize: '13px' }}>Admin (Aisle 4)</td>
                            <td style={{ textAlign: 'right' }}>
                               <button className="icon-btn delete-btn" title="Revert Scan">
                                  <FaTimes />
                               </button>
                            </td>
                         </tr>
                      ))}
                      {scanLog.length === 0 && (
                         <tr>
                            <td colSpan="8" style={{ textAlign: 'center', padding: '40px', color: '#95a5a6' }}>
                               No scans logged in this session yet.
                            </td>
                         </tr>
                      )}
                   </tbody>
                </table>
             </div>
          </div>
        </div>


      </div>

      {/* Unknown Barcode Onboarding Modal */}
      {showOnboard && (
        <div className="ims-modal-overlay" onClick={() => setShowOnboard(false)}>
          <div className="ims-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <FaPlus className="modal-icon" />
              <div>
                <h2>New Barcode Detected</h2>
                <p>Barcode <strong>{newItemBarcode}</strong> is not in your catalog. Add it now?</p>
              </div>
              <button className="modal-close" onClick={() => setShowOnboard(false)}><FaTimes /></button>
            </div>
            <div className="modal-body">
              <div className="form-group">
                <label className="form-label">Product Name *</label>
                <input className="form-input" placeholder="e.g. Aspirin 100mg" value={onboardForm.name}
                  onChange={e => setOnboardForm(f => ({ ...f, name: e.target.value }))} />
              </div>
              <div className="modal-row">
                <div className="form-group">
                  <label className="form-label">Category</label>
                  <select className="form-select" value={onboardForm.category}
                    onChange={e => setOnboardForm(f => ({ ...f, category: e.target.value }))}>
                    {dynamicCategories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Base Unit</label>
                  <select className="form-select" value={onboardForm.unit}
                    onChange={e => setOnboardForm(f => ({ ...f, unit: e.target.value }))}>
                    <option>Unit</option>
                    <option>Pack</option>
                    <option>Box</option>
                    <option>Case</option>
                    <option>Piece</option>
                    <option>Kg</option>
                    <option>Litre</option>
                  </select>
                </div>
              </div>
              <div className="modal-row">
                <div className="form-group">
                  <label className="form-label">Opening Quantity</label>
                  <input className="form-input" type="number" placeholder="0" value={onboardForm.qty}
                    onChange={e => setOnboardForm(f => ({ ...f, qty: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Tracking Mode</label>
                  <select className="form-select" value={onboardForm.tracking}
                    onChange={e => setOnboardForm(f => ({ ...f, tracking: e.target.value }))}>
                    <option value="FIFO">FIFO — First In First Out</option>
                    <option value="FEFO">FEFO — First Expire First Out</option>
                    <option value="LIFO">LIFO — Last In First Out</option>
                  </select>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowOnboard(false)}>Skip for Now</button>
              <button className="btn btn-primary" onClick={handleOnboardSave}>
                <FaSave /> Add to Catalog
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default IMSScanner;

import React, { useState, useEffect } from 'react';
import {
  FaCog, FaDatabase, FaBell, FaToggleOn, FaToggleOff, 
  FaSave, FaCheckCircle, FaLock, FaBarcode, FaBrain, 
  FaRobot, FaPlug, FaMoneyBillWave, FaChartLine, 
  FaPlus, FaTrash, FaEdit, FaLayerGroup, FaExchangeAlt
} from 'react-icons/fa';
import './IMSSettings.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useConfirm } from '../components/ConfirmModal';

const IMSSettings = () => {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const confirm = useConfirm();

  // Master Dynamic State
  const [categories, setCategories] = useState([]);
  const [workflows, setWorkflows] = useState([]);

  // Category Builder State
  const [newCatName, setNewCatName] = useState('');
  const [newCatMode, setNewCatMode] = useState('FIFO');
  const [newCatAlert, setNewCatAlert] = useState('');
  const [newCatReorder, setNewCatReorder] = useState('');
  const [newCatColor, setNewCatColor] = useState('#3498db');

  // Workflow Builder State
  const [newFlowName, setNewFlowName] = useState('');
  const [newFlowColor, setNewFlowColor] = useState('#3498db');

  // Other Settings
  const [alerts, setAlerts] = useState({ email: true, dashboard: true, sms: false, push: true });
  const [security, setSecurity] = useState({ batchStrict: true, managerApproval: false, immutableLogs: true, requireSSO: false });
  const [aiSettings, setAiSettings] = useState({ autoReorder: true, predictiveBuffer: true, dynamicThresholds: true, advisoryMode: false });
  const [integrations, setIntegrations] = useState({ sap: true, oracle: false, vendorEmail: true, zebraPrinter: true });
  const [scannerPrefs, setScannerPrefs] = useState({ autoLog: true, sound: true, vibration: true });

  const [procurementAction, setProcurementAction] = useState('draft'); // draft, email, erp
  const [spendLimit, setSpendLimit] = useState(5000);
  const [bufferPct, setBufferPct] = useState(15);
  const [saved, setSaved] = useState(false);

  // Fetch data on mount
  useEffect(() => {
    if(!activeWorkspaceId) return;
    const loadData = async () => {
       try {
          const catRes = await imsFetch('/api/ims/categories');
          const catData = await catRes.json();
          if(catData.success) setCategories(catData.categories);

          const wfRes = await imsFetch('/api/ims/workflows');
          const wfData = await wfRes.json();
          if(wfData.success) setWorkflows(wfData.workflows);

          const setRes = await imsFetch('/api/ims/settings');
          const setData = await setRes.json();
          if(setData.success && setData.settings && Object.keys(setData.settings).length > 0) {
             const prefs = setData.settings;
             if(prefs.alerts) setAlerts(prefs.alerts);
             if(prefs.security) setSecurity(prefs.security);
             if(prefs.aiSettings) setAiSettings(prefs.aiSettings);
             if(prefs.integrations) setIntegrations(prefs.integrations);
             if(prefs.scannerPrefs) setScannerPrefs(prefs.scannerPrefs);
             if(prefs.procurementAction) setProcurementAction(prefs.procurementAction);
             if(prefs.spendLimit) setSpendLimit(prefs.spendLimit);
             if(prefs.bufferPct) setBufferPct(prefs.bufferPct);
          }
       } catch (err) { console.error("Error fetching IMS data", err); }
    };
    loadData();
  }, [activeWorkspaceId]);

  const handleToggle = (setter, key) => setter(prev => ({ ...prev, [key]: !prev[key] }));

  // Dynamic Add Methods
  const addCategory = async () => {
    if (!newCatName || !newCatAlert || !newCatReorder) return;
    try {
      const res = await imsFetch('/api/ims/categories', {
        method: 'POST',
        body: JSON.stringify({ name: newCatName, mode: newCatMode, alertAt: Number(newCatAlert), reorderAt: Number(newCatReorder), color: newCatColor })
      });
      const data = await res.json();
      if(data.success) {
        setCategories([...categories, data.category]);
        setNewCatName(''); setNewCatAlert(''); setNewCatReorder('');
      }
    } catch(err) { console.error(err); }
  };

  const removeCategory = async (id, name) => {
    const ok = await confirm({
      title: `Delete category "${name}"?`,
      message: 'Items using this category will retain their current category label but lose threshold enforcement.',
      type: 'danger', confirmLabel: 'Delete Category'
    });
    if (!ok) return;
    try {
      await imsFetch(`/api/ims/categories/${id}`, { method: 'DELETE' });
      setCategories(categories.filter(c => c.id !== id));
    } catch(err) { console.error(err); }
  };

  const addWorkflow = async () => {
    if (!newFlowName) return;
    try {
      const res = await imsFetch('/api/ims/workflows', {
        method: 'POST',
        body: JSON.stringify({ name: newFlowName, color: newFlowColor })
      });
      const data = await res.json();
      if(data.success) {
        setWorkflows([...workflows, data.workflow]);
        setNewFlowName('');
      }
    } catch(err) { console.error(err); }
  };

  const removeWorkflow = async (id, name) => {
    const ok = await confirm({
      title: `Delete workflow "${name}"?`,
      message: 'Scans using this workflow will lose their workflow classification.',
      type: 'danger', confirmLabel: 'Delete Workflow'
    });
    if (!ok) return;
    try {
      await imsFetch(`/api/ims/workflows/${id}`, { method: 'DELETE' });
      setWorkflows(workflows.filter(w => w.id !== id));
    } catch(err) { console.error(err); }
  };

  const handleSave = async () => {
    const settings = { alerts, security, aiSettings, integrations, scannerPrefs, procurementAction, spendLimit, bufferPct };
    try {
      const res = await imsFetch('/api/ims/settings', {
        method: 'POST',
        body: JSON.stringify({ settings })
      });
      const data = await res.json();
      if(data.success) {
        setSaved(true);
        setTimeout(() => setSaved(false), 2500);
      }
    } catch(err) { console.error(err); }
  };

  return (
    <div className="ims-settings-page">
      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>IMS Decision Control</h1>
          <p>Configure autonomous rules, thresholds, and dynamic parameters</p>
        </div>
        <div className="ims-header-right">
          <button className="btn btn-primary btn-save-settings" onClick={handleSave}>
            {saved ? <><FaCheckCircle /> Saved!</> : <><FaSave /> Deploy Settings</>}
          </button>
        </div>
      </div>

      <div className="settings-grid">

        {/* ── ALERTS & NOTIFICATIONS ── */}
        <div className="settings-card alerts-card">
          <div className="settings-card-header">
            <FaBell className="settings-card-icon" />
            <h2>Alert Distribution</h2>
          </div>
          <div className="alert-toggles">
            {[
              { key: 'dashboard', label: 'Dashboard Alerts', desc: 'Show critical flags on IMS Command Center' },
              { key: 'email', label: 'Email Notifications', desc: 'Send daily digests and critical alerts to Admins' },
              { key: 'push', label: 'Mobile Push Notifications', desc: 'Real-time push to staff devices for stock-outs' },
              { key: 'sms', label: 'SMS Escallation', desc: 'Text supply chain managers on emergency shortages' },
            ].map(a => (
              <div key={a.key} className="alert-toggle-row" onClick={() => handleToggle(setAlerts, a.key)}>
                <div className="toggle-info">
                  <div className="toggle-label">{a.label}</div>
                  <div className="toggle-desc">{a.desc}</div>
                </div>
                {alerts[a.key] ? <FaToggleOn className="toggle-icon on" /> : <FaToggleOff className="toggle-icon off" />}
              </div>
            ))}
          </div>
        </div>

        {/* ── AI ENGINE CONFIGURATION ── */}
        <div className="settings-card ai-card">
          <div className="settings-card-header">
            <FaBrain className="settings-card-icon ai-icon" />
            <h2>Autonomous AI Engine</h2>
            <span className="ai-badge">Brain Config</span>
          </div>

          <div className="alert-toggles">
            <div className="alert-toggle-row" onClick={() => handleToggle(setAiSettings, 'autoReorder')}>
              <div className="toggle-info">
                <div className="toggle-label">Autonomous Procurement</div>
                <div className="toggle-desc">Allow AI to form restock requests based on velocity</div>
              </div>
              {aiSettings.autoReorder ? <FaToggleOn className="toggle-icon on" /> : <FaToggleOff className="toggle-icon off" />}
            </div>
            <div className="alert-toggle-row" onClick={() => handleToggle(setAiSettings, 'dynamicThresholds')}>
              <div className="toggle-info">
                <div className="toggle-label">Dynamic Thresholds</div>
                <div className="toggle-desc">AI shifts minimums based on seasonal demand</div>
              </div>
              {aiSettings.dynamicThresholds ? <FaToggleOn className="toggle-icon on" /> : <FaToggleOff className="toggle-icon off" />}
            </div>
          </div>

          <div className="settings-slider-group">
            <div className="slider-header">
              <span><FaChartLine /> Predictive Safety Buffer</span>
              <strong>+{bufferPct}%</strong>
            </div>
            <input type="range" min="0" max="50" step="5" value={bufferPct} onChange={(e) => setBufferPct(e.target.value)} className="slider-input" />
          </div>

          <div className="settings-slider-group">
            <div className="slider-header">
              <span><FaMoneyBillWave /> Auto-Approval Spend Limit</span>
              <strong>${spendLimit.toLocaleString()}</strong>
            </div>
            <input type="range" min="0" max="25000" step="1000" value={spendLimit} onChange={(e) => setSpendLimit(e.target.value)} className="slider-input" />
          </div>

          <div className="dropdown-group">
            <p className="dropdown-label"><FaRobot /> AI Procurement Action</p>
            <select value={procurementAction} onChange={e => setProcurementAction(e.target.value)} className="form-select dropdown-select">
              <option value="draft">Draft PO for Manager Review (Safest)</option>
              <option value="email">Auto-Email Authorized Vendors</option>
              <option value="erp">Push Directly to ERP (SAP/Oracle)</option>
            </select>
          </div>
        </div>

        {/* ── EXTERNAL INTEGRATIONS ── */}
        <div className="settings-card integrations-card">
          <div className="settings-card-header">
            <FaPlug className="settings-card-icon sync-icon" />
            <h2>System Integrations</h2>
          </div>
          <div className="alert-toggles">
            {[
              { key: 'sap', label: 'SAP Data Sync', desc: 'Bi-directional sync of inventory counts & POs' },
              { key: 'oracle', label: 'Oracle NetSuite', desc: 'Sync material mastering and financial ledgers' },
              { key: 'vendorEmail', label: 'Vendor EDI/Email', desc: 'Automated outgoing vendor communications' },
              { key: 'zebraPrinter', label: 'Zebra Label Printers', desc: 'Auto-print barcode tags on receiving items' },
            ].map(a => (
              <div key={a.key} className="alert-toggle-row" onClick={() => handleToggle(setIntegrations, a.key)}>
                <div className="toggle-info">
                  <div className="toggle-label">{a.label}</div>
                  <div className="toggle-desc">{a.desc}</div>
                </div>
                {integrations[a.key] ? <FaToggleOn className="toggle-icon sync-on" /> : <FaToggleOff className="toggle-icon off" />}
              </div>
            ))}
          </div>
        </div>

        {/* ── DYNAMIC CATEGORY BUILDER (New) ── */}
        <div className="settings-card category-builder-card">
          <div className="settings-card-header">
            <FaLayerGroup className="settings-card-icon" style={{color: '#f39c12'}} />
            <h2>Master Category Builder</h2>
          </div>
          <div className="builder-desc">Defined categories are synced to Catalog Master and enforce rotational behaviour (FEFO/FIFO).</div>

          <div className="builder-form">
            <div className="bf-inputs flex-row">
              <input type="text" placeholder="Cat Name (e.g. Chemicals)" value={newCatName} onChange={e => setNewCatName(e.target.value)} className="form-input" />
              <select value={newCatMode} onChange={e => setNewCatMode(e.target.value)} className="form-select">
                <option value="FIFO">FIFO (First In First Out)</option>
                <option value="FEFO">FEFO (First Expire First Out)</option>
                <option value="LIFO">LIFO (Last In First Out)</option>
              </select>
            </div>
            <div className="bf-inputs flex-row">
              <input type="number" placeholder="Alert Threshold" value={newCatAlert} onChange={e => setNewCatAlert(e.target.value)} className="form-input" />
              <input type="number" placeholder="Reorder point" value={newCatReorder} onChange={e => setNewCatReorder(e.target.value)} className="form-input" />
              <input type="color" value={newCatColor} onChange={e => setNewCatColor(e.target.value)} className="color-picker" title="Tag Color" />
              <button className="btn btn-secondary btn-icon-only" onClick={addCategory}><FaPlus /></button>
            </div>
          </div>

          <div className="builder-list">
            {categories.map(cat => (
              <div key={cat.id} className="builder-row">
                <span className="builder-color-dot" style={{background: cat.color}}></span>
                <div className="builder-info">
                  <strong>{cat.name}</strong> <span className="cat-mode-badge">{cat.mode}</span>
                  <div className="cat-limits">Alert: {cat.alertAt} · Reorder: {cat.reorderAt}</div>
                </div>
                <button className="btn-icon danger" onClick={() => removeCategory(cat.id, cat.name)}><FaTrash /></button>
              </div>
            ))}
          </div>
        </div>

        {/* ── DYNAMIC SCANNER WORKFLOWS (New) ── */}
        <div className="settings-card workflow-builder-card">
          <div className="settings-card-header">
            <FaExchangeAlt className="settings-card-icon" style={{color: '#3498db'}} />
            <h2>Scanner Operations Definition</h2>
          </div>
          <div className="builder-desc">Custom action modes loaded dynamically into the Smart Scanner app.</div>

          <div className="builder-form flex-row">
            <input type="text" placeholder="Operation (e.g. Return To Vendor)" value={newFlowName} onChange={e => setNewFlowName(e.target.value)} className="form-input" />
            <input type="color" value={newFlowColor} onChange={e => setNewFlowColor(e.target.value)} className="color-picker" />
            <button className="btn btn-secondary btn-icon-only" onClick={addWorkflow}><FaPlus /></button>
          </div>

          <div className="workflows-grid">
            {workflows.map(flow => (
              <div key={flow.id} className="workflow-pill" style={{borderLeftColor: flow.color}}>
                <span className="wf-name">{flow.name}</span>
                <FaTrash className="wf-del" onClick={() => removeWorkflow(flow.id)} />
              </div>
            ))}
          </div>
        </div>

        {/* ── SECURITY ── */}
        <div className="settings-card compliance-card">
          <div className="settings-card-header">
            <FaLock className="settings-card-icon" style={{ color: '#e74c3c' }} />
            <h2>Security & Audit Compliance</h2>
          </div>
          <div className="alert-toggles">
            {[
              { key: 'batchStrict', label: 'Strict Traceability', desc: 'Prevent stock changes without valid Batch/Serial inputs' },
              { key: 'managerApproval', label: 'Manager Overrides', desc: 'Require supervisor PIN for manual quantity adjustments' },
              { key: 'immutableLogs', label: 'Immutable Audit Trail', desc: 'Lock scan history from deletion (FDA / ISO compliance)' },
              { key: 'requireSSO', label: 'Enterprise SSO', desc: 'Enforce Microsoft Entra ID / Okta login for portal access' },
            ].map(a => (
              <div key={a.key} className="alert-toggle-row" onClick={() => handleToggle(setSecurity, a.key)}>
                <div className="toggle-info">
                  <div className="toggle-label">{a.label}</div>
                  <div className="toggle-desc">{a.desc}</div>
                </div>
                {security[a.key] ? <FaToggleOn className="toggle-icon on-red" /> : <FaToggleOff className="toggle-icon off" />}
              </div>
            ))}
          </div>
        </div>

      </div>

      {saved && (
        <div className="save-toast">
          <FaCheckCircle /> Configuration Deployed Successfully!
        </div>
      )}
    </div>
  );
};

