import React, { useState, useEffect, useCallback } from 'react';
import {
  FaUserPlus, FaShieldAlt, FaKey,
  FaSearch, FaTrash, FaLink, FaCopy,
  FaCheck, FaTimes, FaEnvelope, FaUserCircle, FaChevronDown,
  FaSyncAlt, FaUnlockAlt, FaClock
} from 'react-icons/fa';
import './IMSUsers.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useAuth } from '../contexts/AuthContext';
import { useToast } from '../components/Toast';

const SYSTEM_ROLES = [
  { value: 'owner', label: 'Owner', color: '#e74c3c', desc: 'Full admin access, can delete workspace' },
  { value: 'admin', label: 'Admin', color: '#9b59b6', desc: 'Can manage members, roles and settings' },
  { value: 'manager', label: 'Manager', color: '#f39c12', desc: 'Can view and edit inventory data' },
  { value: 'member', label: 'Member', color: '#3498db', desc: 'Standard access, can scan and view' },
  { value: 'viewer', label: 'Viewer', color: '#7f8c8d', desc: 'Read-only access to all data' },
];

const getRoleInfo = (role) => SYSTEM_ROLES.find(r => r.value === role) || { label: role, color: '#7f8c8d', desc: '' };

const getInitials = (name) => {
  if (!name) return '?';
  return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
};

const IMSUsers = () => {
  const { imsFetch, activeWorkspaceId, activeWorkspace } = useWorkspace();
  const { getUserInfo } = useAuth();
  const showToast = useToast();
  const currentUser = getUserInfo();

  const [members, setMembers] = useState([]);
  const [invites, setInvites] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('members');

  // Invite generator state
  const [genRole, setGenRole] = useState('member');
  const [genExpiry, setGenExpiry] = useState('7');
  const [generating, setGenerating] = useState(false);
  const [newInviteLink, setNewInviteLink] = useState('');
  const [copied, setCopied] = useState(false);

  // Role editor state
  const [editingRole, setEditingRole] = useState(null); // userId
  const [editRoleValue, setEditRoleValue] = useState('');
  const [savingRole, setSavingRole] = useState(false);

  // Role config modal
  const [showRoleModal, setShowRoleModal] = useState(false);

  const fetchData = useCallback(async () => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    try {
      const [membersRes, invitesRes] = await Promise.all([
        imsFetch('/api/workspaces/members'),
        imsFetch('/api/workspaces/invites')
      ]);
      const mData = await membersRes.json();
      const iData = await invitesRes.json();
      if (mData.success) setMembers(mData.members);
      if (iData.success) setInvites(iData.invites);
    } catch (err) {
      console.error(err);
    }
    setLoading(false);
  }, [activeWorkspaceId, imsFetch]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleGenerateInvite = async () => {
    setGenerating(true);
    try {
      const res = await imsFetch('/api/workspaces/invites/generate', {
        method: 'POST',
        body: JSON.stringify({ role: genRole, expiryDays: parseInt(genExpiry) })
      });
      const data = await res.json();
      if (data.success) {
        const baseUrl = window.location.origin;
        const link = `${baseUrl}/onboarding?invite=${data.token}`;
        setNewInviteLink(link);
        await fetchData();
        showToast('Invite link generated!', 'success');
      } else {
        showToast(data.error || 'Failed to generate link', 'error');
      }
    } catch {
      showToast('Failed to generate invite link', 'error');
    }
    setGenerating(false);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(newInviteLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
  };

  const handleRevokeInvite = async (id) => {
    try {
      const res = await imsFetch(`/api/workspaces/invites/${id}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) {
        setInvites(prev => prev.filter(i => i.id !== id));
        showToast('Invite revoked', 'success');
      }
    } catch {
      showToast('Failed to revoke invite', 'error');
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    setSavingRole(true);
    try {
      const res = await imsFetch(`/api/workspaces/members/${userId}/role`, {
        method: 'PATCH',
        body: JSON.stringify({ role: newRole })
      });
      const data = await res.json();
      if (data.success) {
        setMembers(prev => prev.map(m => m.id === userId ? { ...m, role: newRole } : m));
        showToast('Role updated', 'success');
      } else {
        showToast(data.error || 'Failed to update role', 'error');
      }
    } catch {
      showToast('Failed to update role', 'error');
    }
    setEditingRole(null);
    setSavingRole(false);
  };

  const handleRemoveMember = async (userId, name) => {
    if (!window.confirm(`Remove ${name} from this workspace?`)) return;
    try {
      const res = await imsFetch(`/api/workspaces/members/${userId}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) {
        setMembers(prev => prev.filter(m => m.id !== userId));
        showToast(`${name} removed from workspace`, 'success');
      } else {
        showToast(data.error || 'Failed to remove member', 'error');
      }
    } catch {
      showToast('Failed to remove member', 'error');
    }
  };

  const filtered = members.filter(m =>
    m.name.toLowerCase().includes(search.toLowerCase()) ||
    m.email.toLowerCase().includes(search.toLowerCase())
  );

  const isAdmin = ['owner', 'admin'].includes(activeWorkspace?.currentUserRole || 'member');

  return (
    <div className="ims-users-page">

      {/* ── HEADER ── */}
      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Team & Access Control</h1>
          <p>Manage workspace members, send invite links, and configure role-based access.</p>
        </div>
        <div className="ims-header-right">
          <button className="btn btn-secondary" onClick={() => setShowRoleModal(true)}>
            <FaShieldAlt /> Role Guide
          </button>
        </div>
      </div>

      {/* ── STATS ROW ── */}
      <div className="users-stats-row">
        <div className="users-stat-card">
          <div className="users-stat-num">{members.length}</div>
          <div className="users-stat-label">Total Members</div>
        </div>
        <div className="users-stat-card">
          <div className="users-stat-num" style={{ color: '#27ae60' }}>
            {members.filter(m => m.status === 'active').length}
          </div>
          <div className="users-stat-label">Active</div>
        </div>
        <div className="users-stat-card">
          <div className="users-stat-num" style={{ color: '#e74c3c' }}>
            {members.filter(m => m.role === 'owner' || m.role === 'admin').length}
          </div>
          <div className="users-stat-label">Admins</div>
        </div>
        <div className="users-stat-card">
          <div className="users-stat-num" style={{ color: '#3498db' }}>
            {invites.length}
          </div>
          <div className="users-stat-label">Active Invite Links</div>
        </div>
      </div>

      {/* ── TABS ── */}
      <div className="users-tabs">
        <button className={`users-tab ${activeTab === 'members' ? 'active' : ''}`} onClick={() => setActiveTab('members')}>
          Members ({members.length})
        </button>
        <button className={`users-tab ${activeTab === 'invite' ? 'active' : ''}`} onClick={() => setActiveTab('invite')}>
          Invite Links ({invites.length})
        </button>
      </div>

      {/* ── MEMBERS TAB ── */}
      {activeTab === 'members' && (
        <div className="users-members-panel">
          <div className="users-search-bar">
            <FaSearch className="usearch-icon" />
            <input
              type="text"
              placeholder="Search by name or email…"
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
            <button className="users-refresh-btn" onClick={fetchData} title="Refresh">
              <FaSyncAlt />
            </button>
          </div>

          {loading ? (
            <div className="users-loading">Loading members…</div>
          ) : filtered.length === 0 ? (
            <div className="users-empty">
              <FaUserCircle className="users-empty-icon" />
              <p>No members found. Invite your team to get started!</p>
            </div>
          ) : (
            <div className="members-list">
              {filtered.map(member => {
                const roleInfo = getRoleInfo(member.role);
                const isYou = member.email === currentUser?.email;
                return (
                  <div className="member-card" key={member.id}>
                    <div className="member-avatar" style={{ background: roleInfo.color + '22', color: roleInfo.color }}>
                      {getInitials(member.name)}
                    </div>
                    <div className="member-info">
                      <div className="member-name">
                        {member.name}
                        {isYou && <span className="member-you-badge">You</span>}
                      </div>
                      <div className="member-email"><FaEnvelope /> {member.email}</div>
                    </div>

                    <div className="member-role-section">
                      {editingRole === member.id ? (
                        <div className="member-role-editor">
                          <select
                            value={editRoleValue}
                            onChange={e => setEditRoleValue(e.target.value)}
                            autoFocus
                          >
                            {SYSTEM_ROLES.map(r => (
                              <option key={r.value} value={r.value}>{r.label}</option>
                            ))}
                          </select>
                          <button className="role-save-btn" onClick={() => handleRoleChange(member.id, editRoleValue)} disabled={savingRole}>
                            <FaCheck />
                          </button>
                          <button className="role-cancel-btn" onClick={() => setEditingRole(null)}>
                            <FaTimes />
                          </button>
                        </div>
                      ) : (
                        <div
                          className="member-role-badge"
                          style={{ background: roleInfo.color + '15', color: roleInfo.color }}
                          onClick={() => {
                            if (isAdmin && !isYou) {
                              setEditingRole(member.id);
                              setEditRoleValue(member.role);
                            }
                          }}
                          title={isAdmin && !isYou ? 'Click to change role' : roleInfo.desc}
                        >
                          {member.role === 'owner' && <FaKey style={{ fontSize: 10 }} />}
                          {roleInfo.label}
                          {isAdmin && !isYou && <FaChevronDown style={{ fontSize: 9, marginLeft: 4, opacity: 0.6 }} />}
                        </div>
                      )}
                    </div>

                    <div className="member-status">
                      <span className={`member-status-dot ${member.status === 'active' ? 'active' : 'pending'}`} />
                      <span>{member.status === 'active' ? 'Active' : 'Pending'}</span>
                    </div>

                    <div className="member-joined">
                      <FaClock style={{ fontSize: 10, opacity: 0.5 }} />
                      {new Date(member.joinedAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}
                    </div>

                    {isAdmin && !isYou && (
                      <button
                        className="member-remove-btn"
                        onClick={() => handleRemoveMember(member.id, member.name)}
                        title="Remove from workspace"
                      >
                        <FaTrash />
                      </button>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* ── INVITE TAB ── */}
      {activeTab === 'invite' && (
        <div className="invite-tab-layout">

          {/* Generator Panel */}
          <div className="invite-generator-panel">
            <div className="igp-header">
              <div className="igp-icon"><FaLink /></div>
              <div>
                <div className="igp-title">Generate Invite Link</div>
                <div className="igp-sub">Anyone with this link can join your workspace with the selected role.</div>
              </div>
            </div>

            <div className="igp-controls">
              <div className="igp-field">
                <label>Assign Role</label>
                <div className="igp-role-grid">
                  {SYSTEM_ROLES.filter(r => r.value !== 'owner').map(r => (
                    <button
                      key={r.value}
                      className={`igp-role-btn ${genRole === r.value ? 'selected' : ''}`}
                      style={genRole === r.value ? { borderColor: r.color, color: r.color, background: r.color + '12' } : {}}
                      onClick={() => setGenRole(r.value)}
                    >
                      {r.label}
                    </button>
                  ))}
                </div>
                <div className="igp-role-desc">{getRoleInfo(genRole).desc}</div>
              </div>

              <div className="igp-field">
                <label>Link expires in</label>
                <div className="igp-expiry-row">
                  {['1', '3', '7', '14', '30'].map(d => (
                    <button key={d} className={`igp-expiry-btn ${genExpiry === d ? 'selected' : ''}`} onClick={() => setGenExpiry(d)}>
                      {d}d
                    </button>
                  ))}
                </div>
              </div>

              <button className="igp-generate-btn" onClick={handleGenerateInvite} disabled={generating}>
                {generating ? 'Generating…' : <><FaLink /> Generate Invite Link</>}
              </button>

              {newInviteLink && (
                <div className="igp-result">
                  <div className="igp-result-label">Share this link with your team:</div>
                  <div className="igp-link-row">
                    <input type="text" readOnly value={newInviteLink} className="igp-link-input" />
                    <button className="igp-copy-btn" onClick={handleCopy}>
                      {copied ? <><FaCheck /> Copied!</> : <><FaCopy /> Copy</>}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Active Links Panel */}
          <div className="active-invites-panel">
            <div className="aip-header">
              <div className="aip-title">Active Invite Links</div>
              <div className="aip-sub">{invites.length} link{invites.length !== 1 ? 's' : ''} currently active</div>
            </div>

            {invites.length === 0 ? (
              <div className="aip-empty">
                <FaUnlockAlt className="aip-empty-icon" />
                <p>No active links. Generate one to invite your team.</p>
              </div>
            ) : (
              <div className="aip-list">
                {invites.map(inv => {
                  const roleInfo = getRoleInfo(inv.role);
                  const expiry = new Date(inv.expires_at);
                  const daysLeft = Math.max(0, Math.ceil((expiry - new Date()) / (1000 * 60 * 60 * 24)));
                  return (
                    <div className="aip-row" key={inv.id}>
                      <div className="aip-token-wrap">
                        <span className="aip-token">{inv.token.slice(0, 12)}…</span>
                        <span className="aip-role-badge" style={{ color: roleInfo.color, background: roleInfo.color + '15' }}>{roleInfo.label}</span>
                      </div>
                      <div className="aip-meta">
                        <span><FaClock style={{ opacity: 0.5 }} /> {daysLeft}d left</span>
                        <span>{inv.uses_remaining} uses</span>
                        <span>by {inv.created_by_name}</span>
                      </div>
                      <button className="aip-revoke-btn" onClick={() => handleRevokeInvite(inv.id)} title="Revoke link">
                        <FaTimes />
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── ROLE GUIDE MODAL ── */}
      {showRoleModal && (
        <div className="modal-overlay" onClick={() => setShowRoleModal(false)}>
          <div className="role-guide-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2><FaShieldAlt /> Role Permissions Guide</h2>
              <button className="btn-close" onClick={() => setShowRoleModal(false)}><FaTimes /></button>
            </div>
            <div className="role-guide-body">
              {SYSTEM_ROLES.map(role => (
                <div className="role-guide-row" key={role.value}>
                  <div className="role-guide-badge" style={{ background: role.color + '15', color: role.color }}>
                    {role.value === 'owner' && <FaKey />} {role.label}
                  </div>
                  <div className="role-guide-desc">{role.desc}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default IMSUsers;

import React, { useState, useEffect, useCallback } from 'react';
import {
  FaClipboardList, FaPlus, FaSearch, FaCheckCircle,
  FaClock, FaExclamationTriangle, FaLayerGroup,
  FaBoxes, FaArrowRight, FaTimes, FaSave,
  FaCogs, FaSpinner, FaTrash, FaSync
} from 'react-icons/fa';
import './IMSWorkOrders.css';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useConfirm } from '../components/ConfirmModal';

const statusConfig = {
  PENDING:     { label: 'Pending',       color: '#7f8c8d', bg: '#ecf0f1', icon: FaClock },
  IN_PROGRESS: { label: 'In Progress',   color: '#e67e22', bg: '#fef9e7', icon: FaSpinner },
  QC:          { label: 'Quality Check', color: '#3498db', bg: '#eaf4fb', icon: FaCheckCircle },
  COMPLETE:    { label: 'Complete',      color: '#27ae60', bg: '#eafaf1', icon: FaCheckCircle },
  CANCELLED:   { label: 'Cancelled',     color: '#e74c3c', bg: '#fdf0ed', icon: FaTimes },
};

const NEXT_STATUS = { PENDING: 'IN_PROGRESS', IN_PROGRESS: 'QC', QC: 'COMPLETE' };
const NEXT_LABEL  = { PENDING: 'Start Production', IN_PROGRESS: 'Move to QC', QC: 'Mark Complete ✓' };

export default function IMSWorkOrders() {
  const { imsFetch, activeWorkspaceId } = useWorkspace();
  const confirm = useConfirm();
  const [workorders, setWorkorders] = useState([]);
  const [selected, setSelected] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('ALL');
  const [showCreate, setShowCreate] = useState(false);
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState('');
  const [newWO, setNewWO] = useState({ productBarcode: '', productName: '', targetQty: '', dueDate: '', priority: 'NORMAL', notes: '' });

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(''), 3000); };

  const loadWOs = useCallback(async () => {
    if (!activeWorkspaceId) return;
    setLoading(true);
    try {
      const r = await imsFetch('/api/ims/workorders');
      const d = await r.json();
      if (d.success) setWorkorders(d.workorders);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  }, [activeWorkspaceId, imsFetch]);

  useEffect(() => { loadWOs(); }, [loadWOs]);

  const selectWO = async (wo) => {
    setSelected(wo);
    const r = await imsFetch(`/api/ims/workorders/${wo.id}`);
    const d = await r.json();
    if (d.success) setMaterials(d.materials);
  };

  const createWO = async () => {
    if (!newWO.productName || !newWO.targetQty) return;
    setSaving(true);
    try {
      const r = await imsFetch('/api/ims/workorders', { method: 'POST', body: JSON.stringify(newWO) });
      const d = await r.json();
      if (d.success) {
        setWorkorders(prev => [d.workorder, ...prev]);
        setShowCreate(false);
        setNewWO({ productBarcode: '', productName: '', targetQty: '', dueDate: '', priority: 'NORMAL', notes: '' });
        showToast('✅ Work Order created');
      }
    } finally { setSaving(false); }
  };

  const changeStatus = async (wo, status) => {
    const r = await imsFetch(`/api/ims/workorders/${wo.id}/status`, { method: 'PUT', body: JSON.stringify({ status }) });
    const d = await r.json();
    if (d.success) {
      setWorkorders(prev => prev.map(w => w.id === wo.id ? { ...w, status } : w));
      setSelected(s => s?.id === wo.id ? { ...s, status } : s);
      showToast(`✅ Status updated to ${statusConfig[status].label}`);
      if (status === 'COMPLETE') showToast('🎉 BOM executed — raw materials deducted from stock!');
    }
  };

  const deleteWO = async (wo) => {
    const ok = await confirm({
      title: `Delete Work Order ${wo.wo_number}?`,
      message: 'This will permanently remove the work order and all its BOM items. This cannot be undone.',
      type: 'danger',
      confirmLabel: 'Delete Work Order'
    });
    if (!ok) return;
    await imsFetch(`/api/ims/workorders/${wo.id}`, { method: 'DELETE' });
    setWorkorders(prev => prev.filter(w => w.id !== wo.id));
    if (selected?.id === wo.id) setSelected(null);
    showToast('🗑️ Work Order deleted');
  };

  const filtered = workorders.filter(w => {
    const ms = w.product_name.toLowerCase().includes(search.toLowerCase()) || w.wo_number.toLowerCase().includes(search.toLowerCase());
    return ms && (filter === 'ALL' || w.status === filter);
  });

  return (
    <div className="ims-wo-page">
      {toast && <div style={{ position: 'fixed', top: 20, right: 20, background: '#2c3e50', color: '#fff', padding: '12px 20px', borderRadius: 10, zIndex: 9999, fontSize: 14 }}>{toast}</div>}

      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Work Orders</h1>
          <p>Create production jobs — BOM materials are auto-deducted from stock when marked Complete</p>
        </div>
        <div className="ims-header-right" style={{ gap: 10, display: 'flex' }}>
          <button className="btn btn-secondary" onClick={loadWOs}><FaSync /> Refresh</button>
          <button className="btn btn-primary" onClick={() => setShowCreate(true)}><FaPlus /> New Work Order</button>
        </div>
      </div>

      {/* KPI Strip */}
      <div className="wo-kpi-strip">
        {[
          { label: 'Total', value: workorders.length, color: '#E3821E', icon: FaClipboardList },
          { label: 'In Progress', value: workorders.filter(w => w.status === 'IN_PROGRESS').length, color: '#e67e22', icon: FaSpinner },
          { label: 'In QC', value: workorders.filter(w => w.status === 'QC').length, color: '#3498db', icon: FaCheckCircle },
          { label: 'Completed', value: workorders.filter(w => w.status === 'COMPLETE').length, color: '#27ae60', icon: FaCheckCircle },
          { label: 'Pending', value: workorders.filter(w => w.status === 'PENDING').length, color: '#7f8c8d', icon: FaClock },
        ].map((k, i) => (
          <div key={i} className="wo-kpi-card" style={{ borderLeftColor: k.color }}>
            <k.icon className="wo-kpi-icon" style={{ color: k.color }} />
            <div><div className="wo-kpi-value" style={{ color: k.color }}>{k.value}</div><div className="wo-kpi-label">{k.label}</div></div>
          </div>
        ))}
      </div>

      <div className="wo-layout">
        {/* Left List */}
        <div className="wo-list-panel">
          <div className="wo-controls">
            <div className="search-input" style={{ flex: 1 }}>
              <FaSearch className="search-icon" />
              <input type="text" placeholder="Search work orders..." value={search} onChange={e => setSearch(e.target.value)} />
            </div>
            <select className="form-select" value={filter} onChange={e => setFilter(e.target.value)} style={{ width: 140 }}>
              <option value="ALL">All Status</option>
              {Object.entries(statusConfig).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
            </select>
          </div>

          {loading ? <div style={{ padding: 30, textAlign: 'center', color: '#aaa' }}><FaSpinner /> Loading...</div> : (
            <div className="wo-cards">
              {filtered.length === 0 && <div style={{ padding: 30, textAlign: 'center', color: '#aaa' }}>No work orders found.</div>}
              {filtered.map(wo => {
                const sc = statusConfig[wo.status] || statusConfig.PENDING;
                const pct = wo.target_qty > 0 ? Math.round((wo.built_qty / wo.target_qty) * 100) : 0;
                return (
                  <div key={wo.id} className={`wo-card ${selected?.id === wo.id ? 'active' : ''}`} onClick={() => selectWO(wo)}>
                    <div className="wo-card-top">
                      <div className="wo-id">{wo.wo_number}</div>
                      <span className="wo-status-badge" style={{ background: sc.bg, color: sc.color }}>{sc.label}</span>
                    </div>
                    <div className="wo-product">{wo.product_name}</div>
                    <div className="wo-meta">
                      <span><FaBoxes /> {wo.built_qty}/{wo.target_qty} units</span>
                      {wo.due_date && <span><FaClock /> Due: {wo.due_date?.split('T')[0]}</span>}
                      <span style={{ color: wo.priority === 'CRITICAL' ? '#e74c3c' : '#999', fontSize: 12 }}>{wo.priority}</span>
                    </div>
                    <div className="wo-progress-bar">
                      <div className="wo-progress-fill" style={{ width: `${pct}%`, background: sc.color }} />
                    </div>
                    <div className="wo-pct">{pct}% complete</div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Right Detail */}
        <div className="wo-detail-panel">
          {selected ? (
            <>
              <div className="wo-detail-header">
                <div>
                  <h2>{selected.product_name}</h2>
                  <div className="wo-detail-id">{selected.wo_number}</div>
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <span className="wo-status-badge large" style={{ background: statusConfig[selected.status]?.bg, color: statusConfig[selected.status]?.color }}>
                    {statusConfig[selected.status]?.label}
                  </span>
                  {selected.status !== 'COMPLETE' && selected.status !== 'CANCELLED' && (
                    <button className="icon-btn delete-btn" onClick={() => deleteWO(selected)}><FaTrash /></button>
                  )}
                </div>
              </div>

              <div className="wo-detail-stats">
                <div className="wo-stat"><div className="wo-stat-val">{selected.target_qty}</div><div className="wo-stat-lbl">Target</div></div>
                <div className="wo-stat"><div className="wo-stat-val">{selected.built_qty}</div><div className="wo-stat-lbl">Built</div></div>
                <div className="wo-stat"><div className="wo-stat-val">{selected.target_qty - selected.built_qty}</div><div className="wo-stat-lbl">Remaining</div></div>
                <div className="wo-stat"><div className="wo-stat-val">{selected.due_date?.split('T')[0] || '—'}</div><div className="wo-stat-lbl">Due Date</div></div>
              </div>

              <div className="wo-materials-section">
                <h3><FaLayerGroup /> Bill of Materials {materials.length === 0 && <span style={{ color: '#aaa', fontWeight: 400, fontSize: 13 }}>(No BOM — add a BOM to the product in Catalog)</span>}</h3>
                {materials.length > 0 && (
                  <table className="wo-bom-table">
                    <thead><tr><th>Component</th><th>Required</th><th>Available Now</th><th>Status</th></tr></thead>
                    <tbody>
                      {materials.map((m, i) => {
                        const ok = Number(m.available_qty) >= Number(m.required_qty);
                        return (
                          <tr key={i}>
                            <td><code style={{ fontSize: 12 }}>{m.barcode}</code> {m.name}</td>
                            <td>{m.required_qty} {m.unit}</td>
                            <td style={{ color: ok ? '#27ae60' : '#e74c3c', fontWeight: 600 }}>{m.available_qty} {m.unit}</td>
                            <td><span className={`bom-status ${ok ? 'ok' : 'short'}`}>{ok ? '✓ OK' : `⚠ Short ${m.required_qty - m.available_qty}`}</span></td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                )}
              </div>

              {selected.notes && <div style={{ background: '#f8f9fa', borderRadius: 8, padding: '10px 14px', fontSize: 13, color: '#555', marginTop: 12 }}>📝 {selected.notes}</div>}

              <div className="wo-actions">
                {NEXT_STATUS[selected.status] && (
                  <button className="btn btn-primary" style={selected.status === 'QC' ? { background: '#27ae60' } : {}}
                    onClick={() => changeStatus(selected, NEXT_STATUS[selected.status])}>
                    <FaArrowRight /> {NEXT_LABEL[selected.status]}
                  </button>
                )}
                {selected.status !== 'COMPLETE' && selected.status !== 'CANCELLED' && (
                  <button className="btn btn-secondary" style={{ borderColor: '#e74c3c', color: '#e74c3c' }}
                    onClick={() => changeStatus(selected, 'CANCELLED')}>
                    <FaTimes /> Cancel WO
                  </button>
                )}
              </div>
            </>
          ) : (
            <div className="wo-empty-detail">
              <FaClipboardList className="wo-empty-icon" />
              <h3>Select a Work Order</h3>
              <p>Click any work order to view its BOM, track progress, and advance its production stage.</p>
            </div>
          )}
        </div>
      </div>

      {/* Create WO Modal */}
      {showCreate && (
        <div className="ims-modal-overlay" onClick={() => setShowCreate(false)}>
          <div className="ims-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div><h2>Create Work Order</h2><p>Define a new production job</p></div>
              <button className="modal-close" onClick={() => setShowCreate(false)}><FaTimes /></button>
            </div>
            <div className="modal-body">
              <div className="modal-row">
                <div className="form-group" style={{ flex: 2 }}>
                  <label className="form-label">Finished Product Name *</label>
                  <input className="form-input" placeholder="e.g. LED Tube Light 40W" value={newWO.productName} onChange={e => setNewWO(f => ({ ...f, productName: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Product Barcode (for BOM)</label>
                  <input className="form-input" placeholder="e.g. TUBE-40W" value={newWO.productBarcode} onChange={e => setNewWO(f => ({ ...f, productBarcode: e.target.value }))} />
                </div>
              </div>
              <div className="modal-row">
                <div className="form-group">
                  <label className="form-label">Target Quantity *</label>
                  <input className="form-input" type="number" placeholder="50" value={newWO.targetQty} onChange={e => setNewWO(f => ({ ...f, targetQty: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Due Date</label>
                  <input className="form-input" type="date" value={newWO.dueDate} onChange={e => setNewWO(f => ({ ...f, dueDate: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Priority</label>
                  <select className="form-select" value={newWO.priority} onChange={e => setNewWO(f => ({ ...f, priority: e.target.value }))}>
                    <option>NORMAL</option><option>HIGH</option><option>CRITICAL</option>
                  </select>
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Notes</label>
                <input className="form-input" placeholder="Any additional instructions..." value={newWO.notes} onChange={e => setNewWO(f => ({ ...f, notes: e.target.value }))} />
              </div>
              <div style={{ background: '#eaf4fb', borderRadius: 8, padding: '10px 14px', fontSize: 13, color: '#2980b9', marginTop: 8 }}>
                💡 If you enter a Product Barcode that has a BOM defined in the Catalog, the system will auto-populate the required raw materials.
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowCreate(false)}>Cancel</button>
              <button className="btn btn-primary" onClick={createWO} disabled={saving || !newWO.productName || !newWO.targetQty}>
                {saving ? <FaSpinner /> : <FaSave />} Create Work Order
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { FaEye, FaEyeSlash, FaLock, FaEnvelope, FaSignInAlt, FaUser } from 'react-icons/fa';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import './LoginPage.css';

const LoginPage = () => {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear messages when user starts typing
    if (error) setError('');
    if (success) setSuccess('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setSuccess('');

    // Basic validation
    if (!formData.email || !formData.password) {
      setError('Please fill in all fields');
      setIsLoading(false);
      return;
    }

    if (!formData.email.includes('@')) {
      setError('Please enter a valid email address');
      setIsLoading(false);
      return;
    }

    // Call the login function from auth context
    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        setSuccess(result.message || 'Login successful! Redirecting...');
        // Navigate immediately to prevent flash
        navigate('/');
      } else {
        setError(result.message || 'Login failed. Please try again.');
      }

    } catch (err) {
      console.error('Login error:', err);
      setError('Login failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <div className="login-content" style={{ width: '100%', maxWidth: '450px', padding: '20px' }}>
      <div className="login-header">
        <img
          src={`${process.env.PUBLIC_URL}/static/media/robridge-logo.png`}
          alt="Robridge Logo"
          className="logo-image"
          onError={(e) => {
            e.target.style.display = 'none';
            e.target.nextSibling.style.display = 'block';
          }}
        />
        <div className="logo-fallback" style={{ display: 'none' }}>
          <div className="-text">ROBRIDGE</div>
        </div>
        <h1 className="login-title">Sign In</h1>
        <p className="login-subtitle">Welcome to RoBridge Community</p>
      </div>

      <form className="login-form" onSubmit={handleSubmit}>
        <div className="form-group">
          <div className="input-container">
            <input
              type="email"
              id="email"
              name="email"
              value={formData.email}
              onChange={handleInputChange}
              className="form-input with-icon"
              placeholder="Gmail"
              required
              disabled={isLoading}
            />
            <div className="input-icon-inside">
              <FaEnvelope />
            </div>
          </div>
        </div>

        <div className="form-group">
          <div className="input-container">
            <input
              type={showPassword ? 'text' : 'password'}
              id="password"
              name="password"
              value={formData.password}
              onChange={handleInputChange}
              className="form-input with-icon"
              placeholder="Password"
              required
              disabled={isLoading}
            />
            <div className="input-icon-inside">
              <FaLock />
            </div>
            <button
              type="button"
              className="password-toggle"
              onClick={togglePasswordVisibility}
              disabled={isLoading}
            >
              {showPassword ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
        </div>

        {error && (
          <div className="error-message">
            {error}
          </div>
        )}

        {success && (
          <div className="success-message">
            {success}
          </div>
        )}

        <div style={{ textAlign: 'right', marginBottom: '15px' }}>
          <Link to="/forgot-password" style={{ color: '#007bff', textDecoration: 'none', fontSize: '0.9rem' }}>
            Forgot Password?
          </Link>
        </div>

        <button
          type="submit"
          className={`login-button ${isLoading ? 'loading' : ''}`}
          disabled={isLoading}
        >
          {isLoading ? (
            <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
              <div className="spinner"></div>
              <span>Signing In...</span>
            </span>
          ) : (
            <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
              <FaSignInAlt />
              <span>Sign In</span>
            </span>
          )}
        </button>
      </form>

      <div className="login-footer" style={{ marginTop: '20px', textAlign: 'center' }}>
        <p style={{ color: '#666' }}>
          Don't have an account?{' '}
          <Link to="/signup" style={{ color: '#007bff', textDecoration: 'none', fontWeight: 'bold' }}>
            Sign Up
          </Link>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import {
  FaBox,
  FaArrowRight,
  FaArrowLeft,
  FaWarehouse,
  FaBarcode,
  FaTag,
  FaPlus,
  FaHistory,
  FaSearch,
  FaFilter,
  FaTimes,
  FaCheck,
  FaExclamationTriangle,
  FaDownload
} from 'react-icons/fa';
import './ProductManagement.css';

import { showToast } from '../components/Toast';
const ProductManagement = () => {
  const [showMovementForm, setShowMovementForm] = useState(false);
  const [movementType, setMovementType] = useState('outbound');
  const [movements, setMovements] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [availableRacks, setAvailableRacks] = useState([]);

  const [formData, setFormData] = useState({
    productName: '',
    productId: '',
    rackId: '',
    quantity: 1,
    notes: ''
  });

  // Load movements and racks on component mount
  useEffect(() => {
    loadMovements();
    loadAvailableRacks();
  }, []);

  const loadAvailableRacks = async () => {
    try {
      const response = await fetch('https://robridge-express-zl9j.onrender.com/api/racks');
      const data = await response.json();

      if (data.success) {
        setAvailableRacks(data.racks || []);
      } else {
        console.error('Failed to load racks:', data.error);
      }
    } catch (error) {
      console.error('Error loading racks:', error);
      setAvailableRacks([]);
    }
  };

  const loadMovements = async () => {
    try {
      setIsLoading(true);
      // In a real app, this would load from API
      const savedMovements = localStorage.getItem('productMovements');
      if (savedMovements) {
        setMovements(JSON.parse(savedMovements));
      } else {
        // Sample data for demonstration
        setMovements([
          {
            id: 1,
            type: 'inbound',
            productName: 'Widget A',
            productId: 'WID-001',
            rackId: 'Rack A-01',
            quantity: 50,
            notes: 'Initial stock',
            timestamp: new Date(Date.now() - 86400000).toISOString(),
            status: 'completed'
          },
          {
            id: 2,
            type: 'outbound',
            productName: 'Gadget B',
            productId: 'GAD-002',
            rackId: 'Rack B-02',
            quantity: 25,
            notes: 'Order fulfillment',
            timestamp: new Date(Date.now() - 172800000).toISOString(),
            status: 'completed'
          }
        ]);
      }
    } catch (error) {
      console.error('Error loading movements:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleInputChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleRecordMovement = async () => {
    // Validation
    if (!formData.productName.trim()) {
      showToast('Product Name is required');
      return;
    }
    if (!formData.productId.trim()) {
      showToast('Product ID is required');
      return;
    }
    if (formData.quantity <= 0) {
      showToast('Quantity must be greater than 0');
      return;
    }

    setIsSaving(true);
    try {
      const newMovement = {
        id: Date.now(),
        type: movementType,
        productName: formData.productName.trim(),
        productId: formData.productId.trim(),
        rackId: formData.rackId.trim() || null,
        quantity: parseInt(formData.quantity),
        notes: formData.notes.trim() || null,
        timestamp: new Date().toISOString(),
        status: 'completed'
      };

      // Update rack quantity if rack ID is provided
      if (formData.rackId) {
        try {
          const rackUpdateResponse = await fetch(`https://robridge-express-zl9j.onrender.com/api/racks/${formData.rackId}/update-quantity`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              type: movementType,
              quantity: parseInt(formData.quantity)
            })
          });

          const rackUpdateData = await rackUpdateResponse.json();

          if (rackUpdateData.success) {
            console.log(`Rack quantity updated: ${rackUpdateData.old_quantity} → ${rackUpdateData.new_quantity}`);
            // Reload available racks to show updated quantities
            loadAvailableRacks();
          } else {
            console.warn('Failed to update rack quantity:', rackUpdateData.error);
          }
        } catch (error) {
          console.error('Error updating rack quantity:', error);
          // Don't block the movement recording if rack update fails
        }
      }

      const updatedMovements = [newMovement, ...movements];
      setMovements(updatedMovements);
      localStorage.setItem('productMovements', JSON.stringify(updatedMovements));

      // Reset form
      setFormData({
        productName: '',
        productId: '',
        rackId: '',
        quantity: 1,
        notes: ''
      });
      setShowMovementForm(false);
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 3000);

    } catch (error) {
      console.error('Error recording movement:', error);
      showToast('Failed to record movement');
    } finally {
      setIsSaving(false);
    }
  };

  const handleCancel = () => {
    setShowMovementForm(false);
    setFormData({
      productName: '',
      productId: '',
      rackId: '',
      quantity: 1,
      notes: ''
    });
  };

  // Export movements to CSV
  const exportToCSV = () => {
    if (movements.length === 0) {
      showToast('No movements to export');
      return;
    }

    // Prepare CSV headers
    const headers = [
      'S.No',
      'Date',
      'Time',
      'Product Name',
      'Product ID',
      'Rack ID',
      'Movement Type',
      'Quantity',
      'Notes'
    ];

    // Prepare data for CSV
    const csvData = movements.map((movement, index) => [
      index + 1,
      new Date(movement.timestamp).toLocaleDateString(),
      new Date(movement.timestamp).toLocaleTimeString(),
      movement.productName,
      movement.productId,
      movement.rackId || 'N/A',
      movement.type.charAt(0).toUpperCase() + movement.type.slice(1),
      movement.quantity,
      movement.notes || 'N/A'
    ]);

    // Combine headers and data
    const csvContent = [headers, ...csvData]
      .map(row => row.map(field => `"${field}"`).join(','))
      .join('\n');

    // Create and download file
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');

    if (link.download !== undefined) {
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);

      // Generate filename with timestamp
      const timestamp = new Date().toISOString().slice(0, 19).replace(/:/g, '-');
      const filename = `product_movements_${timestamp}.csv`;

      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const filteredMovements = movements.filter(movement => {
    const matchesSearch =
      movement.productName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      movement.productId.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (movement.rackId && movement.rackId.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesFilter = filterType === 'all' || movement.type === filterType;

    return matchesSearch && matchesFilter;
  });

  const getMovementIcon = (type) => {
    return type === 'inbound' ? <FaArrowLeft /> : <FaArrowRight />;
  };

  const getMovementColor = (type) => {
    return type === 'inbound' ? '#34A853' : '#EA4335';
  };

  const stats = {
    total: movements.length,
    inbound: movements.filter(m => m.type === 'inbound').length,
    outbound: movements.filter(m => m.type === 'outbound').length,
    totalQuantity: movements.reduce((sum, m) => sum + m.quantity, 0)
  };

  return (
    <div className="product-management">
      <div className="product-header">
        <div className="header-content">
          <FaBox className="header-icon" />
          <h1>Product Management</h1>
          <p>Track product movements and inventory changes</p>
        </div>
        {showSuccess && (
          <div className="success-message">
            <FaCheck />
            Movement recorded successfully!
          </div>
        )}
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon total">
            <FaBox />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.total}</div>
            <div className="stat-label">Total Movements</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon inbound">
            <FaArrowLeft />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.inbound}</div>
            <div className="stat-label">Inbound</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon outbound">
            <FaArrowRight />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.outbound}</div>
            <div className="stat-label">Outbound</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon quantity">
            <FaWarehouse />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.totalQuantity}</div>
            <div className="stat-label">Total Quantity</div>
          </div>
        </div>
      </div>

      <div className="product-content">
        {/* Controls Section */}
        <div className="controls-section">
          <div className="search-filter">
            <div className="search-box">
              <FaSearch className="search-icon" />
              <input
                type="text"
                placeholder="Search products, IDs, or racks..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>

            <div className="filter-box">
              <FaFilter className="filter-icon" />
              <select
                value={filterType}
                onChange={(e) => setFilterType(e.target.value)}
                className="filter-select"
              >
                <option value="all">All Types</option>
                <option value="inbound">Inbound</option>
                <option value="outbound">Outbound</option>
              </select>
            </div>
          </div>

          <div className="header-buttons">
            <button
              className="btn btn-primary"
              onClick={() => setShowMovementForm(true)}
            >
              <FaPlus />
              Record Movement
            </button>

            <button
              className="btn btn-success"
              onClick={exportToCSV}
              disabled={movements.length === 0}
              title="Export movements to CSV"
            >
              <FaDownload />
              Export CSV
            </button>
          </div>
        </div>

        {/* Movement Recording Form */}
        {showMovementForm && (
          <div className="movement-form-overlay">
            <div className="movement-form">
              <div className="form-header">
                <h2>Record Product Movement</h2>
                <button className="close-btn" onClick={handleCancel}>
                  <FaTimes />
                </button>
              </div>

              <div className="form-content">
                {/* Movement Type Selection */}
                <div className="movement-type-section">
                  <label className="form-label">Movement Type</label>
                  <div className="movement-type-buttons">
                    <button
                      className={`movement-type-btn ${movementType === 'outbound' ? 'active' : ''}`}
                      onClick={() => setMovementType('outbound')}
                    >
                      <FaArrowRight />
                      Outbound
                    </button>
                    <button
                      className={`movement-type-btn ${movementType === 'inbound' ? 'active' : ''}`}
                      onClick={() => setMovementType('inbound')}
                    >
                      <FaArrowLeft />
                      Inbound
                    </button>
                  </div>
                </div>

                {/* Form Fields */}
                <div className="form-fields">
                  <div className="form-row">
                    <div className="form-group">
                      <label className="form-label">
                        Product Name <span className="required">*</span>
                      </label>
                      <input
                        type="text"
                        value={formData.productName}
                        onChange={(e) => handleInputChange('productName', e.target.value)}
                        className="form-input"
                        placeholder="Enter product name"
                      />
                    </div>

                    <div className="form-group">
                      <label className="form-label">
                        Product ID <span className="required">*</span>
                      </label>
                      <input
                        type="text"
                        value={formData.productId}
                        onChange={(e) => handleInputChange('productId', e.target.value)}
                        className="form-input"
                        placeholder="Enter product ID"
                      />
                    </div>
                  </div>

                  <div className="form-row">
                    <div className="form-group">
                      <label className="form-label">
                        <FaWarehouse style={{ marginRight: '5px' }} />
                        Rack (Optional)
                      </label>
                      <select
                        value={formData.rackId}
                        onChange={(e) => handleInputChange('rackId', e.target.value)}
                        className="form-input"
                      >
                        <option value="">Select a rack (optional)</option>
                        {availableRacks.map(rack => (
                          <option key={rack.id} value={rack.id}>
                            ID: {rack.id} - {rack.rackName} ({rack.productName})
                          </option>
                        ))}
                      </select>
                      {availableRacks.length === 0 && (
                        <small style={{ color: '#999', fontSize: '12px' }}>
                          No racks available. Create racks in Rack Management first.
                        </small>
                      )}
                    </div>

                    <div className="form-group">
                      <label className="form-label">Quantity</label>
                      <input
                        type="number"
                        value={formData.quantity}
                        onChange={(e) => handleInputChange('quantity', parseInt(e.target.value) || 1)}
                        className="form-input"
                        min="1"
                      />
                    </div>
                  </div>

                  <div className="form-group">
                    <label className="form-label">Notes</label>
                    <textarea
                      value={formData.notes}
                      onChange={(e) => handleInputChange('notes', e.target.value)}
                      className="form-textarea"
                      placeholder="Enter notes (optional)"
                      rows="3"
                    />
                  </div>
                </div>

                {/* Form Actions */}
                <div className="form-actions">
                  <button
                    className="btn btn-primary"
                    onClick={handleRecordMovement}
                    disabled={isSaving}
                  >
                    <FaCheck />
                    {isSaving ? 'Recording...' : 'Record Movement'}
                  </button>

                  <button
                    className="btn btn-secondary"
                    onClick={handleCancel}
                    disabled={isSaving}
                  >
                    <FaTimes />
                    Cancel
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Movements List */}
        <div className="movements-section">
          <div className="section-header">
            <h2>Product Movements ({filteredMovements.length})</h2>
          </div>

          {isLoading ? (
            <div className="loading-state">
              <div className="loading-spinner">
                <div className="spinner"></div>
                <p>Loading movements...</p>
              </div>
            </div>
          ) : filteredMovements.length === 0 ? (
            <div className="empty-state">
              <FaHistory className="empty-icon" />
              <h3>No movements found</h3>
              <p>No movements match your current search or filter criteria.</p>
            </div>
          ) : (
            <div className="movements-list">
              {filteredMovements.map(movement => (
                <div key={movement.id} className="movement-card">
                  <div className="movement-header">
                    <div className="movement-type">
                      <div
                        className="movement-icon"
                        style={{ color: getMovementColor(movement.type) }}
                      >
                        {getMovementIcon(movement.type)}
                      </div>
                      <span className="movement-type-text">
                        {movement.type.charAt(0).toUpperCase() + movement.type.slice(1)}
                      </span>
                    </div>
                    <div className="movement-time">
                      {new Date(movement.timestamp).toLocaleString()}
                    </div>
                  </div>

                  <div className="movement-details">
                    <div className="product-info">
                      <div className="product-name">
                        <FaBox className="product-icon" />
                        {movement.productName}
                      </div>
                      <div className="product-id">
                        <FaBarcode className="barcode-icon" />
                        {movement.productId}
                      </div>
                    </div>

                    <div className="movement-info">
                      {movement.rackId && (
                        <div className="rack-info">
                          <FaWarehouse className="rack-icon" />
                          {movement.rackId}
                        </div>
                      )}
                      <div className="quantity-info">
                        <FaTag className="quantity-icon" />
                        {movement.quantity} units
                      </div>
                    </div>

                    {movement.notes && (
                      <div className="notes-info">
                        <p>{movement.notes}</p>
                      </div>
                    )}
                  </div>

                  <div className="movement-status">
                    <span className={`status-badge ${movement.status}`}>
                      {movement.status}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProductManagement;

import React, { useState, useEffect } from 'react';
import { getServerURL } from '../config/api';
import { useAuth } from '../contexts/AuthContext';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { FaUser, FaEnvelope, FaLock, FaEdit, FaCamera, FaEye, FaEyeSlash, FaCheck, FaTimes } from 'react-icons/fa';
import './Profile.css';

// Helper functions to generate user information based on login data
const formatUserId = (id) => {
  if (!id) return '#USR000';
  return `#USR${String(id).padStart(3, '0')}`;
};

const formatMemberSince = (dateString) => {
  if (!dateString) return 'Member since January 2024';

  const date = new Date(dateString);
  // Check if date is valid
  if (isNaN(date.getTime())) return 'Member since January 2024';

  const options = { month: 'long', year: 'numeric' };
  return `Member since ${date.toLocaleDateString('en-US', options)}`;
};

const Profile = () => {
  const { getUserInfo, getUserRole } = useAuth();
  const { activeWorkspace } = useWorkspace();
  const user = getUserInfo();

  const [userDetails, setUserDetails] = useState({
    name: user?.name || 'User',
    email: user?.email || '',
    id: user?.id ? formatUserId(user.id) : '#USR000',
    memberSince: user?.created_at ? formatMemberSince(user.created_at) : formatMemberSince(null),
    profilePic: null
  });

  const [editMode, setEditMode] = useState({
    name: false,
    email: false
  });

  const [showPasswordModal, setShowPasswordModal] = useState(false);
  const [passwordData, setPasswordData] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });

  const [showPassword, setShowPassword] = useState({
    current: false,
    new: false,
    confirm: false
  });

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  // Hidden file input ref
  const fileInputRef = React.useRef(null);

  // Fetch user profile from backend
  useEffect(() => {
    const fetchUserProfile = async () => {
      try {
        const token = localStorage.getItem('robridge_token');
        const serverURL = getServerURL();

        const response = await fetch(`${serverURL}/api/user/profile`, {
          credentials: 'include',
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });

        const data = await response.json();

        if (data.success) {
          // Load profile pic from local storage
          const savedProfilePic = localStorage.getItem(`profile_pic_${data.user.id}`);

          setUserDetails({
            name: data.user.name || '',
            email: data.user.email || '',
            id: formatUserId(data.user.id),
            memberSince: formatMemberSince(data.user.memberSince),
            profilePic: savedProfilePic || null
          });
        } else {
          setMessage({ type: 'error', text: 'Failed to load profile data' });
        }
      } catch (error) {
        console.error('Error fetching profile:', error);
        setMessage({ type: 'error', text: 'Failed to load profile data' });
      } finally {
        setLoading(false);
      }
    };

    fetchUserProfile();
  }, []);

  const handleInputChange = (field, value) => {
    setUserDetails(prev => ({
      ...prev,
      [field]: value
    }));
  };

  // Handle profile picture selection
  const handleProfilePicSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5000000) { // 5MB limit
        setMessage({ type: 'error', text: 'Image size should be less than 5MB' });
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result;
        setUserDetails(prev => ({ ...prev, profilePic: base64String }));

        // Save to local storage
        const numericId = parseInt(userDetails.id.replace('#USR', '')) || 0;
        localStorage.setItem(`profile_pic_${numericId}`, base64String);

        setMessage({ type: 'success', text: 'Profile picture updated!' });
        setTimeout(() => setMessage({ type: '', text: '' }), 3000);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveProfilePic = () => {
    setUserDetails(prev => ({ ...prev, profilePic: null }));
    const numericId = parseInt(userDetails.id.replace('#USR', '')) || 0;
    localStorage.removeItem(`profile_pic_${numericId}`);
    setMessage({ type: 'success', text: 'Profile picture removed' });
    setTimeout(() => setMessage({ type: '', text: '' }), 3000);
  };

  const toggleEditMode = (field) => {
    if (field === 'password') {
      setShowPasswordModal(true);
      return;
    }
    setEditMode(prev => ({
      ...prev,
      [field]: !prev[field]
    }));
  };

  const handlePasswordChange = (field, value) => {
    setPasswordData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const togglePasswordVisibility = (field) => {
    setShowPassword(prev => ({
      ...prev,
      [field]: !prev[field]
    }));
  };

  const handleSaveChanges = async () => {
    setSaving(true);
    setMessage({ type: '', text: '' });

    try {
      const token = localStorage.getItem('robridge_token');
      const serverURL = getServerURL();

      const response = await fetch(`${serverURL}/api/user/profile`, {
        method: 'PUT',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          name: userDetails.name,
          email: userDetails.email
        })
      });

      const data = await response.json();

      if (data.success) {
        setMessage({ type: 'success', text: 'Profile updated successfully!' });
        setEditMode({ name: false, email: false });

        setUserDetails(prev => ({
          ...prev,
          name: data.user.name,
          email: data.user.email
        }));
      } else {
        setMessage({ type: 'error', text: data.error || 'Failed to update profile' });
      }

      setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    } catch (error) {
      console.error('Error updating profile:', error);
      setMessage({ type: 'error', text: 'Failed to update profile. Please try again.' });
    } finally {
      setSaving(false);
    }
  };

  const handleChangePassword = async () => {
    if (!passwordData.currentPassword || !passwordData.newPassword || !passwordData.confirmPassword) {
      setMessage({ type: 'error', text: 'Please fill in all password fields.' });
      return;
    }

    if (passwordData.newPassword !== passwordData.confirmPassword) {
      setMessage({ type: 'error', text: 'New passwords do not match.' });
      return;
    }

    if (passwordData.newPassword.length < 6) {
      setMessage({ type: 'error', text: 'Password must be at least 6 characters long.' });
      return;
    }

    setSaving(true);
    setMessage({ type: '', text: '' });

    try {
      const token = localStorage.getItem('robridge_token');
      const serverURL = getServerURL();

      const response = await fetch(`${serverURL}/api/user/password`, {
        method: 'PUT',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          currentPassword: passwordData.currentPassword,
          newPassword: passwordData.newPassword
        })
      });

      const data = await response.json();

      if (data.success) {
        setMessage({ type: 'success', text: 'Password changed successfully!' });
        setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
        setShowPassword({ current: false, new: false, confirm: false });
        setShowPasswordModal(false);
      } else {
        setMessage({ type: 'error', text: data.error || 'Failed to change password' });
      }

      setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    } catch (error) {
      console.error('Error changing password:', error);
      setMessage({ type: 'error', text: 'Failed to change password. Please try again.' });
    } finally {
      setSaving(false);
    }
  };

  const closePasswordModal = () => {
    setShowPasswordModal(false);
    setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
    setShowPassword({ current: false, new: false, confirm: false });
  };

  return (
    <div className="profile-page">
      <div className="page-header ims-page-header">
        <div className="ims-header-left">
          <h1>Workspace Profile</h1>
          <p>Manage your account and workspace capacity details</p>
        </div>
        <div className="ims-header-right">
          <button className="btn btn-secondary"><FaLock /> Security</button>
        </div>
      </div>

      {message.text && (
        <div className={`message-banner ${message.type}`}>
          {message.type === 'success' && <FaCheck />}
          {message.text}
        </div>
      )}

      <div className="profile-layout">
        {/* Left Side - Avatar Card */}
        <div className="avatar-card">
          {loading ? (
            <div className="loading-spinner-container" style={{ padding: '40px', display: 'flex', justifyContent: 'center' }}>
              <div className="spinner-small" style={{
                width: '30px',
                height: '30px',
                border: '3px solid #E3821E',
                borderTopColor: 'transparent',
                borderRadius: '50%',
                animation: 'spin 1s linear infinite'
              }}></div>
            </div>
          ) : (
            <>
              <div className="avatar-container">
                <div className="avatar-circle">
                  {userDetails.profilePic ? (
                    <img src={userDetails.profilePic} alt="Profile" className="profile-pic-img" />
                  ) : (
                    <FaUser />
                  )}
                </div>
                <button
                  className="camera-button"
                  title="Change profile picture"
                  onClick={() => fileInputRef.current.click()}
                >
                  <FaCamera />
                </button>
                <input
                  type="file"
                  ref={fileInputRef}
                  style={{ display: 'none' }}
                  accept="image/*"
                  onChange={handleProfilePicSelect}
                />
              </div>
              {userDetails.profilePic && (
                <button
                  className="remove-pic-btn"
                  onClick={handleRemoveProfilePic}
                >
                  Remove Picture
                </button>
              )}
              <div className="user-info-section">
                <h2>{userDetails.name}</h2>
                <div style={{ display: 'flex', gap: '8px', justifyContent: 'center', margin: '8px 0'}}>
                   <span className="user-id-badge">{userDetails.id}</span>
                   <span className="user-id-badge" style={{ background: '#e3f2fd', color: '#1565c0' }}>{activeWorkspace?.role?.toUpperCase() || 'MEMBER'}</span>
                </div>
                <p className="member-date" style={{ color: '#666', fontSize: '13px' }}>{userDetails.memberSince}</p>
                
                <div className="workspace-card" style={{ marginTop: '20px', padding: '15px', background: '#F8F9FA', borderRadius: '12px', border: '1px solid #EAEAEA', textAlign: 'left' }}>
                  <h4 style={{ margin: '0 0 10px', fontSize: '14px', color: '#333' }}>Current Workspace</h4>
                  <div style={{ fontWeight: '600', fontSize: '16px', color: '#fa1804' }}>{activeWorkspace?.name || 'No Workspace'}</div>
                  <div style={{ marginTop: '15px' }}>
                     <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', color: '#666', marginBottom: '5px' }}>
                        <span>SKU Limit</span>
                        <span>{activeWorkspace?.max_skus ? `Max ${activeWorkspace.max_skus}` : 'Unlimited'}</span>
                     </div>
                     <div style={{ height: '6px', background: '#e0e0e0', borderRadius: '3px', overflow: 'hidden' }}>
                        <div style={{ height: '100%', width: '12.5%', background: '#4CAF50' }}></div>
                     </div>
                  </div>
                </div>
              </div>
            </>
          )}
        </div>

        {/* Right Side - Account Information */}
        <div className="account-card">
          <h3>Account Information</h3>

          {loading ? (
            <div className="loading-spinner-container" style={{ padding: '60px', display: 'flex', justifyContent: 'center', alignItems: 'center', flexDirection: 'column', gap: '15px' }}>
              <div className="spinner-small" style={{
                width: '30px',
                height: '30px',
                border: '3px solid #E3821E',
                borderTopColor: 'transparent',
                borderRadius: '50%',
                animation: 'spin 1s linear infinite'
              }}></div>
              <span style={{ color: '#666' }}>Loading account details...</span>
            </div>
          ) : (
            <>
              {/* Name Field */}
              <div className="form-field">
                <label>
                  <FaUser />
                  NAME
                </label>
                <div className="input-wrapper">
                  <input
                    type="text"
                    value={userDetails.name}
                    onChange={(e) => handleInputChange('name', e.target.value)}
                    readOnly={!editMode.name}
                    className={editMode.name ? 'editing' : ''}
                  />
                  <FaEdit
                    className="edit-btn"
                    onClick={() => toggleEditMode('name')}
                    title={editMode.name ? 'Lock field' : 'Edit field'}
                  />
                </div>
              </div>

              {/* Email Field */}
              <div className="form-field">
                <label>
                  <FaEnvelope />
                  EMAIL
                </label>
                <div className="input-wrapper">
                  <input
                    type="email"
                    value={userDetails.email}
                    onChange={(e) => handleInputChange('email', e.target.value)}
                    readOnly={!editMode.email}
                    className={editMode.email ? 'editing' : ''}
                  />
                  <FaEdit
                    className="edit-btn"
                    onClick={() => toggleEditMode('email')}
                    title={editMode.email ? 'Lock field' : 'Edit field'}
                  />
                </div>
              </div>

              {/* Password Field */}
              <div className="form-field">
                <label>
                  <FaLock />
                  PASSWORD
                </label>
                <div className="input-wrapper">
                  <input
                    type="password"
                    value="••••••••"
                    readOnly
                    className=""
                  />
                  <FaEdit
                    className="edit-btn"
                    onClick={() => toggleEditMode('password')}
                    title="Change password"
                  />
                </div>
              </div>

              <button
                className="save-btn btn btn-primary"
                onClick={handleSaveChanges}
                disabled={saving}
              >
                {saving ? 'Saving...' : 'Save Changes'}
              </button>
            </>
          )}
        </div>
      </div>

      {/* Password Change Modal */}
      {showPasswordModal && (
        <div className="modal-overlay" onClick={closePasswordModal}>
          <div className="password-modal" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={closePasswordModal}>
              <FaTimes />
            </button>
            <h2>Change Password</h2>
            <p className="modal-subtitle">Enter your current password to set a new one</p>

            <div className="modal-form">
              <div className="form-field">
                <label>
                  <FaLock />
                  CURRENT PASSWORD
                </label>
                <div className="input-wrapper">
                  <input
                    type={showPassword.current ? 'text' : 'password'}
                    value={passwordData.currentPassword}
                    onChange={(e) => handlePasswordChange('currentPassword', e.target.value)}
                    placeholder="Enter current password"
                  />
                  {showPassword.current ? (
                    <FaEyeSlash
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('current')}
                    />
                  ) : (
                    <FaEye
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('current')}
                    />
                  )}
                </div>
              </div>

              <div className="form-field">
                <label>
                  <FaLock />
                  NEW PASSWORD
                </label>
                <div className="input-wrapper">
                  <input
                    type={showPassword.new ? 'text' : 'password'}
                    value={passwordData.newPassword}
                    onChange={(e) => handlePasswordChange('newPassword', e.target.value)}
                    placeholder="Enter new password"
                  />
                  {showPassword.new ? (
                    <FaEyeSlash
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('new')}
                    />
                  ) : (
                    <FaEye
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('new')}
                    />
                  )}
                </div>
              </div>

              <div className="form-field">
                <label>
                  <FaLock />
                  CONFIRM NEW PASSWORD
                </label>
                <div className="input-wrapper">
                  <input
                    type={showPassword.confirm ? 'text' : 'password'}
                    value={passwordData.confirmPassword}
                    onChange={(e) => handlePasswordChange('confirmPassword', e.target.value)}
                    placeholder="Confirm new password"
                  />
                  {showPassword.confirm ? (
                    <FaEyeSlash
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('confirm')}
                    />
                  ) : (
                    <FaEye
                      className="edit-btn"
                      onClick={() => togglePasswordVisibility('confirm')}
                    />
                  )}
                </div>
              </div>

              <div className="modal-actions">
                <button
                  className="btn btn-secondary"
                  onClick={closePasswordModal}
                >
                  Cancel
                </button>
                <button
                  className="save-btn btn btn-primary"
                  onClick={handleChangePassword}
                  disabled={saving}
                >
                  {saving ? 'Changing...' : 'Change Password'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Profile;

import React, { useState, useEffect } from 'react';
import {
  FaWarehouse,
  FaPlus,
  FaEdit,
  FaTrash,
  FaSave,
  FaTimes,
  FaSearch,
  FaFilter,
  FaBox,
  FaBarcode,
  FaTag
} from 'react-icons/fa';
import './RackManagement.css';

import { showToast } from '../components/Toast';
const RackManagement = () => {
  const [racks, setRacks] = useState([]);

  const [showAddForm, setShowAddForm] = useState(false);
  const [editingRack, setEditingRack] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [isSaving, setIsSaving] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [stats, setStats] = useState({
    totalRacks: 0,
    activeRacks: 0,
    inactiveRacks: 0,
    uniqueProducts: 0
  });
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState('checking');
  const [isInitializingDB, setIsInitializingDB] = useState(false);

  const [formData, setFormData] = useState({
    rackName: '',
    productName: '',
    productId: '',
    quantity: 0
  });

  // Load racks and stats on component mount
  useEffect(() => {
    checkConnection();
    loadRacks();
    loadStats();
  }, []);

  const checkConnection = async () => {
    try {
      const response = await fetch('https://robridge-express-zl9j.onrender.com/api/health');
      if (response.ok) {
        setConnectionStatus('connected');
      } else {
        setConnectionStatus('error');
      }
    } catch (error) {
      console.error('Connection check failed:', error);
      setConnectionStatus('error');
    }
  };

  // Load racks when search or filter changes
  useEffect(() => {
    loadRacks();
  }, [searchTerm, filterStatus]);

  const loadRacks = async () => {
    try {
      setIsLoading(true);
      const params = new URLSearchParams();
      if (searchTerm) params.append('search', searchTerm);
      if (filterStatus !== 'all') params.append('status', filterStatus);

      console.log('Loading racks with params:', params.toString());
      const serverURL = 'https://robridge-express-zl9j.onrender.com';
      const response = await fetch(`${serverURL}/api/racks?${params.toString()}`);
      console.log('Racks response status:', response.status);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      let data;
      try {
        data = await response.json();
        console.log('Racks response data:', data);
      } catch (jsonError) {
        console.error('JSON parsing error:', jsonError);
        const textResponse = await response.text();
        console.error('Response text:', textResponse);
        throw new Error(`Invalid JSON response. Server might not be running on port 3001. Response: ${textResponse.substring(0, 100)}...`);
      }

      if (data.success) {
        setRacks(data.racks);
      } else {
        console.error('Failed to load racks:', data.error);

        // Check if it's a database table error
        if (data.error && data.error.includes('no such table: racks')) {
          console.log('Database table not found, suggesting initialization...');
          // Don't show alert, just log the error
          // The user can click the Initialize Database button
        } else {
          showToast('Failed to load racks: ' + data.error);
        }
      }
    } catch (error) {
      console.error('Error loading racks:', error);
      console.error('Error details:', {
        message: error.message,
        stack: error.stack,
        name: error.name
      });

      // Don't show alert for connection errors, just log them
      if (!error.message.includes('Failed to fetch')) {
        showToast('Error loading racks: ' + error.message + '\n\nPlease check if the backend server is running.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const loadStats = async () => {
    try {
      console.log('Loading stats...');
      const response = await fetch('https://robridge-express-zl9j.onrender.com/api/racks/stats');
      console.log('Stats response status:', response.status);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      let data;
      try {
        data = await response.json();
        console.log('Stats response data:', data);
      } catch (jsonError) {
        console.error('JSON parsing error for stats:', jsonError);
        const textResponse = await response.text();
        console.error('Stats response text:', textResponse);
        throw new Error(`Invalid JSON response for stats. Server might not be running on port 3001. Response: ${textResponse.substring(0, 100)}...`);
      }

      if (data.success) {
        setStats(data.stats);
      } else {
        console.error('Failed to load stats:', data.error);
      }
    } catch (error) {
      console.error('Error loading stats:', error);
      console.error('Error details:', {
        message: error.message,
        stack: error.stack,
        name: error.name
      });
    }
  };

  const handleInputChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleAddRack = async () => {
    if (!formData.rackName || !formData.productName || !formData.productId) {
      showToast('Please fill in all required fields');
      return;
    }

    if (formData.quantity < 0) {
      showToast('Quantity cannot be negative');
      return;
    }

    setIsSaving(true);

    try {
      const response = await fetch('https://robridge-express-zl9j.onrender.com/api/racks', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (data.success) {
        setFormData({ rackName: '', productName: '', productId: '', quantity: 0 });
        setShowAddForm(false);
        loadRacks(); // Reload racks
        loadStats(); // Reload stats
        showToast('Rack added successfully!');
      } else {
        showToast('Failed to add rack: ' + data.error);
      }
    } catch (error) {
      console.error('Error adding rack:', error);
      showToast('Error adding rack: ' + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  const handleEditRack = (rack) => {
    setEditingRack(rack);
    setFormData({
      rackName: rack.rackName,
      productName: rack.productName,
      productId: rack.productId,
      quantity: rack.quantity || 0
    });
  };

  const handleUpdateRack = async () => {
    if (!formData.rackName || !formData.productName || !formData.productId) {
      showToast('Please fill in all fields');
      return;
    }

    setIsSaving(true);

    try {
      const response = await fetch(`https://robridge-express-zl9j.onrender.com/api/racks/${editingRack.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (data.success) {
        setEditingRack(null);
        setFormData({ rackName: '', productName: '', productId: '' });
        loadRacks(); // Reload racks
        loadStats(); // Reload stats
        showToast('Rack updated successfully!');
      } else {
        showToast('Failed to update rack: ' + data.error);
      }
    } catch (error) {
      console.error('Error updating rack:', error);
      showToast('Error updating rack: ' + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteRack = async (rackId) => {
    if (window.confirm('Are you sure you want to delete this rack?')) {
      try {
        const response = await fetch(`https://robridge-express-zl9j.onrender.com/api/racks/${rackId}`, {
          method: 'DELETE'
        });

        const data = await response.json();

        if (data.success) {
          loadRacks(); // Reload racks
          loadStats(); // Reload stats
          showToast('Rack deleted successfully!');
        } else {
          showToast('Failed to delete rack: ' + data.error);
        }
      } catch (error) {
        console.error('Error deleting rack:', error);
        showToast('Error deleting rack: ' + error.message);
      }
    }
  };

  const handleCancel = () => {
    setShowAddForm(false);
    setEditingRack(null);
    setFormData({ rackName: '', productName: '', productId: '' });
  };

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!searchQuery.trim()) {
      showToast('Please enter a rack ID or rack name to search');
      return;
    }

    setIsSearching(true);
    try {
      const response = await fetch(`https://robridge-express-zl9j.onrender.com/api/racks/search?q=${encodeURIComponent(searchQuery.trim())}`);
      const data = await response.json();

      if (data.success) {
        setSearchResults(data.racks);
        setShowSearchResults(true);
        if (data.count === 0) {
          showToast('No racks found matching your search criteria');
        }
      } else {
        showToast('Search failed: ' + data.error);
      }
    } catch (error) {
      console.error('Error searching racks:', error);
      showToast('Error searching racks: ' + error.message);
    } finally {
      setIsSearching(false);
    }
  };

  const clearSearch = () => {
    setSearchQuery('');
    setSearchResults([]);
    setShowSearchResults(false);
  };

  const initializeDatabase = async () => {
    setIsInitializingDB(true);
    try {
      console.log('Initializing database...');
      const response = await fetch('https://robridge-express-zl9j.onrender.com/api/init-db', {
        method: 'POST'
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log('Database initialization response:', data);

      if (data.success) {
        showToast('Database initialized successfully! The page will now load properly.');
        // Reload the page to ensure everything works
        window.location.reload();
      } else {
        showToast('Failed to initialize database: ' + data.error);
      }
    } catch (error) {
      console.error('Error initializing database:', error);
      showToast('Error initializing database: ' + error.message + '\n\nPlease make sure both servers are running.');
    } finally {
      setIsInitializingDB(false);
    }
  };

  const statsData = [
    { label: 'Total Racks', value: stats.totalRacks, icon: FaWarehouse, color: '#E3821E' },
    { label: 'Active Racks', value: stats.activeRacks, icon: FaBox, color: '#34A853' },
    { label: 'Inactive Racks', value: stats.inactiveRacks, icon: FaBox, color: '#EA4335' },
    { label: 'Products', value: stats.uniqueProducts, icon: FaTag, color: '#007ACC' }
  ];

  return (
    <div className="rack-management">
      <div className="rack-header">
        <h1>Rack Management</h1>
        <p>Manage warehouse racks, products, and inventory locations</p>
        <div className="connection-status">
          <div className={`status-indicator ${connectionStatus}`}>
            {connectionStatus === 'checking' && '🔄 Checking connection...'}
            {connectionStatus === 'connected' && '✅ Connected to backend'}
            {connectionStatus === 'error' && '❌ Backend connection failed'}
          </div>
          {connectionStatus === 'connected' && (
            <div className="db-init-section">
              <button
                className="btn btn-secondary init-db-btn"
                onClick={initializeDatabase}
                disabled={isInitializingDB}
              >
                {isInitializingDB ? '🔄 Initializing...' : '🗄️ Initialize Database'}
              </button>
              <p className="db-init-help">
                If you see "no such table: racks" error, click this button to set up the database.
              </p>
            </div>
          )}
        </div>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        {statsData.map((stat, index) => {
          const Icon = stat.icon;
          return (
            <div key={index} className="stat-card" style={{ borderLeftColor: stat.color }}>
              <div className="stat-icon" style={{ color: stat.color }}>
                <Icon />
              </div>
              <div className="stat-content">
                <div className="stat-value">{stat.value}</div>
                <div className="stat-label">{stat.label}</div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="rack-content">
        {/* Quick Search Section */}
        <div className="quick-search-section">
          <div className="search-header">
            <h3>Quick Search</h3>
            <p>Search by Rack ID or Rack Name to find product information</p>
          </div>

          <form onSubmit={handleSearch} className="quick-search-form">
            <div className="search-input-group">
              <FaSearch className="search-icon" />
              <input
                type="text"
                placeholder="Enter Rack ID or Rack Name..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="search-input"
                disabled={isSearching}
              />
              <button
                type="submit"
                className="btn btn-primary search-btn"
                disabled={isSearching || !searchQuery.trim()}
              >
                {isSearching ? 'Searching...' : 'Search'}
              </button>
              {showSearchResults && (
                <button
                  type="button"
                  className="btn btn-secondary clear-btn"
                  onClick={clearSearch}
                >
                  <FaTimes />
                  Clear
                </button>
              )}
            </div>
          </form>
        </div>

        {/* Search Results */}
        {showSearchResults && (
          <div className="search-results-section">
            <div className="search-results-header">
              <h3>Search Results ({searchResults.length})</h3>
              <p>Found {searchResults.length} rack(s) matching "{searchQuery}"</p>
            </div>

            {searchResults.length > 0 ? (
              <div className="search-results-grid">
                {searchResults.map(rack => (
                  <div key={rack.id} className="search-result-card">
                    <div className="result-header">
                      <div className="rack-info">
                        <FaWarehouse className="rack-icon" />
                        <div>
                          <h4>{rack.rackName}</h4>
                          <span className="rack-id">ID: {rack.id}</span>
                        </div>
                      </div>
                      <span className={`status-badge ${rack.status}`}>
                        {rack.status}
                      </span>
                    </div>

                    <div className="product-info">
                      <div className="product-detail">
                        <FaBox className="product-icon" />
                        <div>
                          <label>Product Name:</label>
                          <span>{rack.productName}</span>
                        </div>
                      </div>
                      <div className="product-detail">
                        <FaTag className="product-id-icon" />
                        <div>
                          <label>Product ID:</label>
                          <span className="product-id-text">{rack.productId}</span>
                        </div>
                      </div>
                    </div>

                    <div className="result-footer">
                      <div className="date-info">
                        <span>Created: {new Date(rack.createdAt).toLocaleDateString()}</span>
                      </div>
                      <div className="result-actions">
                        <button
                          className="btn-icon edit-btn"
                          onClick={() => handleEditRack(rack)}
                          title="Edit Rack"
                        >
                          <FaEdit />
                        </button>
                        <button
                          className="btn-icon delete-btn"
                          onClick={() => handleDeleteRack(rack.id)}
                          title="Delete Rack"
                        >
                          <FaTrash />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="no-results">
                <FaSearch className="no-results-icon" />
                <h4>No results found</h4>
                <p>No racks match your search criteria. Try a different search term.</p>
              </div>
            )}
          </div>
        )}

        {/* Controls Section */}
        <div className="controls-section">
          <div className="search-filter">
            <div className="search-box">
              <FaSearch className="search-icon" />
              <input
                type="text"
                placeholder="Search racks, products, or IDs..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>

            <div className="filter-box">
              <FaFilter className="filter-icon" />
              <select
                value={filterStatus}
                onChange={(e) => setFilterStatus(e.target.value)}
                className="filter-select"
              >
                <option value="all">All Status</option>
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
              </select>
            </div>
          </div>

          <button
            className="btn btn-primary"
            onClick={() => setShowAddForm(true)}
          >
            <FaPlus />
            Add New Rack
          </button>
        </div>

        {/* Add/Edit Form */}
        {(showAddForm || editingRack) && (
          <div className="form-section">
            <div className="form-header">
              <h3>{editingRack ? 'Edit Rack' : 'Add New Rack'}</h3>
              <button className="close-btn" onClick={handleCancel}>
                <FaTimes />
              </button>
            </div>

            <div className="form-content">
              <div className="form-row">
                <div className="form-group">
                  <label className="label">Rack Name *</label>
                  <input
                    type="text"
                    value={formData.rackName}
                    onChange={(e) => handleInputChange('rackName', e.target.value)}
                    className="input"
                    placeholder="e.g., Rack A-01"
