                        <FaTrash />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RackManagement;

import React, { useState, useEffect } from 'react';
import {
  FaWarehouse,
  FaMapMarkerAlt,
  FaCheckCircle,
  FaTimesCircle,
  FaExclamationTriangle,
  FaSync,
  FaSearch,
  FaFilter,
  FaDownload,
  FaPlus,
  FaEdit,
  FaTrash,
  FaInfoCircle
} from 'react-icons/fa';
import './RackStatus.css';

import { showToast } from '../components/Toast';
const RackStatus = () => {
  const [racks, setRacks] = useState([]);

  const [filterStatus, setFilterStatus] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRack, setSelectedRack] = useState(null);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [stats, setStats] = useState({
    total: 0,
    occupied: 0,
    free: 0,
    maintenance: 0,
    utilization: 0
  });

  // Load rack status data from database
  ////
  const loadRackStatus = async () => {
    try {
      setIsLoading(true);
      const serverURL = 'https://robridge-express-zl9j.onrender.com';
      const response = await fetch(`${serverURL}/api/rack-status`);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      if (data.success) {
        setRacks(data.racks);
        setStats(data.stats);
      } else {
        console.error('Failed to load rack status:', data.error);
        showToast('Failed to load rack status: ' + data.error);
      }
    } catch (error) {
      console.error('Error loading rack status:', error);
      showToast('Error loading rack status: ' + error.message);
    } finally {
      setIsLoading(false);
    }
  };

  // Load data on component mount
  useEffect(() => {
    loadRackStatus();
  }, []);

  // Simulate real-time updates (update environmental data)
  useEffect(() => {
    const interval = setInterval(() => {
      setRacks(prevRacks =>
        prevRacks.map(rack => ({
          ...rack,
          lastUpdated: new Date().toLocaleString(),
          temperature: (parseFloat(rack.temperature || 20) + (Math.random() - 0.5) * 0.5).toFixed(1),
          humidity: Math.max(30, Math.min(60, parseFloat(rack.humidity || 45) + (Math.random() - 0.5) * 2))
        }))
      );
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  const getStatusIcon = (status) => {
    switch (status) {
      case 'occupied':
        return <FaCheckCircle className="status-icon occupied" />;
      case 'free':
        return <FaTimesCircle className="status-icon free" />;
      case 'maintenance':
        return <FaExclamationTriangle className="status-icon maintenance" />;
      default:
        return <FaInfoCircle className="status-icon" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'occupied':
        return '#EA4335';
      case 'free':
        return '#34A853';
      case 'maintenance':
        return '#FBBC05';
      default:
        return '#9AA0A6';
    }
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'occupied':
        return 'Occupied';
      case 'free':
        return 'Free';
      case 'maintenance':
        return 'Maintenance';
      default:
        return 'Unknown';
    }
  };

  const filteredRacks = racks.filter(rack => {
    const matchesStatus = filterStatus === 'all' || rack.status === filterStatus;
    const matchesSearch = rack.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      rack.location.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (rack.occupiedBy && rack.occupiedBy.toLowerCase().includes(searchTerm.toLowerCase()));
    return matchesStatus && matchesSearch;
  });

  const refreshData = () => {
    setIsRefreshing(true);
    loadRackStatus().finally(() => {
      setIsRefreshing(false);
    });
  };

  const exportData = () => {
    const csvContent = [
      ['Rack Name', 'Location', 'Status', 'Occupied By', 'Capacity', 'Current Load', 'Temperature', 'Humidity', 'Last Updated'],
      ...filteredRacks.map(rack => [
        rack.name,
        rack.location,
        getStatusText(rack.status),
        rack.occupiedBy || 'N/A',
        rack.capacity,
        rack.currentLoad,
        rack.temperature,
        rack.humidity,
        rack.lastUpdated
      ])
    ].map(row => row.join(',')).join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `rack-status-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  // Stats are now loaded from the database

  return (
    <div className="rack-status-container">
      <div className="rack-status-header">
        <div className="header-content">
          <h1>Rack Status</h1>
          <p>Monitor warehouse rack occupancy and status in real-time</p>
        </div>
        <div className="header-actions">
          <button className="btn btn-secondary" onClick={refreshData} disabled={isRefreshing}>
            <FaSync className={isRefreshing ? 'spinning' : ''} />
            {isRefreshing ? 'Refreshing...' : 'Refresh'}
          </button>
          <button className="btn btn-success" onClick={exportData}>
            <FaDownload />
            Export CSV
          </button>
        </div>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon total">
            <FaWarehouse />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.total}</div>
            <div className="stat-label">Total Racks</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon occupied">
            <FaCheckCircle />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.occupied}</div>
            <div className="stat-label">Occupied</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon free">
            <FaTimesCircle />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.free}</div>
            <div className="stat-label">Free</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon maintenance">
            <FaExclamationTriangle />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.maintenance}</div>
            <div className="stat-label">Maintenance</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon utilization">
            <FaInfoCircle />
          </div>
          <div className="stat-content">
            <div className="stat-value">{stats.utilization}%</div>
            <div className="stat-label">Utilization</div>
          </div>
        </div>
      </div>

      <div className="controls-section">
        <div className="search-controls">
          <div className="search-box">
            <FaSearch className="search-icon" />
            <input
              type="text"
              placeholder="Search racks by name, location, or robot..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="filter-controls">
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="filter-select"
            >
              <option value="all">All Status</option>
              <option value="occupied">Occupied</option>
              <option value="free">Free</option>
              <option value="maintenance">Maintenance</option>
            </select>
          </div>
        </div>
      </div>

      <div className="racks-grid">
        {isLoading ? (
          <div className="loading-state">
            <div className="loading-spinner">
              <div className="spinner"></div>
              <p>Loading rack status...</p>
            </div>
          </div>
        ) : filteredRacks.length === 0 ? (
          <div className="empty-state">
            <FaWarehouse className="empty-icon" />
            <h3>No racks found</h3>
            <p>No racks match your current search or filter criteria.</p>
          </div>
        ) : (
          filteredRacks.map(rack => (
            <div
              key={rack.id}
              className={`rack-card ${rack.status} ${selectedRack?.id === rack.id ? 'selected' : ''}`}
              onClick={() => setSelectedRack(rack)}
            >
              <div className="rack-header">
                <div className="rack-name">{rack.name}</div>
                <div className="rack-status">
                  {getStatusIcon(rack.status)}
                  <span style={{ color: getStatusColor(rack.status) }}>
                    {getStatusText(rack.status)}
                  </span>
                </div>
              </div>

              <div className="rack-details">
                <div className="detail-item">
                  <FaMapMarkerAlt className="detail-icon" />
                  <span className="detail-label">Location:</span>
                  <span className="detail-value">{rack.location}</span>
                </div>

                {rack.occupiedBy && (
                  <div className="detail-item">
                    <FaWarehouse className="detail-icon" />
                    <span className="detail-label">Occupied by:</span>
                    <span className="detail-value">{rack.occupiedBy}</span>
                  </div>
                )}

                <div className="detail-item">
                  <span className="detail-label">Capacity:</span>
                  <span className="detail-value">{rack.currentLoad}% / {rack.capacity}%</span>
                </div>

                <div className="detail-item">
                  <span className="detail-label">Temperature:</span>
                  <span className="detail-value">{parseFloat(rack.temperature || 20).toFixed(1)}°C</span>
                </div>

                <div className="detail-item">
                  <span className="detail-label">Humidity:</span>
                  <span className="detail-value">{Math.round(parseFloat(rack.humidity || 45))}%</span>
                </div>
              </div>

              <div className="rack-footer">
                <div className="last-updated">
                  Last updated: {rack.lastUpdated}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {selectedRack && (
        <div className="rack-modal-overlay" onClick={() => setSelectedRack(null)}>
          <div className="rack-modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{selectedRack.name} - Details</h2>
              <button
                className="close-btn"
                onClick={() => setSelectedRack(null)}
              >
                ×
              </button>
            </div>
            <div className="modal-content">
              <div className="modal-section">
                <h3>Status Information</h3>
                <div className="modal-details">
                  <div className="modal-detail-item">
                    <span className="modal-label">Status:</span>
                    <span
                      className="modal-value"
                      style={{ color: getStatusColor(selectedRack.status) }}
                    >
                      {getStatusText(selectedRack.status)}
                    </span>
                  </div>
                  <div className="modal-detail-item">
                    <span className="modal-label">Location:</span>
                    <span className="modal-value">{selectedRack.location}</span>
                  </div>
                  <div className="modal-detail-item">
                    <span className="modal-label">Coordinates:</span>
                    <span className="modal-value">X: {selectedRack.coordinates.x}, Y: {selectedRack.coordinates.y}</span>
                  </div>
                  {selectedRack.occupiedBy && (
                    <div className="modal-detail-item">
                      <span className="modal-label">Occupied by:</span>
                      <span className="modal-value">{selectedRack.occupiedBy}</span>
                    </div>
                  )}
                </div>
              </div>

              <div className="modal-section">
                <h3>Environmental Data</h3>
                <div className="modal-details">
                  <div className="modal-detail-item">
                    <span className="modal-label">Temperature:</span>
                    <span className="modal-value">{parseFloat(selectedRack.temperature || 20).toFixed(1)}°C</span>
                  </div>
                  <div className="modal-detail-item">
                    <span className="modal-label">Humidity:</span>
                    <span className="modal-value">{Math.round(parseFloat(selectedRack.humidity || 45))}%</span>
                  </div>
                  <div className="modal-detail-item">
                    <span className="modal-label">Capacity:</span>
                    <span className="modal-value">{selectedRack.currentLoad}% / {selectedRack.capacity}%</span>
                  </div>
                </div>
              </div>

              <div className="modal-section">
                <h3>Last Updated</h3>
                <div className="modal-details">
                  <div className="modal-detail-item">
                    <span className="modal-value">{selectedRack.lastUpdated}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RackStatus;

import React, { useState } from 'react';
import { FaLock, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';
import { useSearchParams, useNavigate, Link } from 'react-router-dom';
import './LoginPage.css';

const ResetPassword = () => {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const token = searchParams.get('token');

    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (newPassword !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        if (newPassword.length < 6) {
            setError('Password must be at least 6 characters');
            return;
        }

        setIsLoading(true);
        setError('');
        setMessage('');

        try {
            // Use the backend API URL
            const apiUrl = process.env.REACT_APP_API_URL || 'https://robridge-express-zl9j.onrender.com';

            const response = await fetch(`${apiUrl}/api/auth/reset-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ token, newPassword }),
            });

            const data = await response.json();

            if (data.success) {
                setMessage('Password reset successful! Redirecting to login...');
                setTimeout(() => {
                    navigate('/login');
                }, 3000);
            } else {
                setError(data.error || 'Failed to reset password');
            }
        } catch (err) {
            console.error('Reset error:', err);
            setError('An error occurred. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    if (!token) {
        return (
            <div className="login-content" style={{ padding: '20px', textAlign: 'center' }}>
                <FaExclamationCircle size={50} color="#dc3545" />
                <h2>Invalid Link</h2>
                <p>This password reset link is invalid or missing the token.</p>
                <Link to="/login" className="login-button">Back to Login</Link>
            </div>
        );
    }

    return (
        <div className="login-content" style={{ width: '100%', maxWidth: '450px', padding: '20px' }}>
            <div className="login-header">
                <h1 className="login-title">New Password</h1>
                <p className="login-subtitle">Enter your new secure password</p>
            </div>

            <form className="login-form" onSubmit={handleSubmit}>
                <div className="form-group">
                    <div className="input-container">
                        <input
                            type="password"
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            className="form-input with-icon"
                            placeholder="New Password"
                            required
                        />
                        <div className="input-icon-inside"><FaLock /></div>
                    </div>
                </div>

                <div className="form-group">
                    <div className="input-container">
                        <input
                            type="password"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            className="form-input with-icon"
                            placeholder="Confirm New Password"
                            required
                        />
                        <div className="input-icon-inside"><FaLock /></div>
                    </div>
                </div>

                {error && <div className="error-message">{error}</div>}
                {message && <div className="success-message">{message}</div>}

                <button
                    type="submit"
                    className="login-button"
                    disabled={isLoading || !!message}
                >
                    {isLoading ? 'Resetting...' : 'Reset Password'}
                </button>
            </form>
        </div>
    );
};

export default ResetPassword;

import React, { useState, useEffect } from 'react';
import {
  FaMapMarkerAlt,
  FaExpand,
  FaCompress,
  FaSearch,
  FaDownload,
  FaSync,
  FaInfoCircle,
  FaCrosshairs,
  FaBatteryFull,
  FaBatteryThreeQuarters,
  FaBatteryHalf,
  FaBatteryQuarter,
  FaBatteryEmpty,
  FaWifi,
  FaCog,
  FaPlay,
  FaStop,
  FaExclamationTriangle
} from 'react-icons/fa';
import './RobotControl.css';

const RobotControl = () => {
  const [mapData, setMapData] = useState({
    scale: 1,
    centerX: 0,
    centerY: 0,
    zoom: 1,
    isFullscreen: false
  });
  const [robotPosition, setRobotPosition] = useState({ x: 100, y: 100 });
  const [robotStatus, setRobotStatus] = useState('disconnected');
  const [isRunning, setIsRunning] = useState(false);
  const [telemetry, setTelemetry] = useState({
    battery: 85,
    position: { x: 100, y: 100, z: 0 },
    orientation: 0,
    speed: 0,
    temperature: 42,
    taskStatus: 'idle'
  });
  const [connectionStatus, setConnectionStatus] = useState('disconnected');
  const [emergencyStop, setEmergencyStop] = useState(false);

  // Simulate robot movement and telemetry updates
  useEffect(() => {
    if (isRunning && robotStatus === 'connected') {
      const interval = setInterval(() => {
        setTelemetry(prev => ({
          ...prev,
          battery: Math.max(0, prev.battery - Math.random() * 0.5),
          position: {
            x: prev.position.x + (Math.random() - 0.5) * 2,
            y: prev.position.y + (Math.random() - 0.5) * 2,
            z: prev.position.z
          },
          orientation: (prev.orientation + Math.random() * 2 - 1) % 360,
          speed: Math.min(100, prev.speed + (Math.random() - 0.5) * 10),
          temperature: Math.max(20, Math.min(80, prev.temperature + (Math.random() - 0.5) * 2)),
          taskStatus: prev.taskStatus === 'idle' ? 'running' : 'idle'
        }));

        setRobotPosition(prev => ({
          x: prev.x + (Math.random() - 0.5) * 2,
          y: prev.y + (Math.random() - 0.5) * 2
        }));
      }, 1000);

      return () => clearInterval(interval);
    }
  }, [isRunning, robotStatus]);

  // Simulate connection status
  useEffect(() => {
    const interval = setInterval(() => {
      if (robotStatus === 'connected') {
        setConnectionStatus(Math.random() > 0.95 ? 'warning' : 'connected');
      }
    }, 5000);

    return () => clearInterval(interval);
  }, [robotStatus]);

  const connectRobot = () => {
    setRobotStatus('connecting');
    setTimeout(() => {
      setRobotStatus('connected');
      setConnectionStatus('connected');
    }, 2000);
  };

  const disconnectRobot = () => {
    setRobotStatus('disconnected');
    setConnectionStatus('disconnected');
    setIsRunning(false);
    setEmergencyStop(false);
  };

  const startRobot = () => {
    if (robotStatus === 'connected' && !emergencyStop) {
      setIsRunning(true);
    }
  };

  const stopRobot = () => {
    setIsRunning(false);
  };

  const emergencyStopRobot = () => {
    setEmergencyStop(true);
    setIsRunning(false);
    setTimeout(() => setEmergencyStop(false), 5000);
  };

  const toggleFullscreen = () => {
    setMapData(prev => ({ ...prev, isFullscreen: !prev.isFullscreen }));
  };

  const zoomIn = () => {
    setMapData(prev => ({ ...prev, zoom: Math.min(prev.zoom * 1.2, 5) }));
  };

  const zoomOut = () => {
    setMapData(prev => ({ ...prev, zoom: Math.max(prev.zoom / 1.2, 0.5) }));
  };

  const resetView = () => {
    setMapData(prev => ({
      ...prev,
      zoom: 1,
      centerX: 0,
      centerY: 0
    }));
  };

  const downloadMap = () => {
    // Simulate map download
    console.log('Downloading map data...');
  };

  const getBatteryIcon = (level) => {
    if (level > 80) return <FaBatteryFull />;
    if (level > 60) return <FaBatteryThreeQuarters />;
    if (level > 40) return <FaBatteryHalf />;
    if (level > 20) return <FaBatteryQuarter />;
    return <FaBatteryEmpty />;
  };

  const getBatteryColor = (level) => {
    if (level > 60) return '#34A853';
    if (level > 30) return '#FBBC05';
    return '#EA4335';
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'connected': return '#34A853';
      case 'connecting': return '#FBBC05';
      case 'disconnected': return '#EA4335';
      case 'warning': return '#FBBC05';
      default: return '#9AA0A6';
    }
  };

  return (
    <div className={`robot-data-monitor ${mapData.isFullscreen ? 'fullscreen' : ''}`}>
      {/* Header */}
      <div className="monitor-header">
        <h1>Robot Data Monitor</h1>
        <p>Monitor robot telemetry data and status information</p>
      </div>

      {/* Main Dashboard */}
      <div className="monitor-dashboard">
        {/* LIDAR Visualization Panel */}
        <div className="lidar-panel">
          <div className="panel-header">
            <h2>LIDAR Visualization</h2>
          </div>
          <div className="lidar-container">
            <div className="lidar-canvas">
              <div
                className="lidar-content"
                style={{
                  transform: `scale(${mapData.zoom}) translate(${mapData.centerX}px, ${mapData.centerY}px)`
                }}
              >
                {/* LIDAR Background Image */}
                <div className="lidar-background">
                  <img
                    src={`${process.env.PUBLIC_URL}/lidar.png`}
                    alt="LIDAR Map"
                    className="lidar-image"
                  />
                </div>

                {/* Grid Overlay */}
                <div className="lidar-grid"></div>

                {/* Robot Position Marker */}
                <div
                  className="robot-marker"
                  style={{
                    left: `${robotPosition.x}px`,
                    top: `${robotPosition.y}px`
                  }}
                >
                  <div className="marker-dot"></div>
                </div>

                {/* Trajectory Line */}
                <div className="trajectory-line"></div>
              </div>
            </div>

            {/* Legend */}
            <div className="lidar-legend">
              <div className="legend-item">
                <div className="legend-dot initial"></div>
                <span>Initial Position</span>
              </div>
              <div className="legend-item">
                <div className="legend-dot final"></div>
                <span>Final Position</span>
              </div>
              <div className="legend-item">
                <div className="legend-line"></div>
                <span>Trajectory</span>
              </div>
            </div>
          </div>
        </div>

        {/* Live Telemetry Data Panel */}
        <div className="telemetry-panel">
          <div className="panel-header">
            <h2>Live Telemetry Data</h2>
            <p>Live Telemetry</p>
          </div>

          <div className="telemetry-cards">
            {/* Battery Card */}
            <div className="telemetry-card">
              <div className="card-icon battery">
                {getBatteryIcon(telemetry.battery)}
              </div>
              <div className="card-content">
                <div className="card-label">BATTERY</div>
                <div className="card-value" style={{ color: getBatteryColor(telemetry.battery) }}>
                  {Math.floor(telemetry.battery)}%
                </div>
              </div>
            </div>

            {/* Position Card */}
            <div className="telemetry-card">
              <div className="card-icon position">
                <FaMapMarkerAlt />
              </div>
              <div className="card-content">
                <div className="card-label">POSITION</div>
                <div className="card-value">
                  X: {telemetry.position.x.toFixed(1)}, Y: {telemetry.position.y.toFixed(1)}
                </div>
              </div>
            </div>

            {/* Orientation Card */}
            <div className="telemetry-card">
              <div className="card-icon orientation">
                <FaSync />
              </div>
              <div className="card-content">
                <div className="card-label">ORIENTATION</div>
                <div className="card-value">
                  {telemetry.orientation.toFixed(1)}°
                </div>
              </div>
            </div>

            {/* Temperature Card */}
            <div className="telemetry-card">
              <div className="card-icon temperature">
                <FaCog />
              </div>
              <div className="card-content">
                <div className="card-label">TEMPERATURE</div>
                <div className="card-value">
                  {telemetry.temperature.toFixed(1)}°C
                </div>
              </div>
            </div>

            {/* Task Status Card */}
            <div className="telemetry-card">
              <div className="card-icon task">
                <FaPlay />
              </div>
              <div className="card-content">
                <div className="card-label">TASK STATUS</div>
                <div className="card-value">
                  {telemetry.taskStatus.charAt(0).toUpperCase() + telemetry.taskStatus.slice(1)}
                </div>
              </div>
            </div>
          </div>

          {/* Control Buttons */}
          <div className="control-section">
            <button
              className={`control-btn ${robotStatus === 'connected' ? 'connected' : 'disconnected'}`}
              onClick={robotStatus === 'connected' ? disconnectRobot : connectRobot}
              disabled={robotStatus === 'connecting'}
            >
              {robotStatus === 'connecting' ? (
                <>
                  <FaCog className="spinning" />
                  Connecting...
                </>
              ) : robotStatus === 'connected' ? (
                <>
                  <FaWifi />
                  Disconnect
                </>
              ) : (
                <>
                  <FaWifi />
                  Connect Robot
                </>
              )}
            </button>

            <button
              className={`control-btn ${isRunning ? 'running' : 'stopped'}`}
              onClick={isRunning ? stopRobot : startRobot}
              disabled={robotStatus !== 'connected' || emergencyStop}
            >
              {isRunning ? (
                <>
                  <FaStop />
                  Stop Robot
                </>
              ) : (
                <>
                  <FaPlay />
                  Start Robot
                </>
              )}
            </button>

            <button
              className="control-btn emergency"
              onClick={emergencyStopRobot}
              disabled={robotStatus !== 'connected'}
            >
              <FaExclamationTriangle />
              EMERGENCY STOP
            </button>
          </div>
        </div>
      </div>

      {/* Emergency Alert */}
      {emergencyStop && (
        <div className="emergency-overlay">
          <div className="emergency-alert">
            <FaExclamationTriangle className="alert-icon" />
            <div className="alert-content">
              <div className="alert-title">EMERGENCY STOP ACTIVATED</div>
              <div className="alert-message">Robot operations have been suspended</div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RobotControl;

import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import {
  FaBuilding, FaUserPlus, FaArrowRight, FaCheckCircle,
  FaSpinner, FaRocket, FaUsers, FaChartBar, FaShieldAlt,
  FaArrowLeft, FaLink, FaExclamationTriangle
} from 'react-icons/fa';
import { useWorkspace } from '../contexts/WorkspaceContext';
import { useAuth } from '../contexts/AuthContext';
import './WorkspaceOnboarding.css';

export default function WorkspaceOnboarding() {
  const { createWorkspace, imsFetch, fetchWorkspaces, switchWorkspace, workspaces, loadingWorkspaces } = useWorkspace();
  const { getUserInfo } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();

  const user = getUserInfo();
  const prefilledToken = searchParams.get('invite') || '';

  const [mode, setMode] = useState(prefilledToken ? 'join' : null);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [workspaceName, setWorkspaceName] = useState('');
  const [orgType, setOrgType] = useState('manufacturing');
  const [inviteToken, setInviteToken] = useState(prefilledToken);
  const [invitePreview, setInvitePreview] = useState(null);
  const [error, setError] = useState('');
  const [successData, setSuccessData] = useState(null);

  // Removed the auto-redirect so users can use this UI to create additional workspaces anytime.

  const previewInvite = async (token) => {
    if (!token.trim()) return;
    setLoading(true);
    setError('');
    try {
      const serverUrl = window.location.hostname === 'localhost'
        ? 'http://localhost:3001'
        : window.location.origin;
      const res = await fetch(`${serverUrl}/api/workspaces/join/${token.trim()}`);
      const data = await res.json();
      if (data.success) {
        setInvitePreview(data);
        setError('');
      } else {
        setError(data.error || 'Invalid invite link');
        setInvitePreview(null);
      }
    } catch {
      setError('Could not validate invite link. Check your connection.');
      setInvitePreview(null);
    }
    setLoading(false);
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    if (!workspaceName.trim()) { setError('Please enter a workspace name'); return; }
    setLoading(true);
    setError('');
    const result = await createWorkspace(workspaceName.trim());
    setLoading(false);
    if (result.success) {
      setSuccessData({ type: 'create', name: workspaceName });
      setStep(3);
    } else {
      setError(result.error || 'Failed to create workspace');
    }
  };

  const handleJoin = async (e) => {
    e.preventDefault();
    if (!inviteToken.trim()) { setError('Please enter or paste an invite link/code'); return; }
    setLoading(true);
    setError('');
    try {
      const tkn = inviteToken.includes('/join/') ? inviteToken.split('/join/').pop().trim() : inviteToken.trim();
      const res = await imsFetch('/api/workspaces/join', {
        method: 'POST',
        body: JSON.stringify({ token: tkn })
      });
      const data = await res.json();
      if (data.success) {
        await fetchWorkspaces();
        if (data.workspaceId) switchWorkspace(data.workspaceId);
        setSuccessData({ type: 'join', name: data.workspaceName || 'Workspace' });
        setStep(3);
      } else {
        setError(data.error || 'Invalid or expired invite link');
      }
    } catch {
      setError('Failed to join workspace. Please try again.');
    }
    setLoading(false);
  };

  const features = [
    { icon: FaChartBar, label: 'Live Inventory Dashboard', desc: 'Real-time stock levels and alerts' },
    { icon: FaShieldAlt, label: 'RBAC Security', desc: 'Role-based access control built in' },
    { icon: FaUsers, label: 'Team Collaboration', desc: 'Invite your entire team seamlessly' },
    { icon: FaRocket, label: 'ERP Integration', desc: 'Connect SAP, Tally and more' },
  ];

  return (
    <div className="ws-onboarding-root">
      {/* Left Panel */}
      <div className="ws-onboarding-left">
        <div className="ws-onboarding-brand">
          <img src={`${process.env.PUBLIC_URL}/static/media/robridge-logo.png`} alt="RoBridge" className="ws-ob-logo"
            onError={e => { e.target.style.display = 'none'; }} />
          <span className="ws-ob-brand-name">RoBridge IMS</span>
        </div>

        <div className="ws-ob-hero">
          <h1>Your warehouse,<br /><span className="ws-ob-accent">intelligently managed.</span></h1>
          <p>Set up your workspace to start tracking inventory, managing teams, and gaining real-time insights across your operations.</p>
        </div>

        <div className="ws-ob-features">
          {features.map(({ icon: Icon, label, desc }) => (
            <div className="ws-ob-feature" key={label}>
              <div className="ws-ob-feature-icon"><Icon /></div>
              <div>
                <div className="ws-ob-feature-label">{label}</div>
                <div className="ws-ob-feature-desc">{desc}</div>
              </div>
            </div>
          ))}
        </div>

        <div className="ws-ob-dots">
          {[0, 1, 2].map(i => (
            <div key={i} className={`ws-ob-dot ${step - 1 === i ? 'active' : ''}`} />
          ))}
        </div>
      </div>

      {/* Right Panel */}
      <div className="ws-onboarding-right">
        <div className="ws-ob-right-inner">

          {/* Step 1: Mode selection */}
          {step === 1 && (
            <div className="ws-ob-step ws-ob-step-enter">
              <div className="ws-ob-greeting">
                <div className="ws-ob-avatar">{user?.name?.charAt(0)?.toUpperCase() || 'U'}</div>
                <div>
                  <div className="ws-ob-welcome">Welcome, {user?.name?.split(' ')[0] || 'there'}! 👋</div>
                  <div className="ws-ob-sub">Let's get your workspace set up.</div>
                </div>
              </div>

              <div className="ws-ob-cards">
                <button className="ws-ob-card" onClick={() => { setMode('create'); setStep(2); }}>
                  <div className="ws-ob-card-icon create-icon">
                    <FaBuilding />
                  </div>
                  <div className="ws-ob-card-body">
                    <div className="ws-ob-card-title">Create a new workspace</div>
                    <div className="ws-ob-card-desc">Set up IMS for your company or facility. You'll be the workspace owner with full admin access.</div>
                  </div>
                  <FaArrowRight className="ws-ob-card-arrow" />
                </button>

                <button className="ws-ob-card" onClick={() => { setMode('join'); setStep(2); }}>
                  <div className="ws-ob-card-icon join-icon">
                    <FaLink />
                  </div>
                  <div className="ws-ob-card-body">
                    <div className="ws-ob-card-title">Join an existing workspace</div>
                    <div className="ws-ob-card-desc">Got an invite link from your admin? Paste it here to instantly join your team's workspace.</div>
                  </div>
                  <FaArrowRight className="ws-ob-card-arrow" />
                </button>
              </div>
            </div>
          )}

          {/* Step 2: Forms */}
          {step === 2 && mode === 'create' && (
            <div className="ws-ob-step ws-ob-step-enter">
              <button className="ws-ob-back" onClick={() => { setStep(1); setError(''); }}>
                <FaArrowLeft /> Back
              </button>
              <h2 className="ws-ob-form-title">Set up your workspace</h2>
              <p className="ws-ob-form-sub">This will be the central hub for all your inventory operations.</p>

              <form onSubmit={handleCreate} className="ws-ob-form">
                <div className="ws-ob-field">
                  <label>Workspace / Company Name</label>
                  <input
                    type="text"
                    placeholder="e.g. Acme Manufacturing Pvt Ltd"
                    value={workspaceName}
                    onChange={e => { setWorkspaceName(e.target.value); setError(''); }}
                    autoFocus
                    className={error ? 'ws-ob-input error' : 'ws-ob-input'}
                  />
                </div>

                <div className="ws-ob-field">
                  <label>Organization Type</label>
                  <div className="ws-ob-org-grid">
                    {[
                      { val: 'manufacturing', label: 'Manufacturing', emoji: '🏭' },
                      { val: 'retail', label: 'Retail / Distribution', emoji: '🛒' },
                      { val: 'pharma', label: 'Pharma / Food', emoji: '💊' },
                      { val: 'logistics', label: 'Logistics', emoji: '🚚' },
                    ].map(({ val, label, emoji }) => (
                      <button type="button" key={val}
                        className={`ws-ob-org-btn ${orgType === val ? 'selected' : ''}`}
                        onClick={() => setOrgType(val)}>
                        <span>{emoji}</span> {label}
                      </button>
                    ))}
                  </div>
                </div>

                {error && <div className="ws-ob-error"><FaExclamationTriangle /> {error}</div>}

                <button type="submit" className="ws-ob-submit-btn" disabled={loading}>
                  {loading ? <><FaSpinner className="spin" /> Creating...</> : <><FaRocket /> Create Workspace</>}
                </button>
              </form>
            </div>
          )}

          {step === 2 && mode === 'join' && (
            <div className="ws-ob-step ws-ob-step-enter">
              <button className="ws-ob-back" onClick={() => { setStep(1); setError(''); setInvitePreview(null); }}>
                <FaArrowLeft /> Back
              </button>
              <h2 className="ws-ob-form-title">Join a workspace</h2>
              <p className="ws-ob-form-sub">Paste the invite link or code shared by your workspace admin.</p>

              <form onSubmit={handleJoin} className="ws-ob-form">
                <div className="ws-ob-field">
                  <label>Invite Link or Code</label>
                  <input
                    type="text"
                    placeholder="https://… or paste the invite code"
                    value={inviteToken}
                    onChange={e => { setInviteToken(e.target.value); setError(''); setInvitePreview(null); }}
                    onBlur={e => e.target.value.trim() && previewInvite(e.target.value)}
                    autoFocus
                    className={error ? 'ws-ob-input error' : 'ws-ob-input'}
                  />
                  <button type="button" className="ws-ob-preview-btn" onClick={() => previewInvite(inviteToken)} disabled={loading}>
                    {loading ? <FaSpinner className="spin" /> : 'Validate →'}
                  </button>
                </div>

                {invitePreview && (
                  <div className="ws-ob-preview-card">
                    <FaCheckCircle className="ws-ob-preview-check" />
                    <div>
                      <div className="ws-ob-preview-name">{invitePreview.workspaceName}</div>
                      <div className="ws-ob-preview-role">You'll join as: <strong>{invitePreview.role}</strong></div>
                    </div>
                  </div>
                )}

                {error && <div className="ws-ob-error"><FaExclamationTriangle /> {error}</div>}

                <button type="submit" className="ws-ob-submit-btn join" disabled={loading || !inviteToken.trim()}>
                  {loading ? <><FaSpinner className="spin" /> Joining...</> : <><FaUserPlus /> Join Workspace</>}
                </button>
              </form>
            </div>
          )}

          {/* Step 3: Success */}
          {step === 3 && successData && (
            <div className="ws-ob-step ws-ob-success ws-ob-step-enter">
              <div className="ws-ob-success-icon">
                {successData.type === 'create' ? '🚀' : '🎉'}
              </div>
              <h2>{successData.type === 'create' ? 'Workspace Created!' : 'You\'re in!'}</h2>
              <p>
                {successData.type === 'create'
                  ? <><strong>{successData.name}</strong> is ready. Start by adding your first items to the catalog.</>
                  : <>You've successfully joined <strong>{successData.name}</strong>. Your team is waiting!</>
                }
              </p>
              <button className="ws-ob-submit-btn" onClick={() => navigate('/')}>
                <FaArrowRight /> Go to Dashboard
              </button>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
